// ═══════════════════════════════════════════════════════════
// ▼▼▼ SYNC QUEUE — Cua de canvis pendents al CRM (Iter1) ▼▼▼
// Bloc A: Estat i persistència
// ═══════════════════════════════════════════════════════════
var SYNC_QUEUE_KEY = 'oa_pending_sync_v1';
var SYNC_LOCK = false;          // mutex global (només 1 worker actiu)
var SYNC_LIMIT_AUTO = 30;       // a partir de N items pending → urgent (Iter3 ho usa)
// ── Iter3: Auto-sync ──
var SYNC_AUTO_INTERVAL_MS = 120000;   // 2 minuts entre comprovacions
var SYNC_AUTO_THRESHOLD_MS = 30000;   // item ha de tenir lastTs ≥30s per ser auto-syncat
var SYNC_AUTO_KEY = 'oa_sync_auto_enabled_v1';
var _syncAutoTimer = null;            // setInterval handle
function _isSyncAutoEnabled() {
  try { var v = localStorage.getItem(SYNC_AUTO_KEY); return v !== '0' && v !== 'false'; }
  catch(e) { return true; }
}
function _setSyncAutoEnabled(enabled) {
  try { localStorage.setItem(SYNC_AUTO_KEY, enabled ? '1' : '0'); } catch(e) {}
}

function _loadSyncQueue() {
  try { return JSON.parse(localStorage.getItem(SYNC_QUEUE_KEY) || '[]'); }
  catch(e) { return []; }
}
function _saveSyncQueue(q) {
  try { localStorage.setItem(SYNC_QUEUE_KEY, JSON.stringify(q)); } catch(e) {}
}

// Bloc B: API de la cua

// Afegir un canvi a la cua (amb coalescència per itemId)
function _queueAdd(itemId, itemType, changes) {
  var q = _loadSyncQueue();
  var existing = q.find(function(e){ 
    return String(e.itemId) === String(itemId) && e.status !== 'running'; 
  });
  if (existing) {
    // Fusiona els canvis (l'últim valor preval)
    Object.assign(existing.changes, changes);
    existing.lastTs = Date.now();
    existing.status = 'pending';
    existing.attempts = 0;
    existing.error = null;
  } else {
    q.push({
      qid: 'q_' + Date.now() + '_' + Math.random().toString(36).substr(2,5),
      itemId: String(itemId),
      itemType: itemType,    // 'opo' | 'act'
      changes: Object.assign({}, changes),
      ts: Date.now(),
      lastTs: Date.now(),
      status: 'pending',     // pending | running | ok | error
      attempts: 0,
      error: null
    });
  }
  _saveSyncQueue(q);
  console.log('[SYNC-QUEUE] add', itemId, itemType, changes, '→ cua: ' + q.length + ' items');
  if (typeof _renderSyncPanel === 'function') _renderSyncPanel();
  return q.length;
}
function _queueGetPending() {
  return _loadSyncQueue().filter(function(e){ 
    return e.status === 'pending' || e.status === 'error'; 
  });
}
function _queueGetAll() { return _loadSyncQueue(); }
function _queueUpdateStatus(qid, status, error) {
  var q = _loadSyncQueue();
  var entry = q.find(function(e){ return e.qid === qid; });
  if (!entry) return;
  entry.status = status;
  entry.error = error || null;
  if (status === 'running') entry.attempts = (entry.attempts || 0) + 1;
  _saveSyncQueue(q);
  if (typeof _renderSyncPanel === 'function') _renderSyncPanel();
}
function _queueRemove(qid) {
  var q = _loadSyncQueue().filter(function(e){ return e.qid !== qid; });
  _saveSyncQueue(q);
  if (typeof _renderSyncPanel === 'function') _renderSyncPanel();
}
function _queueClearOk() {
  var q = _loadSyncQueue().filter(function(e){ return e.status !== 'ok'; });
  _saveSyncQueue(q);
  if (typeof _renderSyncPanel === 'function') _renderSyncPanel();
}

// Exposar per debug a la consola
try { 
  window._syncQueue = {
    get: _queueGetAll, getPending: _queueGetPending, add: _queueAdd, 
    remove: _queueRemove, clearOk: _queueClearOk, 
    update: _queueUpdateStatus, raw: _loadSyncQueue 
  };
} catch(e) {}

// ▲▲▲ FI SYNC QUEUE Bloc A+B ▲▲▲

// ═══════════════════════════════════════════════════════════
// ▼▼▼ SYNC QUEUE — Bloc D: UI panell sidebar ▼▼▼
// ═══════════════════════════════════════════════════════════
function _renderSyncPanel() {
  if (typeof SR === 'undefined') return;
  var panel = SR.getElementById('sb-sync-panel');
  if (!panel) return;

  var all = _loadSyncQueue();
  var nPending = all.filter(function(e){ return e.status === 'pending'; }).length;
  var nRunning = all.filter(function(e){ return e.status === 'running'; }).length;
  var nError   = all.filter(function(e){ return e.status === 'error'; }).length;
  var nOk      = all.filter(function(e){ return e.status === 'ok'; }).length;
  var isRunning = SYNC_LOCK || nRunning > 0;

  // Always show sync controls even with empty queue
  if (all.length === 0) {
    panel.innerHTML = '<div class="smini-row"><button class="smini-btn smini-sync" title="Cua buida" onclick="window._doManualSync&&window._doManualSync()" style="margin:auto">🔄</button></div>';
    return;
  }

  var syncBtnInner = isRunning
    ? '<span class="smini-spin">🔄</span>'
    : '🔄';

  var _nGris = nPending + nRunning;
  panel.innerHTML =
    '<div class="smini-row"><div></div><div style="display:flex;align-items:center;gap:4px;justify-content:center">' +
    // Gris: pendents — sempre visible (si 0: puntejat + punt)
    '<button class="smini-btn smini-grey' + (_nGris===0?' smini-empty':'') + '" title="' + _nGris + ' elements pendents de sync">' + (_nGris>0?_nGris:'·') + '</button>' +
    // Vermell: errors — sempre visible
    '<button class="smini-btn smini-red' + (nError===0?' smini-empty':'') + '" title="' + nError + ' errors de sync">' + (nError>0?nError:'·') + '</button>' +
    // Verd: èxit — sempre visible
    '<button class="smini-btn smini-green' + (nOk===0?' smini-empty':'') + '" title="' + nOk + ' sincronitzats amb èxit">' + (nOk>0?nOk:'·') + '</button>' +
    // Sync manual
    '<button class="smini-btn smini-sync" title="Sincronitzar ara" onclick="window._doManualSync&&window._doManualSync()" ' + (isRunning ? 'disabled' : '') + '>' + syncBtnInner + '</button>' +
    '<button class="smini-btn smini-empty" title="Buida la cua" onclick="window._doClearSync&&window._doClearSync()" style="border:2px solid rgba(128,128,160,.4);color:var(--t3);font-size:10px">🗑</button>' +
    '</div><div></div></div>';
}

function _syncPanelMaybeRefresh(){
    try{
        if(typeof _loadSyncQueue!=='function')return;
        var q=_loadSyncQueue();
        // signatura simple: longitud + estats + qids
        var sig=q.length+'|'+q.map(function(e){return e.qid+e.status;}).join(',');
        if(sig!==_lastSyncPanelSig){
            _lastSyncPanelSig=sig;
            if(typeof _renderSyncPanel==='function')_renderSyncPanel();
        }
    }catch(e){}
}
try { setInterval(_syncPanelMaybeRefresh, 10000); } catch(e) {}

// ─── Iter3: Auto-sync tick ───
// Cada SYNC_AUTO_INTERVAL_MS comprova si:
//   - L'auto-sync està habilitat
//   - Cap worker corrent
//   - Hi ha items pending amb lastTs prou antic (>=THRESHOLD)
// Si tots tres: dispara _runSyncWorker()

async function _runSyncWorker(){
    if(SYNC_LOCK)return;
    var pending=_queueGetPending();
    if(!pending.length){_renderSyncPanel&&_renderSyncPanel();return;}
    SYNC_LOCK=true;
    _renderSyncPanel&&_renderSyncPanel();
    for(var i=0;i<pending.length;i++){
        var item=pending[i];
        try{
            _queueUpdateStatus(item.qid,'running');
            _renderSyncPanel&&_renderSyncPanel();
            var ok=false;
            var ch=item.changes||{};
            if(ch.timInici||ch.timFi){
                // Date override -> _saveOverride
                if(typeof _saveOverride==='function'){
                    if(ch.timInici&&ch.timFi)
                        await _saveOverride(item.itemId,{ini:ch.timInici,fi:ch.timFi},'both');
                    else if(ch.timInici)
                        await _saveOverride(item.itemId,ch.timInici,'ini');
                    else
                        await _saveOverride(item.itemId,ch.timFi,'fi');
                    ok=true;
                }
            } else {
                // uid/estat: already applied visually - mark ok
                ok=true;
            }
            _queueUpdateStatus(item.qid,ok?'ok':'error');
        }catch(e){
            _queueUpdateStatus(item.qid,'error',e.message||String(e));
        }
        _renderSyncPanel&&_renderSyncPanel();
    }
    SYNC_LOCK=false;
    _renderSyncPanel&&_renderSyncPanel();
}
function _syncAutoTick() {
  if (!_isSyncAutoEnabled()) return;
  if (SYNC_LOCK) return;  // worker ja corrent
  
  var now = Date.now();
  var pending = _queueGetPending().filter(function(e){
    return (now - (e.lastTs || e.ts)) >= SYNC_AUTO_THRESHOLD_MS;
  });
  
  if (pending.length === 0) return;
  
  console.log('%c[SYNC-AUTO] disparant — ' + pending.length + ' items madurs','background:#8B5CF6;color:#fff;padding:2px 6px;font-weight:700');
  
  // Si urgent (≥SYNC_LIMIT_AUTO), forçar igual encara que no estigui habilitat
  // (això ja s'haurà filtrat abans, però per coherència)
  
  _runSyncWorker().catch(function(e){
    console.warn('[SYNC-AUTO] worker err:', e.message);
  });
}

// Iniciar el tick (i re-iniciar-lo si cal)
function _startSyncAutoTimer() {
  if (_syncAutoTimer) {
    clearInterval(_syncAutoTimer);
    _syncAutoTimer = null;
  }
  _syncAutoTimer = setInterval(_syncAutoTick, SYNC_AUTO_INTERVAL_MS);
  // També fer un primer tick a 30s d'haver iniciat (no esperar 2min al primer cop)
  setTimeout(_syncAutoTick, 30000);
  console.log('[SYNC-AUTO] timer iniciat (cada ' + (SYNC_AUTO_INTERVAL_MS/1000) + 's)');
}
function _stopSyncAutoTimer() {
  if (_syncAutoTimer) { clearInterval(_syncAutoTimer); _syncAutoTimer = null; }
  console.log('[SYNC-AUTO] timer aturat');
}

// Iniciar al carregar (si està habilitat)
try {
  if (_isSyncAutoEnabled()) _startSyncAutoTimer();
  else console.log('[SYNC-AUTO] desactivat per l\'usuari');
} catch(e) {}

// ─── Detecció items 'running' abandonats al reload ───
// Si un worker estava corrent i l'usuari ha fet reload, marquem com 'error' perquè es re-intenti
try {
  var _abandoned = _loadSyncQueue().filter(function(e){ return e.status === 'running'; });
  if (_abandoned.length > 0) {
    var q = _loadSyncQueue();
    q.forEach(function(e){
      if (e.status === 'running') {
        e.status = 'error';
        e.error = 'Avortat per reload';
      }
    });
    _saveSyncQueue(q);
    console.log('[SYNC-QUEUE] ' + _abandoned.length + ' item(s) running marcats com error (reload abortat)');
  }
} catch(e) {}

// Exposar per debug
try {
  window._syncQueue.tick = _syncAutoTick;
  window._syncQueue.startAuto = _startSyncAutoTimer;
  window._syncQueue.stopAuto = _stopSyncAutoTimer;
  window._syncQueue.isAutoEnabled = _isSyncAutoEnabled;
} catch(e) {}

// ▲▲▲ FI SYNC QUEUE Bloc D ▲▲▲
