// ── OneDrive Overrides ─────────────────────────────────────
var OD=(function(){
  var TENANT='609cbec4-a6b7-422c-95c1-057586ed0026';
  var CLIENT='edf4bc1b-5274-4c3a-91fe-99a34d67fd12';
  var REDIRECT='https://grupoaplicaciones.gco.global/FE/ISC.Gaan.CRM.FE.Inicio/';
  var SCOPE='https://graph.microsoft.com/Files.ReadWrite Sites.Read.All Mail.Send offline_access User.Read';
  // Carpeta OPTIMIZARTE del OneDrive de DH — compartida amb FK i SF (permisos d'edició)
  // Tots els usuaris llegeixen i escriuen aquí independentment del compte amb què loguen
  var DH_DRIVE_ID='b!UA7M2sY3P0Gyuj8INUif70BI1A23JNtHuRZW8KO3p6GsFwThV2k4T78rc90zZXen';
  var DH_FOLDER_ID='01GBOM3GDJS7UBEPAE5RA2R5LJ37WDJE64';
  var _BASE_URL='https://graph.microsoft.com/v1.0/drives/'+DH_DRIVE_ID+'/items/'+DH_FOLDER_ID+':';
  var FILE_NAME='opticrm-overrides.json';
  var LS_TOK='od_tok_v1', LS_EXP='od_exp_v1';

  // Carregar token persistent de localStorage
  var _tok=null, _exp=0;
  try{
    var _lt=localStorage.getItem(LS_TOK);
    var _le=parseInt(localStorage.getItem(LS_EXP)||'0');
    if(_lt&&_le&&Date.now()<_le){_tok=_lt;_exp=_le;console.log('OD: token restaurat de localStorage');}
  }catch(e){}

  function _saveTok(tok,exp){
    _tok=tok;_exp=exp;
    try{localStorage.setItem(LS_TOK,tok);localStorage.setItem(LS_EXP,String(exp));}catch(e){}
  }
  function _clearTok(){
    _tok=null;_exp=0;
    try{localStorage.removeItem(LS_TOK);localStorage.removeItem(LS_EXP);}catch(e){}
  }

  function _authUrl(prompt){
    return 'https://login.microsoftonline.com/'+TENANT+'/oauth2/v2.0/authorize?'+
      new URLSearchParams({client_id:CLIENT,response_type:'token',redirect_uri:REDIRECT,
        scope:SCOPE,response_mode:'fragment',prompt:prompt||'none'}).toString();
  }
  async function _silentToken(){
    if(_tok&&Date.now()<_exp)return _tok;
    // Intent silenciós via iframe
    return new Promise(function(res){
      var f=document.createElement('iframe');
      f.style.cssText='position:fixed;width:0;height:0;border:0';
      f.src=_authUrl('none');
      var t=setTimeout(function(){try{document.body.removeChild(f);}catch(e){}res(null);},6000);
      f.onload=function(){
        try{
          var h=f.contentWindow.location.hash.substring(1);
          var p=new URLSearchParams(h);
          var tok=p.get('access_token');
          if(tok){var exp=Date.now()+(parseInt(p.get('expires_in')||'3600')-60)*1000;_saveTok(tok,exp);}
          clearTimeout(t);try{document.body.removeChild(f);}catch(e){}res(tok||null);
        }catch(e){clearTimeout(t);try{document.body.removeChild(f);}catch(e2){}res(null);}
      };
      document.body.appendChild(f);
    });
  }
  async function loginPopup(){
    var popup=window.open(_authUrl('select_account'),'ODLogin','width=500,height=600,left=400,top=100');
    if(!popup){console.warn('OD: popup bloquejat');return false;}
    return new Promise(function(res){
      var _done=false;
      function _finish(ok){
        if(_done)return;_done=true;
        clearInterval(poll);
        window.removeEventListener('message',_onMsg);
        try{if(!popup.closed)popup.close();}catch(e){}
        res(ok);
      }

      // Via 1: postMessage del popup (quan l'extensió detecta que és dins el popup d'OD)
      function _onMsg(e){
        if(!e.data||!e.data._opticrm_od_login)return;
        if(e.data.ok){
            // Token ja guardat a localStorage pel popup — recarregar
            try{
                var _lt=localStorage.getItem('od_tok_v1');
                var _le=parseInt(localStorage.getItem('od_exp_v1')||'0');
                if(_lt&&_le&&Date.now()<_le){_saveTok(_lt,_le);}
            }catch(e2){}
            _finish(true);
        }
        // Si ok:false però popup ha carregat → seguim esperant el hash o el tancament
      }
      window.addEventListener('message',_onMsg);

      // Via 2: poll ràpid llegint el hash (funciona si el redirect no elimina el hash)
      var poll=setInterval(function(){
        try{
          var h;try{h=popup.location.hash.substring(1);}catch(_coop){/*cross-origin, esperar*/return;}
          if(h){
            var p=new URLSearchParams(h);
            var tok=p.get('access_token');
            if(tok){
              var exp=Date.now()+(parseInt(p.get('expires_in')||'3600')-60)*1000;
              _saveTok(tok,exp);
              _finish(true);return;
            }
          }
          // Via 3: si el popup ja ha navegat a griActividad (hash perdut per redirecció)
          // però el token s'ha guardat a localStorage (via postMessage/popup detection)
          try{
            var _lt=localStorage.getItem('od_tok_v1');
            var _le=parseInt(localStorage.getItem('od_exp_v1')||'0');
            if(_lt&&_le&&Date.now()<_le&&!_tok){_saveTok(_lt,_le);_finish(true);return;}
          }catch(e2){}
        }catch(e){}
        if(popup.closed){
            // Popup tancat: comprovar si token s'ha guardat per altre via
            try{
                var _lt2=localStorage.getItem('od_tok_v1');
                var _le2=parseInt(localStorage.getItem('od_exp_v1')||'0');
                if(_lt2&&_le2&&Date.now()<_le2)_saveTok(_lt2,_le2);
            }catch(e3){}
            _finish(!!_tok);
        }
      },80);
    });
  }
  async function load(){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok){console.log('OD: no token');return {};}
    try{
      var r=await fetch(_BASE_URL+'/'+FILE_NAME,{headers:{Authorization:'Bearer '+tok}});
      if(r.status===401){_clearTok();return {};}
      if(r.status===404){return {};}
      if(!r.ok){return {};}
      var meta=await r.json();
      var dl=meta['@microsoft.graph.downloadUrl'];if(!dl)return {};
      var r2=await fetch(dl);
      var d=await r2.json();
      console.log('OD: '+Object.keys(d).length+' overrides carregats');
      return d;
    }catch(e){console.log('OD load error:',e.message);return {};}
  }
  async function save(data){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok){console.warn('OD: no token per guardar');return false;}
    try{
      var r=await fetch(_BASE_URL+'/'+FILE_NAME+':/content',{
        method:'PUT',headers:{Authorization:'Bearer '+tok,'Content-Type':'text/plain'},
        body:JSON.stringify(data,null,2)
      });
      if(r.status===401){_clearTok();}
      if(r.ok)console.log('OD: '+Object.keys(data).length+' overrides guardats');
      else console.warn('OD save status:',r.status);
      return r.ok;
    }catch(e){console.log('OD save error:',e.message);return false;}
  }
  function isReady(){return !!_tok&&Date.now()<_exp;}
  async function getUser(){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok)return null;
    try{
      var r=await fetch('https://graph.microsoft.com/v1.0/me?$select=displayName,userPrincipalName,mail',
        {headers:{Authorization:'Bearer '+tok}});
      if(!r.ok)return null;
      return await r.json();
    }catch(e){return null;}
  }
  async function loadFile(fileName){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok){console.warn('[OD.loadFile] '+fileName+': sense token');return null;}
    try{
      var r=await fetch(_BASE_URL+'/'+fileName,{headers:{Authorization:'Bearer '+tok}});
      if(r.status===401){console.warn('[OD.loadFile] '+fileName+': 401 unauthorized');_clearTok();return null;}
      if(r.status===404){console.warn('[OD.loadFile] '+fileName+': 404 no trobat');return null;}
      if(!r.ok){console.warn('[OD.loadFile] '+fileName+': status '+r.status);return null;}
      var meta=await r.json();
      var modified=meta.lastModifiedDateTime||null;
      var dl=meta['@microsoft.graph.downloadUrl'];
      if(!dl){console.warn('[OD.loadFile] '+fileName+': sense downloadUrl al meta');return null;}
      var r2=await fetch(dl);
      if(!r2.ok){console.warn('[OD.loadFile] '+fileName+': download status '+r2.status);return null;}
      var data;
      try{ data=await r2.json(); }
      catch(parseErr){console.warn('[OD.loadFile] '+fileName+': JSON parse error: '+parseErr.message);return null;}
      if(data&&typeof data==='object')data._odModified=modified;
      console.log('[OD.loadFile] '+fileName+': OK, '+(typeof data==='object'?Object.keys(data).length+' keys':typeof data));
      return data;
    }catch(e){console.warn('[OD.loadFile] '+fileName+': exception: '+e.message);return null;}
  }
  async function saveFile(fileName,data){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok){console.warn('OD: no token per saveFile('+fileName+')');return false;}
    try{
      var r=await fetch(_BASE_URL+'/'+fileName+':/content',{
        method:'PUT',headers:{Authorization:'Bearer '+tok,'Content-Type':'text/plain'},
        body:JSON.stringify(data,null,2)
      });
      if(r.status===401)_clearTok();
      return r.ok;
    }catch(e){console.log('OD saveFile('+fileName+') error:',e.message);return false;}
  }
  // Llistar fitxers del folder, opcionalment filtrant per prefix
  async function listFiles(prefix){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok)return [];
    try{
      // Llista tots els fills del folder
      var listUrl='https://graph.microsoft.com/v1.0/drives/'+DH_DRIVE_ID+'/items/'+DH_FOLDER_ID+'/children?$top=200&$select=name,size,lastModifiedDateTime,file';
      var r=await fetch(listUrl,{headers:{Authorization:'Bearer '+tok}});
      if(r.status===401){_clearTok();return [];}
      if(!r.ok)return [];
      var j=await r.json();
      var items=(j.value||[]).filter(function(it){
        if(!it.file)return false; // nom\u00e9s fitxers, no carpetes
        if(prefix && it.name.indexOf(prefix)!==0)return false;
        return true;
      }).map(function(it){
        return {name:it.name, size:it.size||0, modified:it.lastModifiedDateTime||''};
      });
      return items;
    }catch(e){console.log('OD listFiles error:',e.message);return [];}
  }
  
  // ── Enviar mail via Graph API ──────────────────────────────────
  // Envia mail des del compte de l'usuari autenticat (Dany).
  // Inclou el report com a body HTML i opcionalment com a adjunt.
  async function sendMail(toAddress, subject, htmlBody, attachmentName){
    var tok=_tok&&Date.now()<_exp?_tok:await _silentToken();
    if(!tok)return {ok:false,error:'No token'};
    try{
      var msg={
        message:{
          subject: subject||'Informe OPTIMIZARTE',
          body:{contentType:'HTML', content:htmlBody||''},
          toRecipients:[{emailAddress:{address:toAddress}}]
        },
        saveToSentItems:true
      };
      // Si hi ha attachmentName, afegir l'HTML com a adjunt
      if(attachmentName){
        var b64=btoa(unescape(encodeURIComponent(htmlBody||'')));
        msg.message.attachments=[{
          '@odata.type':'#microsoft.graph.fileAttachment',
          name: attachmentName,
          contentType:'text/html',
          contentBytes: b64
        }];
      }
      var r=await fetch('https://graph.microsoft.com/v1.0/me/sendMail',{
        method:'POST',
        headers:{Authorization:'Bearer '+tok,'Content-Type':'application/json'},
        body:JSON.stringify(msg)
      });
      if(r.status===401){_clearTok();return {ok:false,error:'Token expirat'};}
      if(r.status===202||r.ok){console.log('OD sendMail OK a',toAddress);return {ok:true};}
      var errText=await r.text();
      console.error('OD sendMail error:',r.status,errText);
      return {ok:false,error:'HTTP '+r.status+': '+errText.substring(0,200)};
    }catch(e){
      console.error('OD sendMail exception:',e);
      return {ok:false,error:e.message||String(e)};
    }
  }
  
  // ── Auto-refresh token (comprova cada 5 min, refresca si <15 min restants) ──
  var _arTimer=null;
  function startAutoRefresh(){
    if(_arTimer)return;
    console.log('OD: auto-refresh activat (comprova cada 5min, refresca si <15min)');
    _arTimer=setInterval(async function(){
      if(!_tok)return;
      var remaining=_exp-Date.now();
      if(remaining>15*60*1000)return; // encara queda temps
      console.log('OD: refrescant token ('+Math.round(remaining/60000)+' min restants)...');
      var newTok=await _silentToken();
      if(newTok){
        console.log('OD: token refrescat OK, nou exp: '+new Date(_exp).toLocaleTimeString('ca-ES'));
        if(typeof _updOdStatus==='function')_updOdStatus(true);
      } else {
        console.warn('OD: silent refresh fallit — token caducat');
        if(typeof _updOdStatus==='function')_updOdStatus(false);
        // Opacar agenda + mostrar modal selecció amb avís de desconnexió
        if(typeof _showDisconnectedModal==='function')_showDisconnectedModal();
      }
    },5*60*1000);
  }
  return{load,save,loadFile,saveFile,listFiles,sendMail,loginPopup,isReady,getUser,startAutoRefresh,
    _getTenant:function(){return TENANT;},
    _getClient:function(){return CLIENT;},
    _getRedirect:function(){return REDIRECT;},
    _getScope:function(){return SCOPE;}
  };
})();

// Exposar OD globalment perquè el bridge handler (fora de IIFE) pugui accedir-hi
try { window.OD = OD; } catch(e) {}

// Overrides en memòria (carregats de OneDrive a l'inici)
var _overrides={};
async function _loadOverrides(){
    _overrides=await OD.load();window._overrides=_overrides;
    
    // ── Migració v1 (existent): netejar dates feb/mar/maig 2026 ─────
    var _migKey='oa_ovr_mig_v1';
    if(localStorage.getItem(_migKey)!=='1'){
        var _cleaned=0;
        var _badMonths={'02':1,'03':1,'05':1};
        Object.keys(_overrides).forEach(function(id){
            var ov=_overrides[id];
            // Acceptar format string (antic) o object (nou)
            var dt=typeof ov==='string'?ov:(ov&&ov.ini)||'';
            if(!dt)return;
            var m1=dt.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
            var m2=dt.match(/^(\d{4})-(\d{2})-(\d{2})/);
            var mm=null,yyyy=null;
            if(m1){mm=m1[2];yyyy=m1[3];}
            else if(m2){mm=m2[2];yyyy=m2[1];}
            if(yyyy==='2026'&&_badMonths[mm]){delete _overrides[id];_cleaned++;}
        });
        if(_cleaned>0){
            console.log('🧹 Migració overrides v1: netejats '+_cleaned+' overrides bruts');
            window._overrides=_overrides;
            await OD.save(_overrides);
        }
        localStorage.setItem(_migKey,'1');
    }
    
    // ── Migració v2: netejar overrides molt antics (anteriors a 2024) ──
    // Aquests segurament són dates de creació antigues que es van guardar erròniament
    var _migKey2='oa_ovr_mig_v2';
    if(localStorage.getItem(_migKey2)!=='1'){
        var _cleaned2=0;
        Object.keys(_overrides).forEach(function(id){
            var ov=_overrides[id];
            var dt=typeof ov==='string'?ov:(ov&&ov.ini)||'';
            if(!dt)return;
            var m1=dt.match(/^(\d{2})\/(\d{2})\/(\d{4})/);
            var m2=dt.match(/^(\d{4})-(\d{2})-(\d{2})/);
            var yyyy=null;
            if(m1)yyyy=parseInt(m1[3],10);
            else if(m2)yyyy=parseInt(m2[1],10);
            if(yyyy&&yyyy<2024){
                console.log('   Override antic eliminat: id='+id+' data='+dt);
                delete _overrides[id];_cleaned2++;
            }
        });
        if(_cleaned2>0){
            console.log('🧹 Migració overrides v2: netejats '+_cleaned2+' overrides antics (<2024)');
            window._overrides=_overrides;
            await OD.save(_overrides);
        }
        localStorage.setItem(_migKey2,'1');
    }
    // Carregar assigns des de OD si existeix
    try{
        var asgData=await OD.loadFile('opticrm-assigns.json');
        if(asgData&&asgData.assigns){
            var localAsg=loadAsg();
            var merged=Object.assign({},asgData.assigns,localAsg);
            try{localStorage.setItem(ASG_KEY,JSON.stringify(merged));}catch(e){}
        }
    }catch(e){}
    // Carregar kanban des de OD si existeix
    try{
        var kbData=await OD.loadFile('opticrm-kanban.json');
        if(kbData&&kbData.kanban){
            Object.keys(kbData.kanban).forEach(function(k){
                if(!localStorage.getItem(k))_origLSSet(k,kbData.kanban[k]);
            });
        }
    }catch(e){}
    // Carregar VTOS des de OD (fitxer dedicat, sync immediat)
    try{
        var vtosOD=await OD.loadFile('opticrm-vtos.json');
        if(vtosOD&&Array.isArray(vtosOD.vtos)&&vtosOD.vtos.length>0){
            var localVt=loadVtos();
            var odVtIds=new Set(vtosOD.vtos.map(function(x){return x.id;}));
            // Merge: OD guanya, però afegim locals únics
            var mergedVt=vtosOD.vtos.concat(localVt.filter(function(x){return !odVtIds.has(x.id);}));
            try{localStorage.setItem(VTOS_KEY,JSON.stringify(mergedVt));}catch(e){}
            if(typeof S!=='undefined'&&S.vtos){
                S.vtos.items=mergedVt;
                if(typeof updVtos==='function')updVtos();
            }
            console.log('OD VTOS carregats: '+mergedVt.length+' items ('+vtosOD.vtos.length+' OD + '+(mergedVt.length-vtosOD.vtos.length)+' locals únics)');
        }
    }catch(e){}
}
async function _saveOverride(id,dt,which){
    // which: 'ini' (default), 'fi', o objecte {ini, fi}
    var entry=_overrides[id];
    // Format antic (string) → migrar a objecte
    if(typeof entry==='string')entry={ini:entry};
    if(!entry||typeof entry!=='object')entry={};
    
    if(typeof dt==='object'&&dt!==null){
        // Cas: dt és un objecte {ini, fi}
        if(dt.ini!==undefined)entry.ini=dt.ini;
        if(dt.fi!==undefined)entry.fi=dt.fi;
    } else if(which==='fi'){
        entry.fi=dt;
    } else {
        // Default: actualitzar TIM_INICI
        entry.ini=dt;
    }
    
    // Si l'objecte queda buit, eliminar entrada
    if(!entry.ini&&!entry.fi){
        delete _overrides[id];
    } else {
        _overrides[id]=entry;
    }
    window._overrides=_overrides;
    if(typeof OD!=='undefined'&&OD.isReady())await OD.save(_overrides);
    _triggerCacheSync();
}
