// Fetchejar CRM i actualitzar cache (reutilitza la lògica de fa())
// fetchActPage standalone per al sync en background (fetchActPage original és local a fa())
async function fetchActPageSync(cfg,page,paginaCode,pila){
    var msg={SelectorMediador:{ClaveSeleccionada:cfg.selMed},SelectorVista:{ClaveSeleccionada:'208'},
        CheckMisActividades:{Valor:false},Concepto:{Valor:null},
        AE_COD_MEDIADOR_RACF:'00017167',CIAGRUPO:'SCO',ENTIDAD:'Appointment',
        OPERATIVA:'GridActividades',NAVEGACION:page===1?'CARGA_INICIAL':'CARGA_PAGINADO',
        COD_MEDIADOR_LOGADO:'-1',UsuarioRol:'Oficina'};
    if(cfg.codAsoc)msg.CodAsociados={ClaveSeleccionada:cfg.codAsoc};
    msg.ListaResultados={Paginacion:{TamanoPagina:500}};
    if(page>1&&paginaCode){msg.ListaResultados.Paginacion.PaginacionPila=pila.slice();
        msg.ListaResultados.Paginacion.PaginacionCodigoSiguiente=paginaCode;
        msg.ListaResultados.Paginacion.Paginando=true;}
    var ctx=Object.assign({},CTX,{init:'ISC.Gaan.Actividad.FE.GridActividad'});
    var body=new URLSearchParams({'_GAAN_Mensaje_Pantalla_':JSON.stringify(msg),
        '_GAAN_Comando_':page===1?'buscar':'paginar',
        '_GAAN_ClientContext_':JSON.stringify(ctx),'_GAAN_SPA_':'true'});
    try{
        var r=await fetch('/FE/ISC.Gaan.Actividad.FE.GridActividad/',{method:'POST',
            headers:{'Content-Type':'application/x-www-form-urlencoded'},body:body.toString()});
        var j=await r.json();
        var lista=j&&j.message&&j.message.ListaResultados;
        var data=(lista&&lista.FuenteDatos)||[];
        var pag=lista&&lista.Paginacion;
        return{data:data,nextCode:pag&&pag.PaginacionCodigoSiguiente||null};
    }catch(e){return{data:[],nextCode:null};}
}
async function _syncFromCRM(){
    console.log('OD: sync CRM en background...');
    // ACT_CFGS definit localment (és dins fa() com a var local, no accessible des d'aquí)
    var _ACT_CFGS=[
        {targetUid:'M441819E',selMed:'M441819E',codAsoc:null},
        {targetUid:'M354046Y',selMed:'M354046Y',codAsoc:null},
        {targetUid:'MA44658D',selMed:'MA44658D',codAsoc:null}
    ];
    var opoCTX=null;
    try{
        var pageR=await fetch('/FE/ISC.Gaan.Oportunidad.FE.GridOportunidad/?_CIA=SCO');
        if(pageR.ok){
            var html=await pageR.text();
            var mm=html.match(/name="_GAAN_ClientContext_"[^>]*value='([^']+)'/);
            if(!mm)mm=html.match(/name="_GAAN_ClientContext_"[^>]*value="([^"]+)"/);
            if(mm){var cs=mm[1].replace(/&quot;/g,'"').replace(/&amp;/g,'&');opoCTX=JSON.parse(cs);}
        }
    }catch(e){}
    if(!opoCTX)opoCTX=Object.assign({},CTX,{init:'ISC.Gaan.Oportunidad.FE.GridOportunidad'});window._opoCTX=opoCTX;
    var seenAct=new Set();var seenOpo=new Set();
    var newActs=[];var newOpos=[];
    // Fetch actes
    for(var ci=0;ci<_ACT_CFGS.length;ci++){
        var cfg=_ACT_CFGS[ci],code=null,pila=[];
        for(var p=1;p<=40;p++){
            var r=await fetchActPageSync(cfg,p,code,pila);
            r.data.forEach(function(a){
                if(seenAct.has(a.IDACTIV))return;
                seenAct.add(a.IDACTIV);
                newActs.push(Object.assign({},a,{_uid:cfg.targetUid}));
            });
            if(!r.nextCode)break;
            pila.push(code||'1');code=r.nextCode;
        }
    }
    // Fetch OPOs
    var OPO_CFGS2=[{uid:'M441819E',selMed:'M441819E',codAsoc:null,targetUid:'M441819E'},{uid:'M354046Y',selMed:'M354046Y',codAsoc:null,targetUid:'M354046Y'},{uid:'MA44658D',selMed:'MA44658D',codAsoc:null,targetUid:'MA44658D'}];
    for(var oi=0;oi<OPO_CFGS2.length;oi++){
        var ocfg=OPO_CFGS2[oi],ocode=null,opila=[];
        for(var op=1;op<=40;op++){
            var or=await fetchOpoPageWithCtx(ocfg,op,ocode,opila,opoCTX);
            or.data.forEach(function(o){
                var uid=(o.UID_RACF||'').trim()||ocfg.targetUid;
                if(!USERS[uid])uid=ocfg.targetUid;
                if(seenOpo.has(o.IDOPOACT))return;
                seenOpo.add(o.IDOPOACT);
                newOpos.push({IDACTIV:o.IDOPOACT,IDOPOACT:o.IDOPOACT,_isOpo:true,_uid:uid,
                    DESASUN:o.ASUNTO,CLIENTE:o.CLIENTE,TIM_INICI:o.TIMFREA||'',
                    TIM_FI:o.TIMESTI||'',INDSITU_DESC:o.INDSITU_DESC||'Abierta',
                    INDACTI_DESC:'Oportunidad',INDPRIO_DESC:o.INDPRIORI_DESC,
                    OBSACT:o.OBSACT,UID_RACF:uid,NOMUSER:o.NOMUSER,
                    REFNUMPERS:o.REFNUMPERS,RAMEMIS_DESC:o.RAMEMIS_DESC,
                    DATOPOR:o.DATOPOR,TIMFREA:o.TIMFREA,
                    PRIEST:o.PRIEST,COMEST:o.COMEST,IDPROB:o.IDPROB});
            });
            if(!or.nextCode)break;
            opila.push(ocode||'1');ocode=or.nextCode;
        }
    }
    if(newActs.length+newOpos.length===0)return;
    // Aplicar assignacions
    var asg=loadAsg();
    var allNew=newActs.concat(newOpos);
    allNew.forEach(function(a){if(asg[String(a.IDACTIV)]&&USERS[asg[String(a.IDACTIV)]])a._uid=asg[String(a.IDACTIV)];});
    // Actualitzar S.all i renderitzar
    S.all=allNew;
    _applyOverrides();
    applyF();
    updC();
    // Merge estat local (kanban, urgent) amb OD abans de guardar
    // Llegir cache existent d'OD i fusionar l'estat local d'altres usuaris
    var existingCache=await OD.loadFile(CACHE_FILE);
    if(existingCache){
        // Fusionar kanban: OD guanya per claus que no tenim localment
        if(existingCache.kanban){
            Object.keys(existingCache.kanban).forEach(function(k){
                if(!localStorage.getItem(k))_origLSSet(k,existingCache.kanban[k]);
            });
        }
        // Fusionar urgent: unió de tots els flags
        if(existingCache.urgent){
            Object.keys(existingCache.urgent).forEach(function(k){
                if(existingCache.urgent[k]==='1'&&!localStorage.getItem(k))_origLSSet(k,'1');
            });
        }
        // Fusionar assigns: OD guanya
        if(existingCache.assigns){
            var localAsg2=loadAsg();
            var merged=Object.assign({},existingCache.assigns,localAsg2);
            saveAsg(merged);
        }
    }
    // Guardar a cache
    await saveCache();
    console.log('OD sync complet: '+newActs.length+' act, '+newOpos.length+' opos');
}

