// KK.2 — Rang mode global (vistes Tareas/Llista/Kanban/Foco/Cerca)
S.rangMode = S.rangMode || 'avui_atras';
function _passesRangModeGlobal(x, mode){
    mode = mode || S.rangMode || 'avui_atras';
    if(mode === 'totes') return true;
    var dStr = x.TIM_INICI || '';
    if(!dStr) return mode === 'totes';
    var parts = dStr.split('/');
    if(parts.length < 3) return true;
    var dt = new Date(parseInt(parts[2],10), parseInt(parts[1],10)-1, parseInt(parts[0],10));
    dt.setHours(0,0,0,0);
    var avui = new Date(); avui.setHours(0,0,0,0);
    if(mode === 'avui')       return dt.getTime() === avui.getTime();
    if(mode === 'atrassades') return dt.getTime() <  avui.getTime();
    if(mode === 'avui_atras') return dt.getTime() <= avui.getTime();
    if(mode === 'rang'){
        var from = S.dateRange && S.dateRange.from;
        var to   = S.dateRange && S.dateRange.to;
        if(from){ var fd = new Date(from); fd.setHours(0,0,0,0); if(dt < fd) return false; }
        if(to){   var td = new Date(to);   td.setHours(23,59,59,999); if(dt > td) return false; }
        return true;
    }
    return true;
}
function _buildRangPill(parentBar){
    if(!parentBar) return null;
    var labels = {avui:'AVUI', atrassades:'ATRASSADES', avui_atras:'AVUI + ATRASSADES', totes:'TOTES', rang:'SELECCIONAR DATES'};
    var btn = document.createElement('button');
    var mode = S.rangMode || 'avui_atras';
    var isActive = mode !== 'avui_atras';
    btn.className = 'foc-tpill' + (isActive ? ' on' : '');
    btn.style.cssText += ';font-size:10px;padding:4px 14px;white-space:nowrap;flex-shrink:0;min-width:max-content';
    btn.textContent = '📅 ' + (labels[mode] || mode);
    btn.title = 'Filtre Rang temporal';
    btn.dataset.rangPill = '1';
    btn.addEventListener('click', function(ev){
        ev.stopPropagation();
        _showRangPopoverGlobal(btn);
    });
    parentBar.appendChild(btn);
    return btn;
}
function _showRangPopoverGlobal(triggerEl){
    var rect = triggerEl.getBoundingClientRect();
    var pop = document.createElement('div');
    pop.style.cssText = ['position:fixed','left:'+Math.max(8,rect.left)+'px','top:'+(rect.bottom+4)+'px','background:#fff','border:2px solid #DC0028','border-radius:8px','padding:6px','z-index:2147483647','box-shadow:0 6px 20px rgba(0,0,0,.3)','min-width:240px','font-family:Arial,sans-serif','color:#202020'].join(';');
    var options = [
        {k:'avui',        l:'AVUI',                 sub:'data inici avui'},
        {k:'atrassades',  l:'ATRASSADES',           sub:"data inici abans d'avui"},
        {k:'avui_atras',  l:'AVUI + ATRASSADES',    sub:'avui i abans'},
        {k:'totes',       l:'TOTES',                sub:'sense filtre'},
        {k:'rang',        l:'SELECCIONAR DATES',    sub:'rang amb calendari'}
    ];
    options.forEach(function(o){
        var isAct = (S.rangMode === o.k);
        var optDiv = document.createElement('div');
        optDiv.style.cssText = 'padding:10px 12px;cursor:pointer;border-radius:6px;font-size:13px;' +
            (isAct ? 'background:rgba(220,0,40,.12);color:#DC0028;font-weight:700' : 'background:transparent;color:#414141;font-weight:600');
        optDiv.innerHTML = '<div>'+o.l+'</div><div style="font-size:10px;color:#888;margin-top:2px;font-weight:400">'+o.sub+'</div>';
        optDiv.addEventListener('mouseenter', function(){ if(S.rangMode !== o.k) this.style.background = '#f3f4f6'; });
        optDiv.addEventListener('mouseleave', function(){ if(S.rangMode !== o.k) this.style.background = 'transparent'; });
        optDiv.addEventListener('click', function(ev){
            ev.stopPropagation(); ev.preventDefault();
            if(o.k === 'rang'){
                S.rangMode = 'rang';
                pop.remove();
                if(typeof _showDateRangePopover === 'function') _showDateRangePopover(triggerEl);
                else if(typeof applyF === 'function') applyF();
            } else {
                S.rangMode = o.k;
                if(o.k !== 'rang' && S.dateRange) S.dateRange = {from:'', to:''};
                pop.remove();
                if(typeof applyF === 'function') applyF();
            }
        });
        pop.appendChild(optDiv);
    });
    document.body.appendChild(pop);
    setTimeout(function(){
        function _onDoc(e){
            var path = e.composedPath ? e.composedPath() : [e.target];
            if(path.indexOf(pop) === -1){
                pop.remove();
                document.removeEventListener('click', _onDoc, true);
                try{ if(typeof SR!=='undefined' && SR) SR.removeEventListener('click', _onDoc, true); }catch(_e){}
            }
        }
        document.addEventListener('click', _onDoc, true);
        try{ if(typeof SR!=='undefined' && SR) SR.addEventListener('click', _onDoc, true); }catch(_e){}
    }, 100);
}
