    foot.innerHTML='<button id="alta-cancel-btn" style="padding:8px 18px;background:transparent;border:1.5px solid var(--br);border-radius:6px;color:var(--t2);font-size:12px;cursor:pointer;font-family:inherit;font-weight:600">Tancar</button>';
