// NOTE: la funció _showClientDataForGestiona ha estat eliminada (2026-05-18) perquè
// el flux d'alta a Gestiona ara és totalment automàtic via gestiona-autofill.js.
// El click "Donar d'alta a Gestiona" del modal d'accions crida directament _altaOpenClientCRM.

// Executor: afegeix OPOs/ACTs al sidebar (mode simplificat — només sidebar)
async function _executeAltaCreate(payload,opos,acts){
    var creator=payload.colab_recoge_racf||payload.colab_asigna_racf||_activeUid||'M441819E';
    if(!USERS[creator])creator=_activeUid||'M441819E';
    
    var allItems=[];
    opos.forEach(function(opo){
        allItems.push({
            id:String(Date.now())+'_'+Math.random().toString(36).slice(2,7),
            asunto:opo.titol,
            cliente:payload.nombre_completo,
            refnumpers:payload.nif_cif||'',
            fecha:_altaTodayDDMMYYYY(),
            fecha2:_altaIsoToDDMMYYYY(opo.vto),
            tipo:'Oportunidad',
            usuari:creator,
            notas:opo.notes,
            creado:Date.now(),
            _altaSrc:true,
            _altaKbCol:opo.kbCol
        });
    });
    acts.forEach(function(act){
        allItems.push({
            id:String(Date.now())+'_'+Math.random().toString(36).slice(2,7),
            asunto:act.titol,
            cliente:payload.nombre_completo,
            refnumpers:payload.nif_cif||'',
            fecha:act.fecha,
            tipo:act.tipo,
            usuari:creator,
            notas:act.notes,
            creado:Date.now(),
            _altaSrc:true
        });
    });
    
    allItems.forEach(function(it){S.vtos.items.unshift(it);});
    saveVtos(S.vtos.items);
    updVtos();
    applyF();
    if(typeof saveCache==='function')saveCache().catch(function(){});
    
    _toast('\u2713 Afegits '+opos.length+' OPOs i '+acts.length+' activitats al sidebar Noves OPO/ACT','#10B981',5500);
}

// Helper: obre la fitxa del client al CRM Gestiona en una nova pestanya
function _altaOpenClientCRM(payload){
    try{
        // Prioritat 1: si tenim refnumpers (NUMPERS/REFPERS) → Visión 360 directament
        var refnumpers=payload.refnumpers||'';
        if(!refnumpers && payload.numpers){
            refnumpers=payload.numpers+'/'+(payload.refpers||'000');
        }
        // Si no tenim refnumpers, intentar trobar-lo a S.all per NIF
        if(!refnumpers && payload.nif_cif && window.S && S.all){
            var nifClean=payload.nif_cif.replace(/\s/g,'').toUpperCase();
            for(var i=0;i<S.all.length;i++){
                var a=S.all[i];
                if(!a.REFNUMPERS||!a.OBSACT)continue;
                var obs=String(a.OBSACT||'').toUpperCase();
                if(obs.indexOf(nifClean)>=0){
                    refnumpers=a.REFNUMPERS;
                    console.log('[ALTA-BRIDGE] refnumpers trobat via S.all:',refnumpers);
                    break;
                }
            }
        }
        
        if(refnumpers){
            // CLIENT EXISTENT → Visión 360
            var refPts=refnumpers.split('/');
            var numpers=refPts[0]||'';
            var refpers=refPts[1]||'000';
            var v360Url='https://catalanaaplicaciones.gco.global/FE/PER.Clientes.Menu.FE.Busqueda/?_CIA=SCO&NUMPERS='+encodeURIComponent(numpers)+'&REFPERS='+encodeURIComponent(refpers)+'&ORIGEN=PER&_t='+Date.now();
            console.log('[ALTA-BRIDGE] obrint Visión 360 (client existent):',v360Url);
            setTimeout(function(){window.open(v360Url,'_blank');},800);
            return;
        }
        
        // CLIENT NOU → desar dades a window i obrir pantalla d'alta Gestiona
        // El content script gestiona-autofill.js demanarà les dades a window.opener via postMessage
        // (NO podem usar chrome.storage perquè app.js NO és content script — és <script> injectat)
        var altaUrl='https://gestiona.gco.global/gestionadministrativa/gestiondeclientes/gestionclientesoccident';
        try {
            var payloadWithTs = Object.assign({}, payload, { _ts: Date.now() });
            // Desem el payload com a variable global perquè el listener postMessage el pugui retornar
            window._opticrmPendingAlta = payloadWithTs;
            console.log('[ALTA-BRIDGE] Payload guardat a window._opticrmPendingAlta (postMessage listener actiu)');

            // Listener postMessage UN COP (idempotent — flag per evitar duplicats)
            if (!window._opticrmAltaListener) {
                window._opticrmAltaListener = true;
                window.addEventListener('message', function(ev) {
                    if (!ev.data || ev.data.type !== 'OPTICRM_REQUEST_ALTA') return;
                    // Verificar origen Gestiona (subdomini de gco.global, no estricte per flexibilitat)
                    if (!/gco\.global$/.test(ev.origin.replace(/^https?:\/\//,'').split('/')[0])) {
                        console.warn('[ALTA-BRIDGE] origen rebutjat:', ev.origin);
                        return;
                    }
                    if (window._opticrmPendingAlta) {
                        try {
                            ev.source.postMessage({
                                type: 'OPTICRM_ALTA_DATA',
                                payload: window._opticrmPendingAlta
                            }, ev.origin);
                            console.log('[ALTA-BRIDGE] payload enviat a Gestiona via postMessage');
                            // Esborrem el payload després d'enviar-lo (un sol ús)
                            window._opticrmPendingAlta = null;
                        } catch(eP) {
                            console.warn('[ALTA-BRIDGE] error enviant payload:', eP);
                        }
                    } else {
                        console.log('[ALTA-BRIDGE] no hi ha payload pendent');
                    }
                });
            }
            setTimeout(function(){window.open(altaUrl,'_blank');},200);
        } catch(eSt) {
            console.warn('[ALTA-BRIDGE] error preparant payload:', eSt);
            setTimeout(function(){window.open(altaUrl,'_blank');},200);
        }
    }catch(_e){console.warn('[ALTA-BRIDGE] obrir client error:',_e&&_e.message);}
}
try { window._altaOpenClientCRM = _altaOpenClientCRM; } catch(e) {}

// ═══════════════════════════════════════════════════════════════
// CLIENT-SEARCH BRIDGE — gestor de cerca de client per al formulari
// ═══════════════════════════════════════════════════════════════

// Envia el resultat al formulari (window.opener) i tanca la pestanya
function _sendClientSearchResultToOpener(found, clientData){
    try{
        if(window.opener && !window.opener.closed){
            window.opener.postMessage({
                type:'_opticrm_client_search_result',
                _opticrm:true,
                found:!!found,
                client:clientData||null
            },'*');
            console.log('[CLIENT-SEARCH] resultat enviat a opener:',{found:found,client:clientData});
        }
    }catch(e){console.warn('[CLIENT-SEARCH] error postMessage:',e&&e.message);}
}

// Mostra una notificació visual a la pestanya de cerca
function _showClientSearchOverlay(text, color){
    try{
        var existing=document.getElementById('_opticrm-search-overlay');
        if(existing)existing.remove();
        var ov=document.createElement('div');
        ov.id='_opticrm-search-overlay';
        ov.style.cssText='position:fixed;top:50%;left:50%;transform:translate(-50%,-50%);z-index:2147483647;background:'+(color||'#DC0028')+';color:#fff;padding:24px 32px;border-radius:14px;font-family:inherit;font-size:14px;font-weight:700;box-shadow:0 12px 48px rgba(0,0,0,.5);text-align:center;max-width:480px;line-height:1.5';
        ov.innerHTML=text;
        document.body.appendChild(ov);
    }catch(e){}
}

// Funció principal: cerca un client per NIF/nom i retorna les dades al opener
// Exporta tots els clients distincts de S.all al window.opener (formulari)
async function _handleClientsExport(){
    _showClientSearchOverlay('\ud83d\udce5 Exportant llista de clients per al formulari...','#3B82F6');
    
    // Esperar que S.all estigui carregat
    var _wait=0;
    while((!window.S||!S.all||S.all.length===0)&&_wait<30){
        await new Promise(function(r){setTimeout(r,500);});
        _wait++;
    }
    
    var clients=[];
    if(window.S&&S.all){
        var seen={};
        S.all.forEach(function(a){
            if(!a.REFNUMPERS||!a.CLIENTE)return;
            if(seen[a.REFNUMPERS])return;
            seen[a.REFNUMPERS]=true;
            // Intentar extreure NIF d'OBSACT (alguns clients el tenen)
            var nifGuess='';
            var obs=String(a.OBSACT||'');
            var nifMatch=obs.match(/\b([0-9]{8}[A-Z])\b/) || obs.match(/\b([A-Z][0-9]{7,8}[0-9A-Z]?)\b/);
            if(nifMatch)nifGuess=nifMatch[1];
            clients.push({nom:a.CLIENTE,ref:a.REFNUMPERS,nif:nifGuess});
        });
    }
    
    console.log('[CLIENTS-EXPORT] enviant',clients.length,'clients');
    
    // Enviar al opener (formulari)
    try{
        if(window.opener && !window.opener.closed){
            window.opener.postMessage({
                type:'_opticrm_clients_export',
                _opticrm:true,
                clients:clients,
                exportedAt:Date.now()
            },'*');
        }
    }catch(e){console.warn('[CLIENTS-EXPORT] error postMessage:',e&&e.message);}
    
    _showClientSearchOverlay('\u2705 Llista exportada: <b>'+clients.length+'</b> clients<br><span style="font-size:11px;font-weight:400;opacity:.85">Aquesta finestra es tancar\u00e0 autom\u00e0ticament</span>','#10B981');
    
    setTimeout(function(){
        try{window.close();}catch(e){}
    },2000);
}

async function _handleClientSearchRequest(query){
    if(!query)return;
    var qNorm=String(query).trim().toUpperCase().replace(/\s+/g,' ');
    
    _showClientSearchOverlay('\ud83d\udd0d Cercant <b>'+esc(qNorm)+'</b> a Gestiona...<br><span style="font-size:11px;font-weight:400;opacity:.85">Aquesta finestra es tancar\u00e0 autom\u00e0ticament</span>','#3B82F6');
    
    // Esperar que S.all estigui carregat (potser ja ho està via cache)
    var _wait=0;
    while((!window.S||!S.all||S.all.length===0)&&_wait<30){
        await new Promise(function(r){setTimeout(r,500);});
        _wait++;
    }
    
    if(!window.S||!S.all){
        _showClientSearchOverlay('\u274c Agenda no carregada. Intenta-ho de nou.','#DC0028');
        _sendClientSearchResultToOpener(false,null);
        setTimeout(function(){try{window.close();}catch(e){}},2500);
        return;
    }
    
    // 1) Detectar si query és format NIF/CIF
    var qClean=qNorm.replace(/\s|-/g,'');
    var isNifFormat=/^[0-9]{8}[A-Z]$/.test(qClean) || /^[A-Z][0-9]{7,8}[0-9A-Z]?$/.test(qClean);
    
    // 2) Cercar a S.all per nom, refnumpers, i OBSACT (per si l'NIF està a observacions)
    var matches=[];
    var seen={};
    S.all.forEach(function(a){
        if(!a.REFNUMPERS||!a.CLIENTE)return;
        if(seen[a.REFNUMPERS])return;
        var name=String(a.CLIENTE||'').toUpperCase();
        var ref=String(a.REFNUMPERS||'').toUpperCase();
        var obs=String(a.OBSACT||'').toUpperCase();
        // Match si el query apareix al nom, refnumpers, o (per NIF) a observacions
        var matched=false;
        if(name.indexOf(qNorm)>=0)matched=true;
        else if(ref.indexOf(qNorm)>=0)matched=true;
        else if(isNifFormat && obs.indexOf(qClean)>=0)matched=true;
        if(matched){
            seen[a.REFNUMPERS]=true;
            matches.push({nom:a.CLIENTE,ref:a.REFNUMPERS});
        }
    });
    
    console.log('[CLIENT-SEARCH] query=',qNorm,'isNif=',isNifFormat,'matches=',matches.length);
    
    if(matches.length===0){
        // No trobat a S.all
        var hint=isNifFormat
            ? 'El NIF <b>'+esc(qClean)+'</b> no apareix a cap client amb activitat actual a l\'agenda.<br><span style="font-size:11px;font-weight:400;opacity:.85">Si \u00e9s un client existent al CRM per\u00f2 sense OPOs/ACTs actives, prova cercar pel <b>nom o cognoms</b>. Si \u00e9s un client nou, fes l\'alta directa al formulari.</span>'
            : 'No s\'ha trobat <b>'+esc(qNorm)+'</b> a clients amb OPOs/ACTs actives.<br><span style="font-size:11px;font-weight:400;opacity:.85">Si \u00e9s un client nou, fes l\'alta directa al formulari. Si existeix, comprova manualment a Gestiona.</span>';
        _showClientSearchOverlay('\u26a0 '+hint,'#F59E0B');
        _sendClientSearchResultToOpener(false,null);
        setTimeout(function(){try{window.close();}catch(e){}},5000);
        return;
    }
    
    // 2) Si hi ha un sol match clar, extraure'n dades. Si n'hi ha varios, usar el primer.
    var picked=matches[0];
    if(matches.length>1){
        _showClientSearchOverlay('\u2139 Trobats <b>'+matches.length+'</b> clients. Important el primer:<br><b>'+esc(picked.nom)+'</b><br><span style="font-size:10px;font-weight:400;opacity:.85">'+esc(picked.ref)+'</span>','#3B82F6');
    } else {
        _showClientSearchOverlay('\u2705 Client trobat: <b>'+esc(picked.nom)+'</b><br><span style="font-size:11px;font-weight:400;opacity:.85">Extraient dades completes...</span>','#10B981');
    }
    
    // 3) Usar _loadInteropData per extreure NIF, telf, email, adre\u00e7a... mitjan\u00e7ant iframe ocult
    var refnumpers=picked.ref;
    var clientName=picked.nom;
    var refPts=refnumpers.split('/');
    var numpers=refPts[0]||'';
    var refpers=refPts[1]||'000';
    
    // Crear container temporal per a _loadInteropData (no es mostra)
    var tmpContainer=document.createElement('div');
    tmpContainer.style.display='none';
    document.body.appendChild(tmpContainer);
    
    var resolved=false;
    
    // Listener per als resultats de l'extensi\u00f3 (CustomEvent _opticrm_res_v360_data)
    var onResult=function(e){
        if(resolved)return;
        var resp=e.detail;
        if(resp&&resp.ok&&resp.data&&(resp.data.nif||resp.data.email||resp.data.telefon)){
            resolved=true;
            window.removeEventListener('_opticrm_res_v360_data',onResult);
            
            // Compondre l'objecte client per al formulari
            var clientObj={
                nombre:clientName,
                nombreCompleto:clientName,
                refnumpers:refnumpers,
                nif:resp.data.nif||'',
                telefon:resp.data.telefon||resp.data.telefono||'',
                telefono:resp.data.telefon||resp.data.telefono||'',
                movil:resp.data.movil||'',
                email:resp.data.email||'',
                email2:resp.data.email2||'',
                direccion:resp.data.direccion||resp.data.dir||'',
                dir:resp.data.direccion||resp.data.dir||'',
                cp:resp.data.cp||'',
                localidad:resp.data.localidad||resp.data.poblacio||resp.data.poblacion||'',
                poblacio:resp.data.localidad||resp.data.poblacio||resp.data.poblacion||'',
                fnac:resp.data.fnac||'',
                sexo:resp.data.sexo||''
            };
            
            _showClientSearchOverlay('\u2705 Dades importades a OPTIMIZARTE\u2192<br><b>'+esc(clientObj.nombre)+'</b><br>NIF: <b>'+esc(clientObj.nif||'?')+'</b> \u00b7 Tel: <b>'+esc(clientObj.telefon||'?')+'</b>','#10B981');
            _sendClientSearchResultToOpener(true,clientObj);
            try{tmpContainer.remove();}catch(e2){}
            setTimeout(function(){try{window.close();}catch(e2){}},2500);
        }
    };
    window.addEventListener('_opticrm_res_v360_data',onResult);
    
    // Crear iframe ocult que cridarà l'extensió
    var v360Url='https://catalanaaplicaciones.gco.global/FE/PER.Clientes.Menu.FE.Busqueda/?_CIA=SCO&NUMPERS='+encodeURIComponent(numpers)+'&REFPERS='+encodeURIComponent(refpers)+'&ORIGEN=PER&_t='+Date.now();
    var ifr=document.createElement('iframe');
    ifr.id='_iop_search_ifr';
    ifr.src=v360Url;
    ifr.style.cssText='position:fixed;width:1px;height:1px;left:-9999px;top:-9999px;border:none;opacity:0;pointer-events:none';
    document.body.appendChild(ifr);
    
    var _loadCount=0;
    ifr.addEventListener('load',function(){
        _loadCount++;
        clearTimeout(ifr._loadTimer);
        ifr._loadTimer=setTimeout(function(){
            window.postMessage({
                type:'_opticrm_req_v360_iframe',
                numpers:numpers,
                clientName:clientName||'',
                _opticrm:true
            },'*');
        },500);
    });
    
    // Timeout: si no respon en 20s, enviar nom\u00e9s les dades b\u00e0siques que tenim
    setTimeout(function(){
        if(resolved)return;
        resolved=true;
        window.removeEventListener('_opticrm_res_v360_data',onResult);
        try{ifr.remove();}catch(e){}
        try{tmpContainer.remove();}catch(e){}
        // Enviar al menys les dades b\u00e0siques (nom + ref) sense NIF/contacte
        var basic={
            nombre:clientName,
            nombreCompleto:clientName,
            refnumpers:refnumpers,
            nif:'',
            telefon:'',
            email:''
        };
        _showClientSearchOverlay('\u26a0 Timeout extracci\u00f3. Enviem nom\u00e9s nom i refer\u00e8ncia:<br><b>'+esc(clientName)+'</b><br><span style="font-size:10px;font-weight:400;opacity:.85">Hauràs d&#39;omplir NIF i contacte manualment.</span>','#F59E0B');
        _sendClientSearchResultToOpener(true,basic);
        setTimeout(function(){try{window.close();}catch(e){}},3500);
    },20000);
}

function applyF(){
    if(S.view==='reunio'){try{if(window._OAvDash)window._OAvDash.refresh();}catch(e){}return;}
    var _drF=(S.dateRange&&S.dateRange.from)||'';
    var _drT=(S.dateRange&&S.dateRange.to)||'';
    var _hasRange=_drF||_drT;
    
    if(_hasRange){
        // ── MODE RANG: prevaler sobre TOTS els altres filtres (excepte cerca de text) ──
        S.fil=S.all.filter(function(a){
            // Només respectem la cerca textual i els tipus globals OPO/ACT (rts)
            var isOpo=!!a._isOpo;
            if(isOpo&&!S.rts.has('opo'))return false;
            if(!isOpo&&!S.rts.has('act'))return false;
            if(S.sq){var q=S.sq.toLowerCase();var hay=(a.DESASUN||'').toLowerCase()+(a.CLIENTE||'').toLowerCase()+(a.CODMEDI_DESC||'').toLowerCase();if(hay.indexOf(q)<0)return false;}
            // Comprovem el rang sobre TIM_INICI
            var dRaw=(a.TIM_INICI||'').slice(0,10);
            if(!dRaw)return false;
            var dp=dRaw.split('/');
            if(dp.length!==3)return false;
            var iso=dp[2]+'-'+dp[1]+'-'+dp[0];
            if(_drF&&iso<_drF)return false;
            if(_drT&&iso>_drT)return false;
            return true;
        });
    } else {
        // ── MODE NORMAL: filtres habituals ──
        S.fil=S.all.filter(function(a){
            var uid=a._uid||a.UID_RACF||'M441819E';
            if(!S.aU.has(uid))return false;
            if(!S.aT.has(gT(a)))return false;
            var _st=gS(a);if(S.sf!=='don'&&(_st==='co'||_st==='ca'))return false;
            if(S.sf==='pen')return gS(a)==='ab';
            if(S.sf==='don')return gS(a)==='co';
            if(S.sf==='vis')return gT(a)==='Visita'&&S.aS.has(gS(a));
            if(S.sf==='cit')return gT(a)==='Cita'&&S.aS.has(gS(a));
            if(!S.aS.has(gS(a)))return false;
            var isOpo=gT(a)==='Oportunidad';
            if(isOpo&&!S.rts.has('opo'))return false;
            if(!isOpo&&!S.rts.has('act'))return false;
            if(S.sq){var q=S.sq.toLowerCase();var hay=(a.DESASUN||'').toLowerCase()+(a.CLIENTE||'').toLowerCase()+(a.CODMEDI_DESC||'').toLowerCase();if(hay.indexOf(q)<0)return false;}
            return true;
        });
    }
    // KK.2 — Filtre Rang temporal per a vistes Tareas/Llista/Kanban/Foco/Cerca
    var _rmViews = ['kanban','tareas','list','focus','clients'];
    if(_rmViews.indexOf(S.view) >= 0 && S.rangMode && S.rangMode !== 'totes'){
        S.fil = S.fil.filter(function(x){ return _passesRangModeGlobal(x); });
    }
    _urgFirst(S.fil);updC();render();
}
