function gUrgAct(id){return localStorage.getItem('urg_act_'+id)==='1';}
function _setUrgOpo(id,v){if(v)localStorage.setItem('urg_opo_'+id,'1');else localStorage.setItem('urg_opo_'+id,'0');}
