            var allIds=S.fil.map(function(a){return a._isOpo?(a.IDOPOACT||a.IDACTIV):a.IDACTIV;});
            allIds.forEach(function(id){_sel.add(id);});
            qa('.act,.foc-card,.la,.wact,.kb-card').forEach(function(el){el.style.outline='2px solid #8B5CF6';});
