            var _pp1d=ov.querySelector('#opo-post1d-'+a.IDOPOACT);
            if(_pp1d)_pp1d.addEventListener('click',function(){
                var _cur=_fromISO(ov.querySelector('#prox-inp-'+a.IDOPOACT).value)||new Date();
                _setProxInp(_nextLaboral(_cur));
            });
            var _pp1w=ov.querySelector('#opo-post1w-'+a.IDOPOACT);
