                                _toast('🎯 Propensió finalitzada · Obrint ACT al CRM…','#10B981',2500);
                                try { if(_OAv && typeof _OAv.oa === 'function') _OAv.oa(a.IDACTIV); } catch(_e){ console.warn('finprop oa:',_e.message); }
                                applyF();
