                rowHdr.innerHTML='<span style="font-size:8.5px;font-weight:800;color:var(--t3);letter-spacing:.8px;text-transform:uppercase">'+_rowLabels[ri]+'</span>'+
                    '<span style="font-size:9px;background:var(--bg3);border:1px solid var(--br);border-radius:8px;padding:0 6px;color:var(--t3);font-weight:700">'+rowItems.length+'</span>';
