var _lockOv = null;
var _lockTimer = null;
var _lockAnimPct = 0;
// Helper: espera que el navegador hagi pintat el DOM (mínim 2 frames + buffer)
function _waitForPaint(extraMs) {
    return new Promise(function(resolve){
        requestAnimationFrame(function(){
            requestAnimationFrame(function(){
                setTimeout(resolve, extraMs||80);
            });
        });
    });
}

// AA.3 — Esperar que el CRM hagi acabat de carregar
// Considerem ready quan: document.readyState='complete' I DOM body s'ha estabilitzat 1s
// Failsafe: maxMs (default 30000ms)
function _waitForCRMReady(maxMs) {
    maxMs = maxMs || 30000;
    return new Promise(function(resolve){
        var startT = Date.now();
        var checkReady = function(){
            if(document.readyState !== 'complete'){
                if(Date.now() - startT > maxMs){
                    console.warn('[CRM-ready] timeout per readyState');
                    return resolve('timeout-readyState');
                }
                return setTimeout(checkReady, 100);
            }
            var lastChange = Date.now();
            var observer;
            try {
                observer = new MutationObserver(function(){ lastChange = Date.now(); });
                observer.observe(document.body, {childList:true, subtree:true, attributes:false});
            } catch(eO){
                console.warn('[CRM-ready] MutationObserver err:', eO);
                return resolve('no-observer');
            }
            var stableMs = 1000;
            var pollIv = setInterval(function(){
                var sinceChange = Date.now() - lastChange;
                var elapsed = Date.now() - startT;
                if(sinceChange >= stableMs){
                    clearInterval(pollIv);
                    try{ observer.disconnect(); }catch(e){}
                    console.log('[CRM-ready] DOM estable, ready en', elapsed, 'ms');
                    resolve('ready');
                } else if(elapsed > maxMs){
                    clearInterval(pollIv);
                    try{ observer.disconnect(); }catch(e){}
                    console.warn('[CRM-ready] timeout (DOM segueix canviant)');
                    resolve('timeout');
                }
            }, 200);
        };
        checkReady();
    });
}


// ── GEAR MENU — PIN 7950 ────────────────────────────────────────────────
function _gearToggle(ev){
  ev.stopPropagation();
  var m=SR.getElementById('gear-menu');
  if(!m)return;
  var isOpen=m.classList.contains('open');
  if(!isOpen){
    var pin=SR.getElementById('gear-pin');
    var items=SR.getElementById('gear-items');
    var pinWrap=SR.getElementById('gear-pin-wrap');
    var _stillUnlocked=typeof _gearUnlockExpiry!=='undefined'&&Date.now()<_gearUnlockExpiry;
    if(pin)pin.value='';
    if(_stillUnlocked){
      if(pinWrap)pinWrap.style.display='none';
      if(items)items.style.display='flex';
    } else {
      if(items)items.style.display='none';
      if(pinWrap)pinWrap.style.display='';
    }
    m.classList.add('open');
    setTimeout(function(){if(!_stillUnlocked&&pin)pin.focus();},60);
    var _cg=function(e){
      var wrap=SR.getElementById('gear-wrap');
      if(wrap&&(wrap===e.target||wrap.contains(e.target)))return;
      m.classList.remove('open');
      document.removeEventListener('click',_cg,true);
    };
    setTimeout(function(){document.addEventListener('click',_cg,true);},10);
  }else{
    m.classList.remove('open');
  }
}
var _gearUnlockExpiry=0;
function _gearPin(val){
  if(val==='7950'){_gearUnlockExpiry=Date.now()+5*60*1000;}
  if(val!=='7950'&&Date.now()>_gearUnlockExpiry)return;
  var items=SR.getElementById('gear-items');
  var pinWrap=SR.getElementById('gear-pin-wrap');
  var devRow=SR.getElementById('gear-dev-row');
  var isDev=localStorage.getItem('oa_skip_crm_fetch')==='1';
  if(devRow)devRow.innerHTML='<button class="gear-item'+(isDev?' dev-on':'')+'" onclick="_OAv.toggleDevMode();_gearRefreshDev()">🔌 Dev mode'+(isDev?' ✓':'')+'</button>';
  if(pinWrap)pinWrap.style.display='none';
  if(items){items.style.display='flex';}
}
function _gearClose(){
  var m=SR.getElementById('gear-menu');
  if(m)m.classList.remove('open');
}
function _gearRefreshDev(){
  setTimeout(function(){
    var isDev=localStorage.getItem('oa_skip_crm_fetch')==='1';
    var devRow=SR.getElementById('gear-dev-row');
    if(!devRow)return;
    devRow.innerHTML='<button class="gear-item'+(isDev?' dev-on':'')+'" onclick="_OAv.toggleDevMode();_gearRefreshDev()">🔌 Dev mode'+(isDev?' ✓':'')+'</button>';
  },100);
}
