function lockUI(){
    if(_lockOv) return;
    _lockOv = document.createElement('div');
    _lockOv.id = 'opticrm-init-lock';
    _lockOv.style.cssText = [
        'position:fixed;inset:0',
        'z-index:2147483647',
        'display:flex;flex-direction:column;align-items:center;justify-content:center;gap:18px',
        'background:rgba(10,10,14,.88);backdrop-filter:blur(5px)',
        'font-family:Inter,system-ui,sans-serif'
    ].join(';');
    _lockOv.innerHTML =
        '<div style="width:56px;height:56px;border-radius:14px;background:#DC0028;display:grid;place-items:center;font-weight:900;font-size:26px;color:#fff;box-shadow:0 6px 24px rgba(220,0,40,.5);letter-spacing:-1px">O</div>'+
        '<div style="text-align:center">'+
        '<div style="font-size:14px;font-weight:700;color:#F2F2F8;letter-spacing:.5px;margin-bottom:3px">OPTIMIZART€ 3.0</div>'+
        '<div style="font-size:9px;color:#bcbcbc;letter-spacing:1px;text-transform:uppercase">Agenda Comercial</div>'+
        '</div>'+
        '<div id="opticrm-lock-lbl" style="font-size:11px;color:#bcbcbc;letter-spacing:.5px;min-height:16px;text-align:center">Inicialitzant...</div>'+
        '<div style="width:220px;height:4px;background:rgba(255,255,255,.07);border-radius:4px;overflow:hidden">'+
        '<div id="opticrm-lock-bar" style="height:100%;background:#DC0028;border-radius:4px;width:0%;transition:width .6s ease"></div>'+
        '</div>';
    document.body.appendChild(_lockOv);
    // Bloquejar el host del Shadow DOM
    host.style.pointerEvents = 'none';
    // Animació suau per temps: 0→88% en ~18s (easing exponencial)
    _lockAnimPct = 0;
    if(_lockTimer) clearInterval(_lockTimer);
    _lockTimer = setInterval(function(){
        if(!_lockOv) { clearInterval(_lockTimer); _lockTimer=null; return; }
        var remaining = 88 - _lockAnimPct;
        _lockAnimPct += remaining * 0.022; // avanç exponencialment decreixent
        var bar = _lockOv.querySelector('#opticrm-lock-bar');
        if(bar) bar.style.width = _lockAnimPct.toFixed(1) + '%';
    }, 120);
}
function setLockProgress(pct, label){
    if(!_lockOv) return;
    try{
        var lbl = _lockOv.querySelector('#opticrm-lock-lbl');
        // Actualitzar label amb la fase real
        if(lbl && label) lbl.textContent = label;
        // Si el progrés real supera l'animació per temps, avançar la barra
        if(pct!=null && pct > _lockAnimPct){
            _lockAnimPct = pct;
            var bar = _lockOv.querySelector('#opticrm-lock-bar');
            if(bar) bar.style.width = pct + '%';
        }
    }catch(e){}
}
function unlockUI(){
    if(!_lockOv) return;
    // Aturar animació de progrés
    if(_lockTimer){ clearInterval(_lockTimer); _lockTimer=null; }
    var bar = _lockOv.querySelector('#opticrm-lock-bar');
    host.style.pointerEvents = '';

    // Quanta amplada falta per al 100%? (llegim style.width — pot ser p.ex. "73.4%")
    var currWidth = 0;
    if(bar){
        var ws = bar.style.width;
        currWidth = parseFloat(ws) || 0;
    }
    var needsFill = currWidth < 99;

    var fadeAndRemove = function(){
        if(!_lockOv) return;
        _lockOv.style.transition = 'opacity .4s ease';
        _lockOv.style.opacity = '0';
        setTimeout(function(){ try{_lockOv.remove();}catch(e){} _lockOv=null; }, 420);
    };

    if(bar && needsFill){
        // Forçar transició ràpida i reflow perquè s'apliqui ABANS del canvi de width
        bar.style.transition = 'width .35s ease-out';
        void bar.offsetWidth;  // reflow
        bar.style.width = '100%';
        // 350ms per omplir + 700ms perquè es vegi el "Llest!" abans del fade
        setTimeout(fadeAndRemove, 1100);
    } else {
        // Ja és al 100% — només mostrem un instant abans del fade
        setTimeout(fadeAndRemove, 700);
    }
}


