// ── Selector d'usuari durant la pantalla de càrrega ─────────────
function showUserSelectorInLock(onSelect){
    if(!_lockOv){onSelect(null);return;}
    // ── Prioritat: 1) CTX del CRM (sessió real) 2) localStorage 3) Modal ──
    // CTX pot identificar el mediador si el RACF personal consta al context
    var _ctxUid=null;
    try{
        var _cr=CTX&&(CTX.UID_RACF||CTX.mediadorRacf||CTX.racf||CTX.Racf||CTX.usuario||'');
        if(_cr&&UIDS.indexOf(_cr.trim())>=0)_ctxUid=_cr.trim();
    }catch(e){}
    if(_ctxUid){
        // CTX identifica un usuari concret del equip → auto-seleccionar sense modal
        try{localStorage.setItem('opticrm_sel_uid',_ctxUid);}catch(e){}
        onSelect(_ctxUid);
        return;
    }
    // CTX no determinant (RACF d'oficina comú) → aplicar 3 condicionants
    // Modal apareix SI: 1er cop del dia · OD desconnectat · 3h+ del darrer login
    var _savedUid=null;
    var _showPicker=false;
    var _pickerReason='';
    try{
        var _su=localStorage.getItem('opticrm_sel_uid');
        var _suTs=parseInt(localStorage.getItem('opticrm_sel_uid_ts')||'0',10);
        var _force=localStorage.getItem('opticrm_force_user_pick')==='1';
        var _odReady=(typeof OD!=='undefined'&&OD.isReady());
        
        // Condició 0: usuari ha forçat el canvi (botó 👤)
        if(_force){
            localStorage.removeItem('opticrm_force_user_pick');
            _showPicker=true;_pickerReason='forçat per usuari';
        }
        // Condició 1: cap usuari guardat o invàlid → cal seleccionar
        else if(!_su||UIDS.indexOf(_su)<0){
            _showPicker=true;_pickerReason='cap usuari guardat';
        }
        // Condició 2: OD no està connectat (silent token ha fallat)
        else if(!_odReady){
            _showPicker=true;_pickerReason='OD desconnectat';
        }
        // Condició 3: 3h+ del darrer login
        else if(_suTs>0&&(Date.now()-_suTs)>=3*60*60*1000){
            _showPicker=true;_pickerReason='3h+ del darrer login';
        }
        // Condició 4: primer cop del dia (data login != data avui)
        else if(_suTs>0){
            var _lastDate=new Date(_suTs);
            var _today=new Date();
            var _sameDay=_lastDate.getFullYear()===_today.getFullYear()&&
                         _lastDate.getMonth()===_today.getMonth()&&
                         _lastDate.getDate()===_today.getDate();
            if(!_sameDay){
                _showPicker=true;_pickerReason='primer cop del dia';
            } else {
                _savedUid=_su;
            }
        } else {
            _savedUid=_su;
        }
    }catch(e){_showPicker=true;_pickerReason='error: '+e.message;}
    
    if(!_showPicker&&_savedUid){
        console.log('[USER-PICKER] auto-seleccionat: '+_savedUid+' (sense modal)');
        onSelect(_savedUid);
        return;
    }
    console.log('[USER-PICKER] modal mostrat. Motiu: '+_pickerReason);
    // Res guardat → mostrar modal de selecció
    // Amaguen el label i la barra temporalment
    var lbl=_lockOv.querySelector('#opticrm-lock-lbl');
    var barWrap=_lockOv.querySelector('#opticrm-lock-bar')?.parentElement;
    if(lbl)lbl.style.display='none';
    if(barWrap)barWrap.style.display='none';

    var sel=document.createElement('div');
    sel.id='lock-user-sel';
    sel.style.cssText='display:flex;flex-direction:column;align-items:center;gap:16px;animation:modalIn .25s ease both';

    var title=document.createElement('div');
    title.style.cssText='text-align:center';
    title.innerHTML='<div style="font-size:11px;color:#6060A0;letter-spacing:.3px">'+(_odAlready?'OneDrive connectat · Confirma qui ets':'Selecciona el teu usuari per activar OneDrive')+'</div>';
    sel.appendChild(title);

    var cards=document.createElement('div');
    cards.style.cssText='display:flex;gap:10px;flex-wrap:wrap;justify-content:center';

    var _odAlready=OD.isReady();
    var users=[
        {uid:'M441819E',name:'Dany Hernandez',ini:'DH',bg:'rgba(245,158,11,.15)',col:'#DC0028'},
        {uid:'M354046Y',name:'Fadoua Khachach',ini:'FK',bg:'rgba(59,130,246,.15)',col:'#3B82F6'},
        {uid:'MA44658D',name:'Silvia Famoso',ini:'SF',bg:'rgba(16,185,129,.15)',col:'#10B981'}
    ];

    users.forEach(function(u){
        var count=S.all.filter(function(a){return(a._uid||a.UID_RACF)===u.uid&&!a._isOpo;}).length;
        var card=document.createElement('button');
        card.style.cssText='background:rgba(255,255,255,.04);border:1.5px solid rgba(255,255,255,.08);border-radius:14px;padding:18px 22px;cursor:pointer;font-family:inherit;display:flex;flex-direction:column;align-items:center;gap:10px;min-width:120px;transition:all .15s;color:inherit';
        card.innerHTML=
            '<div style="width:52px;height:52px;border-radius:14px;background:'+u.bg+';display:grid;place-items:center;font-weight:800;font-size:18px;color:'+u.col+';font-family:Poppins,sans-serif;box-shadow:0 4px 16px '+u.bg+'">'+u.ini+'</div>'+
            '<div style="text-align:center"><div style="font-size:11.5px;font-weight:700;color:#F2F2F8;white-space:nowrap">'+u.name.split(' ')[0]+'</div>'+
            '<div style="font-size:10px;color:#6060A0;margin-top:2px">'+u.name.split(' ').slice(1).join(' ')+'</div>'+
            '<div style="font-size:9px;color:'+u.col+';margin-top:4px;font-weight:600">'+count+' act.</div></div>';
        card.addEventListener('mouseenter',function(){card.style.borderColor=u.col;card.style.background='rgba(255,255,255,.08)';});
        card.addEventListener('mouseleave',function(){card.style.borderColor='rgba(255,255,255,.08)';card.style.background='rgba(255,255,255,.04)';});
        card.addEventListener('click',function(){
            try{
                localStorage.setItem('opticrm_sel_uid',u.uid);
                localStorage.setItem('opticrm_sel_uid_ts',String(Date.now()));
            }catch(e){}
            onSelect(u.uid);
        });
        cards.appendChild(card);
    });
    sel.appendChild(cards);

    var skip=document.createElement('button');
    skip.style.cssText='background:none;border:none;color:#4A4A62;font-size:10.5px;cursor:pointer;font-family:inherit;margin-top:4px';
    skip.textContent='Continuar sense OneDrive →';
    skip.addEventListener('click',function(){onSelect(null);});
    sel.appendChild(skip);

    _lockOv.appendChild(sel);
}
function hideUserSelector(){
    var sel=document.getElementById('lock-user-sel');if(sel)sel.remove();
    var lbl=_lockOv&&_lockOv.querySelector('#opticrm-lock-lbl');
    var barWrap=_lockOv&&_lockOv.querySelector('#opticrm-lock-bar')?.parentElement;
    if(lbl)lbl.style.display='';
    if(barWrap)barWrap.style.display='';
}

// ── TEAM NOTAS card ──────────────────────────────────────────────
function buildTeamNotasCard(entityId, accentColor){
    accentColor = accentColor || '#F59E0B';
    var STORE_KEY = 'tn_' + entityId;

    function loadItems(){
        try{ return JSON.parse(localStorage.getItem(STORE_KEY)||'[]'); }
        catch(e){ return []; }
    }
    function saveItems(arr){
        try{ localStorage.setItem(STORE_KEY, JSON.stringify(arr)); }catch(e){}
    }

    var card = document.createElement('div');
    card.style.cssText = 'border:1px solid var(--br);border-radius:10px;overflow:clip;background:var(--bg2)';

    // Header (col·lapsable)
    var hdr = document.createElement('button');
    hdr.style.cssText = 'width:100%;padding:11px 16px;display:flex;align-items:center;justify-content:space-between;background:rgba(245,158,11,.05);border:none;cursor:pointer;font-family:inherit';
    var _open = false; // Col·lapsat per defecte

    function renderHdr(){
        var items = loadItems();
        var done = items.filter(function(x){return x.done;}).length;
        hdr.innerHTML =
            '<div style="display:flex;align-items:center;gap:8px">' +
            '<span style="font-size:14px">📋</span>' +
            '<div style="text-align:left">' +
            '<div style="font-size:11px;font-weight:700;color:var(--t1)">Team Notas</div>' +
            '<div style="font-size:9.5px;color:var(--t3)">' + done + '/' + items.length + ' completades</div>' +
            '</div></div>' +
            '<span style="font-size:10px;color:' + accentColor + ';font-weight:600">' + (_open ? '▲ Col·lapsar' : '▼ Desplegar') + '</span>';
    }

    var body = document.createElement('div');
    body.style.cssText = 'padding:14px 16px;display:flex;flex-direction:column;gap:8px;overflow:visible';

    function renderBody(){
        body.innerHTML = '';
        var items = loadItems();

        // Llista items locals
        var list = document.createElement('div');
        list.style.cssText = 'display:flex;flex-direction:column;gap:5px';

        items.forEach(function(item, idx){
            var row = document.createElement('div');
            row.style.cssText = 'display:flex;align-items:center;gap:8px;padding:7px 10px;border-radius:7px;background:var(--bg3);border:1px solid var(--br);transition:opacity .15s' + (item.done ? ';opacity:.5' : '');

            // Checkbox
            var chk = document.createElement('button');
            chk.style.cssText = 'flex-shrink:0;width:18px;height:18px;border-radius:5px;border:1.5px solid ' + (item.done ? accentColor : 'var(--brl)') + ';background:' + (item.done ? accentColor : 'transparent') + ';cursor:pointer;display:flex;align-items:center;justify-content:center;font-size:11px;color:#fff;transition:all .12s';
            chk.innerHTML = item.done ? '✓' : '';
            chk.addEventListener('click', function(e){
                e.stopPropagation();
                var arr = loadItems();
                arr[idx].done = !arr[idx].done;
                saveItems(arr);
                renderBody();
                renderHdr();
            });

            // Drag handle
            var dh = document.createElement('span');
            dh.style.cssText = 'flex-shrink:0;cursor:grab;color:var(--t4);font-size:11px;padding:0 2px;user-select:none;opacity:0;transition:opacity .12s';
            dh.innerHTML = '⠿';
            dh.draggable = true;
            dh.addEventListener('dragstart', function(e){
                row.style.opacity='.4';
                e.dataTransfer.setData('tn-idx', String(idx));
                e.dataTransfer.effectAllowed='move';
            });
            dh.addEventListener('dragend', function(){ row.style.opacity='1'; });
            row.addEventListener('dragover', function(e){
                e.preventDefault();e.dataTransfer.dropEffect='move';
                row.style.borderTop='2px solid '+accentColor;
            });
            row.addEventListener('dragleave', function(){ row.style.borderTop=''; });
            row.addEventListener('drop', function(e){
                e.preventDefault();row.style.borderTop='';
                var fromIdx=parseInt(e.dataTransfer.getData('tn-idx'));
                if(isNaN(fromIdx)||fromIdx===idx)return;
                var arr=loadItems();
                var moved=arr.splice(fromIdx,1)[0];
                var toIdx=fromIdx<idx?idx-1:idx;
                arr.splice(toIdx,0,moved);
                saveItems(arr);renderBody();renderHdr();
            });

            // Text — editable amb doble clic
            var txt = document.createElement('span');
            txt.style.cssText = 'flex:1;font-size:12px;color:'+(item.done?'var(--t3)':'var(--t1)')+';line-height:1.4'+(item.done?';text-decoration:line-through':'');
            txt.textContent = item.text;
            txt.title = 'Doble clic per editar';
            txt.addEventListener('dblclick', function(e){
                e.stopPropagation();
                var inp2=document.createElement('input');
                inp2.type='text';inp2.value=item.text;
                inp2.style.cssText='flex:1;font-size:12px;color:var(--t1);background:var(--bg2);border:1px solid '+accentColor+';border-radius:5px;padding:2px 6px;font-family:inherit;outline:none;width:100%';
                txt.replaceWith(inp2);inp2.focus();inp2.select();
                function saveEdit(){
                    var v=inp2.value.trim();
                    if(v){var arr=loadItems();arr[idx].text=v;saveItems(arr);}
                    renderBody();renderHdr();
                }
                inp2.addEventListener('blur',saveEdit);
                inp2.addEventListener('keydown',function(e2){if(e2.key==='Enter'){e2.preventDefault();saveEdit();}if(e2.key==='Escape'){renderBody();}});
            });

            // Eliminar
            var del = document.createElement('button');
            del.style.cssText = 'flex-shrink:0;width:18px;height:18px;border-radius:4px;border:1px solid rgba(239,68,68,.3);background:rgba(239,68,68,.06);color:#EF4444;font-size:11px;cursor:pointer;display:flex;align-items:center;justify-content:center;opacity:0;transition:opacity .12s';
            del.innerHTML = '×';
            del.addEventListener('click', function(e){
                e.stopPropagation();
                var arr = loadItems();
                arr.splice(idx, 1);
                saveItems(arr);
                renderBody();
                renderHdr();
            });
            row.addEventListener('mouseenter', function(){ del.style.opacity='1';dh.style.opacity='1'; });
            row.addEventListener('mouseleave', function(){ del.style.opacity='0';dh.style.opacity='0'; });

            row.appendChild(dh);
            row.appendChild(chk);
            row.appendChild(txt);
            row.appendChild(del);
            list.appendChild(row);
        });
        body.appendChild(list);

        // Fila afegir nova nota
        var addRow = document.createElement('div');
        addRow.style.cssText = 'display:flex;align-items:center;gap:7px;margin-top:3px';
        var inp = document.createElement('input');
        inp.type = 'text';
        inp.placeholder = '+ Afegir nota...';
        inp.style.cssText = 'flex:1;background:var(--bg3);border:1px solid var(--br);border-radius:7px;padding:6px 10px;font-size:12px;color:var(--t1);font-family:inherit;outline:none;transition:border-color .12s';
        inp.addEventListener('focus', function(){ inp.style.borderColor = accentColor; });
        inp.addEventListener('blur', function(){ inp.style.borderColor = 'var(--br)'; });
        var addBtn = document.createElement('button');
        addBtn.style.cssText = 'padding:6px 12px;background:rgba(245,158,11,.12);border:1px solid rgba(245,158,11,.35);border-radius:7px;color:' + accentColor + ';font-size:12px;font-weight:700;cursor:pointer;font-family:inherit;white-space:nowrap';
        addBtn.textContent = '+ Afegir';
        function doAdd(){
            var v = inp.value.trim();
            if(!v)return;
            var arr = loadItems();
            arr.push({text:v, done:false, ts:Date.now()});
            saveItems(arr);
            inp.value = '';
            renderBody();
            renderHdr();
            // Focus de tornada
            setTimeout(function(){ var ni=body.querySelector('input[type=text]'); if(ni)ni.focus(); }, 50);
        }
        inp.addEventListener('keydown', function(e){ if(e.key==='Enter'){e.preventDefault();doAdd();} });
        addBtn.addEventListener('click', function(e){ e.stopPropagation(); doAdd(); });
        addRow.appendChild(inp);
        addRow.appendChild(addBtn);
        body.appendChild(addRow);
    }

    // Col·lapsar/expandir
    hdr.addEventListener('click', function(){
        _open = !_open;
        body.style.display = _open ? 'flex' : 'none';
        body.style.flexDirection = 'column';
        renderHdr();
    });

    renderHdr();
    renderBody();
    body.style.display = 'none'; // Inicia col·lapsat
    card.appendChild(hdr);
    card.appendChild(body);
    return card;
}

function rCRM(){
    // Obre/tanca modal fullscreen
    var prev=SR.getElementById('crm-modal');if(prev){prev.remove();return;}
    var ov=document.createElement('div');
    ov.id='crm-modal';
    ov.style.cssText='position:fixed;inset:0;z-index:2147483646;background:rgba(0,0,0,.6);backdrop-filter:blur(3px);display:flex;align-items:center;justify-content:center';
    var PILLS=[
        {id:'crm',     l:'🏠 CRM Comercial',  u:'https://gestiona.gco.global/gestioncomercialsco'},
        {id:'tarif',   l:'💰 Tarificador',     u:'https://gestiona.gco.global/productos'},
        {id:'altacli', l:'👤 Clients',         u:'https://gestiona.gco.global/gestionadministrativa/gestiondeclientes/gestionclientesoccident'},
        {id:'altaopo', l:'💼 Nova OPO',        u:'https://grupoaplicaciones.gco.global/FE/ISC.Gaan.Oportunidad.FE.DetOportunidad/?_CIA=SCO&OPERATIVA=ALTA'},
        {id:'altaact', l:'📋 Nova Activitat',  u:'https://grupoaplicaciones.gco.global/FE/ISC.Gaan.Actividad.FE.DetalleActividad/?_CIA=SCO&OPERATIVA=ALTA'}
    ];
    var innerBox=document.createElement('div');
    innerBox.style.cssText='width:80vw;height:88vh;background:#0c0c10;border-radius:14px;overflow:hidden;display:flex;flex-direction:column;box-shadow:0 20px 60px rgba(0,0,0,.6);border:1px solid #2C2C38';
    var fr=document.createElement('iframe');
    fr.src=PILLS[2].u; // Defecte: Clients
    fr.style.cssText='flex:1;width:100%;border:none;background:#0c0c10';
    fr.setAttribute('allowfullscreen','');
    var tb=document.createElement('div');
    tb.style.cssText='display:flex;align-items:center;gap:6px;padding:13px 14px;background:#141419;border-bottom:1px solid #2C2C38;flex-shrink:0;flex-wrap:wrap';
    var logo=document.createElement('div');
    logo.style.cssText='width:20px;height:20px;background:#DC0028;border-radius:4px;display:grid;place-items:center;font-size:9px;font-weight:800;color:#fff;flex-shrink:0';
    logo.textContent='O';
    tb.appendChild(logo);
    var _curPill='crm';
    PILLS.forEach(function(p){
        var btn=document.createElement('button');
        var _act=p.id==='altacli'; // Defecte Clients
        btn.style.cssText='padding:3px 9px;border-radius:6px;font-size:11px;font-weight:600;cursor:pointer;font-family:inherit;transition:all .12s;border:1px solid '+(_act?'#DC0028':'#2C2C38')+';background:'+(_act?'rgba(245,158,11,.15)':'transparent')+';color:'+(_act?'#FF7A95':'#B0B0CC');
        btn.textContent=p.l;
        btn.addEventListener('click',function(){
            fr.src=p.u;_curPill=p.id;
            tb.querySelectorAll('button').forEach(function(b){b.style.borderColor='#2C2C38';b.style.background='transparent';b.style.color='#B0B0CC';});
            btn.style.borderColor='#DC0028';btn.style.background='rgba(245,158,11,.15)';btn.style.color='#FF7A95';
        });
        tb.appendChild(btn);
    });
    var closeBtn=document.createElement('button');
    closeBtn.style.cssText='margin-left:auto;padding:7px 12px;border-radius:8px;border:1px solid #2C2C38;background:transparent;color:#8080A0;font-size:16px;font-weight:700;cursor:pointer;font-family:inherit;flex-shrink:0';
    closeBtn.textContent='×';
    closeBtn.addEventListener('click',function(){ov.remove();});
    tb.appendChild(closeBtn);
    innerBox.appendChild(tb);innerBox.appendChild(fr);
    ov.appendChild(innerBox);
    ov.addEventListener('click',function(e){if(e.target===ov)ov.remove();});
    app.appendChild(ov);
}

