    wrap.innerHTML='';
    var iv=document.createElement('div');
    iv.id='inf-view';
    iv.style.cssText='flex:1;min-height:0;display:grid;grid-template-columns:50% 25% 25%;background:var(--bg);overflow:hidden';
    
    // ── COL 1: RESULTATS ─────────────────────────────────────
    var col1=document.createElement('div');
    col1.style.cssText='display:flex;flex-direction:column;min-width:0;overflow:hidden;border-right:1px solid var(--br);background:var(--bg)';
    var col1Hdr=document.createElement('div');
    col1Hdr.id='inf-col1-hdr';
    col1Hdr.style.cssText='flex-shrink:0;padding:10px 14px;background:var(--bg2);border-bottom:1px solid var(--br);display:flex;align-items:center;gap:10px;flex-wrap:wrap;min-height:48px';
    col1.appendChild(col1Hdr);
    var col1Body=document.createElement('div');
