// ── Week card format (optimitzat per columnes estretes) ─────────────────────
// ─── P: Helper data anterior — TIM_INICI < avui (vora vermella) ───
function _isItemAnterior(a){
    if(!a) return false;
    var ini = a.TIM_INICI || '';
    if(!ini || ini.length < 10) return false;
    var p = ini.slice(0,10).split('/');
    if(p.length !== 3) return false;
    var iniMs = new Date(+p[2], +p[1]-1, +p[0]).getTime();
    if(isNaN(iniMs)) return false;
    var avui = new Date(); avui.setHours(0,0,0,0);
    return iniMs < avui.getTime();
}

// ─── L3: Comptador de dies a la dreta dels cards (Setmana/Focus/Producció/Tasques) ───
function _cardDaysHtml(a){
    if(!a) return null;
    var isOpo = a._isOpo || (typeof gT==='function' && gT(a)==='Oportunidad') || false;
    var avui = new Date(); avui.setHours(0,0,0,0);
    var avuiMs = avui.getTime();
    if(isOpo){
        var fi = a.TIM_FI || a.TIMESTI || a.COMEST || '';
        if(!fi) return null;
        var p = String(fi).split('/'); if(p.length!==3) return null;
        var fiMs = new Date(+p[2], +p[1]-1, +p[0]).getTime();
        if(isNaN(fiMs)) return null;
        var d = Math.round((fiMs - avuiMs)/86400000);
        var color, lbl;
        if(d < 0){ color='#525252'; lbl='+'+Math.abs(d)+'d'; }
        else if(d <= 30){ color='#DC0028'; lbl=(d===0?'avui':d+'d'); }
        else if(d <= 45){ color='#F97316'; lbl=d+'d'; }
        else if(d <= 60){ color='#0EA5E9'; lbl=d+'d'; }
        else { color='#525252'; lbl=d+'d'; }
        return {color:color, lbl:lbl, weight:700};
    } else {
        var ini = a.TIM_INICI || '';
        if(!ini) return null;
        var p2 = String(ini).split('/'); if(p2.length!==3) return null;
        var iniMs = new Date(+p2[2], +p2[1]-1, +p2[0]).getTime();
        if(isNaN(iniMs)) return null;
        var d2 = Math.round((avuiMs - iniMs)/86400000);
        var color2, lbl2;
        if(d2 < 0){ color2='#525252'; lbl2='+'+Math.abs(d2)+'d'; }
        else if(d2 === 0){ color2='#0F766E'; lbl2='avui'; }
        else { color2='#DC0028'; lbl2=d2+'d'; }
        return {color:color2, lbl:lbl2, weight:700};
    }
}
function _renderCardDayBadge(a, parentEl){
    if(!parentEl) return;
    var info = _cardDaysHtml(a);
    if(!info) return;
    var b = document.createElement('div');
    b.className = 'card-dcounter';
    b.style.cssText = 'position:absolute;right:6px;top:50%;transform:translateY(-50%);' +
        'display:flex;align-items:center;justify-content:center;' +
        'min-width:38px;padding:0 2px;' +
        'font-size:13px;font-weight:'+info.weight+';color:'+info.color+';' +
        'pointer-events:none;line-height:1;letter-spacing:-.3px;white-space:nowrap';
    b.textContent = info.lbl;
    parentEl.appendChild(b);
}
