// DASHBOARD INLINE (vista 'reunio') — _OAvDash
// Refactor de showDashboard() a vista inline integrada amb _OAv.sv
// ─────────────────────────────────────────────────────────────
var _OAvDash = (function(){
    var _root = null;       // element <div id="dash-root">
    var _content = null;    // element <div id="dash-content">
    // Estat intern (privat)
    var _S = { sortCol:null, sortDir:1, curTab:0, urgOnly:false, onlyOpen:true, rangMode:'avui_atras', sel:{o:null,a:null,m:null,t:null}, openCG:new Set() };
    var _cachedItems = null;
    // Z2.7+Z3.2 — Popover amb 5 opcions de mode temporal (Shadow DOM aware)
    function _showRangModePopover(triggerEl){
        console.log('[rangmode] === OPEN === trigger:', triggerEl);
        // Z5.2: append SEMPRE al document.body (no Shadow DOM) per fugir de
        // problemes de stacking i isolation
        var host = document.body;
        // Treure popover anterior si existeix
        var prev = document.querySelector('.dash-rangmode-pop');
        if(prev){ prev.remove(); console.log('[rangmode] removed prev'); }
        var rect;
        try { rect = triggerEl.getBoundingClientRect(); }
        catch(eR){ console.warn('[rangmode] no rect:', eR); rect = {left:100, bottom:100}; }
        console.log('[rangmode] rect:', rect.left, rect.bottom);
        var pop = document.createElement('div');
        pop.className = 'dash-rangmode-pop';
        pop.style.cssText = [
            'position:fixed',
            'left:'+Math.max(8,rect.left)+'px',
            'top:'+(rect.bottom+4)+'px',
            'background:#fff',
            'border:2px solid #DC0028',
            'border-radius:8px',
            'padding:6px',
            'z-index:2147483647',
            'box-shadow:0 6px 20px rgba(0,0,0,.3)',
            'min-width:240px',
            'font-family:Arial,sans-serif',
            'color:#202020'
        ].join(';');
        var options = [
            {k:'avui',        l:'AVUI',                 sub:'data inici avui'},
            {k:'atrassades',  l:'ATRASSADES',           sub:'data inici abans d\'avui'},
            {k:'avui_atras',  l:'AVUI + ATRASSADES',    sub:'avui i abans'},
            {k:'totes',       l:'TOTES',                sub:'sense filtre'},
            {k:'rang',        l:'SELECCIONAR DATES',    sub:'rang amb calendari'}
        ];
        options.forEach(function(o){
            var isAct = (_S.rangMode===o.k);
            var optDiv = document.createElement('div');
            optDiv.className = 'dash-rmode-opt';
            optDiv.setAttribute('data-mode', o.k);
            optDiv.style.cssText = 'padding:10px 12px;cursor:pointer;border-radius:6px;font-size:13px;'+
                (isAct ? 'background:rgba(220,0,40,.12);color:#DC0028;font-weight:700' : 'background:transparent;color:#414141;font-weight:600');
            optDiv.innerHTML = '<div>'+o.l+'</div><div style="font-size:10px;color:#888;margin-top:2px;font-weight:400">'+o.sub+'</div>';
            optDiv.addEventListener('mouseenter', function(){
                if(_S.rangMode!==o.k) this.style.background='#f3f4f6';
            });
            optDiv.addEventListener('mouseleave', function(){
                if(_S.rangMode!==o.k) this.style.background='transparent';
            });
            optDiv.addEventListener('click', function(ev){
                ev.stopPropagation();
                ev.preventDefault();
                console.log('[rangmode] === SELECTED ===:', o.k);
                if(o.k === 'rang'){
                    _S.rangMode = 'rang';
                    pop.remove();
                    if(typeof _showDateRangePopover === 'function'){
                        _showDateRangePopover(triggerEl);
                    } else { console.warn('[rangmode] _showDateRangePopover not found'); }
                } else {
                    _S.rangMode = o.k;
                    if(o.k !== 'rang' && S.dateRange){
                        S.dateRange = {from:'', to:''};
                    }
                    pop.remove();
                    _invalidateCache();
                    if(typeof applyF === 'function') applyF();
                    else _renderBody();
                }
            });
            pop.appendChild(optDiv);
        });
        document.body.appendChild(pop);
        console.log('[rangmode] popover appended to body, BCR:', pop.getBoundingClientRect());
        // Close on outside click amb composedPath per Shadow DOM
        setTimeout(function(){
            function _onDoc(e){
                var path = e.composedPath ? e.composedPath() : [e.target];
                if(path.indexOf(pop) === -1){
                    console.log('[rangmode] close (outside click)');
                    pop.remove();
                    document.removeEventListener('click', _onDoc, true);
                    if(typeof SR!=='undefined' && SR) SR.removeEventListener('click', _onDoc, true);
                }
            }
            document.addEventListener('click', _onDoc, true);
            try{ if(typeof SR!=='undefined' && SR) SR.addEventListener('click', _onDoc, true); }catch(eS){}
        }, 100);
    }
    // Z6.1: Exposar a window per al fallback onclick inline
    try { window._showRangModePopover = _showRangModePopover; } catch(eWin){}


    // Z2.2 — Helper filtre temporal centralitzat
    function _passesRangMode(x){
        var mode = _S.rangMode || 'avui_atras';
        if(mode === 'totes') return true;
        var dRaw = (x.dataInici || '').slice(0,10);
        if(!dRaw) return false;
        var dp = dRaw.split('/');
        if(dp.length !== 3) return false;
        var iso = dp[2] + '-' + dp[1] + '-' + dp[0];
        var t = new Date(); t.setHours(0,0,0,0);
        var todayIso = t.getFullYear()+'-'+String(t.getMonth()+1).padStart(2,'0')+'-'+String(t.getDate()).padStart(2,'0');
        if(mode === 'avui')        return iso === todayIso;
        if(mode === 'atrassades')  return iso <  todayIso;
        if(mode === 'avui_atras')  return iso <= todayIso;
        if(mode === 'rang'){
            var fr = (S.dateRange && S.dateRange.from) || '';
            var to = (S.dateRange && S.dateRange.to) || '';
            if(fr && iso < fr) return false;
            if(to && iso > to) return false;
            return true;
        }
        return true;
    }
    // Z4.1 — Helper centralitzat per al filtre d'usuari per defecte
    // Regla única:
    //   - Si NO hi ha cap usuari seleccionat → mostra només _activeUid (usuari connectat)
    //   - Si selecció inclou 'all' → mostra tots
    //   - Else → mostra els usuaris seleccionats
    // PP.2 — Popover per seleccionar Tipus Acció OPO (TOTES + 6 opcions)
    function _showOpoTipoPopover(triggerEl){
        var rect = triggerEl.getBoundingClientRect();
        var pop = document.createElement('div');
        pop.style.cssText = 'position:fixed;left:'+Math.max(8,rect.left)+'px;top:'+(rect.bottom+4)+'px;background:#fff;border:2px solid #DC0028;border-radius:8px;padding:6px;z-index:2147483647;box-shadow:0 6px 20px rgba(0,0,0,.3);min-width:210px;font-family:Arial,sans-serif;color:#202020';
        function _mkOpt(label, emoji, key){
            var isAct = (_S.sel.opoTipo === key);
            var d = document.createElement('div');
            d.style.cssText = 'padding:8px 12px;cursor:pointer;border-radius:6px;font-size:13px;display:flex;align-items:center;gap:10px;' + (isAct?'background:rgba(220,0,40,.12);color:#DC0028;font-weight:700':'background:transparent;color:#414141;font-weight:600');
            d.innerHTML = '<span style="font-size:18px;width:22px;text-align:center">'+emoji+'</span><span>'+label+'</span>';
            d.addEventListener('mouseenter', function(){ if(!isAct) this.style.background = '#f3f4f6'; });
            d.addEventListener('mouseleave', function(){ if(!isAct) this.style.background = 'transparent'; });
            d.addEventListener('click', function(ev){
                ev.stopPropagation(); ev.preventDefault();
                _S.sel.opoTipo = key;
                pop.remove();
                if(typeof _renderBody === 'function') _renderBody();
            });
            return d;
        }
        pop.appendChild(_mkOpt('TOTES (sense filtre)', '🎯', null));
        var sep = document.createElement('div');
        sep.style.cssText = 'height:1px;background:#e5e7eb;margin:4px 6px';
        pop.appendChild(sep);
        OPO_TIPO_OPTS.forEach(function(o){ pop.appendChild(_mkOpt(o.l, o.e, o.k)); });
        document.body.appendChild(pop);
        setTimeout(function(){
            function _onDoc(e){
                var path = e.composedPath ? e.composedPath() : [e.target];
                if(path.indexOf(pop) === -1){
                    pop.remove();
                    document.removeEventListener('click', _onDoc, true);
                    try{ if(typeof SR !== 'undefined' && SR) SR.removeEventListener('click', _onDoc, true); }catch(_e){}
                }
            }
            document.addEventListener('click', _onDoc, true);
            try{ if(typeof SR !== 'undefined' && SR) SR.addEventListener('click', _onDoc, true); }catch(_e){}
        }, 100);
    }
    function _passesUserFilter(x){
        if(!_S.sel.m || _S.sel.m.size === 0) return x.uid === _activeUid;
        if(_S.sel.m.has('all')) return true;
        return _S.sel.m.has(x.uid);
    }
    function _rangModeLabel(){
        var m = _S.rangMode || 'avui_atras';
        if(m==='avui') return 'AVUI';
        if(m==='atrassades') return 'ATRASSADES';
        if(m==='avui_atras') return 'AVUI + ATRASSADES';
        if(m==='totes') return 'TOTES';
        if(m==='rang') return 'SELECCIONAR DATES';
        return 'AVUI + ATRASSADES';
    }
    function _initSel(){ _S.sel={o:new Set(),a:new Set(),m:new Set(),t:new Set(),opoTipo:null}; }
    _initSel();

    var KB_MAP = {'ganada':'Ganada','perdida':'Perdida','anyo':'Año Próx.','espera':'En Espera','analisis':'En Anàlisi','tarifa':'Tarificació','docu':'Pdte. Docu','presentar':'Presentar','respuesta':'Pdte. Resp. Client','resp_cond':'Pdte. Resp. Cond.','emitir':'Per Emetre','cierre':'Cierre/Revisió','completada':'Completada','pendent':'Pendents','avui':'Avui','setmana':'Setmana','mes':'Mes','fent':'En Curs','esperant':'Esperant','altres':'Altres','urgent':'Urgents'};

    function _esc(s){return(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}

    function _buildItems(){
        var avui=new Date();avui.setHours(0,0,0,0);
        var avuiMs=avui.getTime();
        return S.all.map(function(a){
            var uid = a._uid||a.UID_RACF||'M441819E';
            var isOpo = !!a._isOpo;
            var kbKey = isOpo ? localStorage.getItem('kb_'+a.IDOPOACT) : localStorage.getItem('tc_col_'+a.IDACTIV);
            var urgKey = isOpo ? localStorage.getItem('urg_opo_'+a.IDOPOACT) : localStorage.getItem('urg_act_'+a.IDACTIV);
            var st = (a.INDSITU_DESC||'').trim();
            var estat = st.indexOf('Completad')>=0?'co':st.indexOf('Cancelad')>=0?'ca':'ab';
            var tipus = isOpo ? 'Oportunidad' : (function(){var d=(a.INDACTI_DESC||'').trim();if(d.indexOf('Llamada')>=0)return'Llamada';if(d.indexOf('Cita')>=0)return'Cita';if(d.indexOf('Visita')>=0)return'Visita';if(d.indexOf('WhatsApp')>=0||d.indexOf('Whats')>=0)return'WhatsApp';if(d.indexOf('Propens')>=0)return'Propensión';if(d.indexOf('Correo')>=0)return'Correo';return'Tarea';})();
            // Pre-calcular dataIniciMs (timestamp) per accelerar filtres temporals
            var dataIniciMs = null;
            if(a.TIM_INICI){var pi=a.TIM_INICI.split('/');if(pi.length===3){dataIniciMs=new Date(+pi[2],+pi[1]-1,+pi[0]).getTime();}}
            var diesCierre = null;
            if(isOpo && a.TIM_FI){var pp=a.TIM_FI.split('/');if(pp.length===3){var fi=new Date(parseInt(pp[2]),parseInt(pp[1])-1,parseInt(pp[0]));diesCierre=Math.round((fi.getTime()-avuiMs)/86400000);}}
            // NN.9 — Pre-calcular emoji Tipus Acció OPO
            var opoTipoEmoji = '';
            if(isOpo){
                var _otKey = localStorage.getItem('opo_tipo_'+a.IDOPOACT);
                if(_otKey){
                    for(var _oi=0;_oi<OPO_TIPO_OPTS.length;_oi++){
                        if(OPO_TIPO_OPTS[_oi].k===_otKey){ opoTipoEmoji=OPO_TIPO_OPTS[_oi].e; break; }
                    }
                }
            }
            return {id:isOpo?a.IDOPOACT:a.IDACTIV, isOpo:isOpo, asunto:a.DESASUN||'', client:a.CLIENTE||'', uid:uid, uName:(USERS[uid]||{}).name||uid, uIni:(USERS[uid]||{}).ini||'?', uColor:(USERS[uid]||{}).color||'#888', uBg:(USERS[uid]||{}).bg||'#333', estat:estat, tipus:tipus, kb:kbKey||'', kbLabel:KB_MAP[kbKey]||kbKey||'—', urgent:!!urgKey, dataInici:a.TIM_INICI||'', dataIniciMs:dataIniciMs, dataCierre:isOpo?(a.TIM_FI||''):'', diesCierre:diesCierre, opoTipoEmoji:opoTipoEmoji};
        });
    }
    function _getItems(){
        // Cache: només reconstruir quan _cachedItems és null
        if(_cachedItems===null) _cachedItems = _buildItems();
        return _cachedItems;
    }
    function _invalidateCache(){ _cachedItems = null; }

    function _getFiltered(items){
        var fmed = _root.querySelector('#dash-f-med');
        var fkb = _root.querySelector('#dash-f-kb');
        var ftp = _root.querySelector('#dash-f-tipus');
        var fsr = _root.querySelector('#dash-f-srch');
        var med = fmed?fmed.value:'';
        var kb = fkb?fkb.value:'';
        var tp = ftp?ftp.value:'';
        var sq = (fsr?fsr.value:'').toLowerCase();
        return items.filter(function(x){
            if(med&&x.uid!==med)return false;
            if(kb&&x.kb!==kb)return false;
            if(tp&&x.tipus!==tp)return false;
            if(_S.urgOnly&&!x.urgent)return false;
            if(_S.onlyOpen){ if(x.estat!=='ab') return false; } else { if(x.estat!=='co') return false; }
            if(sq&&(x.asunto+x.client+x.tipus).toLowerCase().indexOf(sq)<0)return false;
            // Z2.3: Filtre temporal via _passesRangMode
            if(!_passesRangMode(x)) return false;
            // PP.1 — Filtre per Tipus Acció OPO (només afecta OPOs)
            if(x.isOpo && _S.sel.opoTipo){
                var _targetE = null;
                for(var _oti=0;_oti<OPO_TIPO_OPTS.length;_oti++){ if(OPO_TIPO_OPTS[_oti].k===_S.sel.opoTipo){ _targetE=OPO_TIPO_OPTS[_oti].e; break; } }
                if(_targetE && x.opoTipoEmoji !== _targetE) return false;
            }
            return true;
        });
    }

    function _estatBadge(e){var l={ab:'Abierta',co:'Completada',ca:'Cancelada'};return '<span class="dash-badge '+e+'">'+l[e]+'</span>';}
    function _urgBadge(u, isOpo){return u?'<span class="dash-badge urg">🚨</span>':('<span style="font-size:13px" title="'+(isOpo?'Oportunitat':'Activitat')+'">'+(isOpo?'💼':'📋')+'</span>');}
    function _iniHtml(x){return '<span class="dash-ini" style="background:'+x.uBg+';color:'+x.uColor+'">'+_esc(x.uIni)+'</span>';}
    function _kbHtml(x){var c=x.kb;var cls=c==='ganada'?'ganada':c==='perdida'?'perdida':c==='anyo'?'anyo':'';return x.kbLabel?'<span class="dash-kbtag '+cls+'">'+_esc(x.kbLabel)+'</span>':'';}
    function _diasHtml(d){
        // Gradació OPO (dies fins cierre): <0 vencut, ≤30 vermell, ≤45 taronja, ≤60 blau, >60 gris
        if(d===null||d===undefined)return '';
        var cls;
        if(d<0) cls='dash-dias-past';
        else if(d<=30) cls='dash-dias-red';
        else if(d<=45) cls='dash-dias-orange';
        else if(d<=60) cls='dash-dias-blue';
        else cls='dash-dias-gray';
        var lbl=d<0?'('+Math.abs(d)+'d passats)':d===0?'avui':d+'d';
        return '<span class="dash-dias-num '+cls+'">'+lbl+'</span>';
    }
    function _diasCreaHtml(dataIniciMs, avuiMs){
        // Gradació ACT (dies des de creació): <0 gris (futur), ==0 verd (avui), >0 vermell (vencut)
        if(!dataIniciMs)return '';
        var d = Math.round((avuiMs - dataIniciMs)/86400000);
        var cls, lbl;
        if(d<0){ cls='dash-dias-gray'; lbl='+'+Math.abs(d)+'d'; }
        else if(d===0){ cls='dash-dias-green'; lbl='avui'; }
        else { cls='dash-dias-red'; lbl=d+'d'; }
        return '<span class="dash-dias-num '+cls+'">'+lbl+'</span>';
    }
    function _sortArr(arr,col){
        if(!col)return arr;
        return arr.slice().sort(function(a,b){
            var va=a[col]||'',vb=b[col]||'';
            if(typeof va==='number'&&typeof vb==='number')return _S.sortDir*(va-vb);
            return _S.sortDir*(String(va).localeCompare(String(vb)));
        });
    }
    function _th(label,col){var cls=_S.sortCol===col?(_S.sortDir===1?'sort-asc':'sort-desc'):'';return '<th class="'+cls+'" data-col="'+col+'">'+label+'</th>';}

    function _renderKpisAct(filActs){
        // Y5.1: 3 cards específiques (Pendents avui, Urgents avui, Completades mes)
        var avui = new Date(); avui.setHours(0,0,0,0);
        var avuiMs = avui.getTime();
        var y = avui.getFullYear(), mo = avui.getMonth();
        var mesIni  = new Date(y, mo,   1, 0,0,0).getTime();
        var mesFi   = new Date(y, mo+1, 0, 23,59,59).getTime();
        // filActs ja ve filtrat per usuari/data. Per al comptador d'aquest pestanya
        // ens quedem amb el subset que prov de _getFiltered → ve filtrat per Fins avui/Rang.
        var actPend = filActs.filter(function(x){return x.estat==='ab' && x.dataIniciMs && x.dataIniciMs<=avuiMs;}).length;
        var actUrg  = filActs.filter(function(x){return x.estat==='ab' && x.urgent && x.dataIniciMs && x.dataIniciMs<=avuiMs;}).length;
        var actComp = filActs.filter(function(x){return x.estat==='co' && x.dataIniciMs && x.dataIniciMs>=mesIni && x.dataIniciMs<=mesFi;}).length;
        return '<div class="dash-kpi-row dash-kpi-row-3">'+
            '<div class="dash-kpi k-act"><div class="dash-kpi-num">'+actPend+'</div><div class="dash-kpi-lbl">📋 ACT Pendents</div><div class="dash-kpi-sub">avui o anterior</div></div>'+
            '<div class="dash-kpi k-red"><div class="dash-kpi-num">'+actUrg+'</div><div class="dash-kpi-lbl">🚨 ACT Urgents</div><div class="dash-kpi-sub">avui o anterior</div></div>'+
            '<div class="dash-kpi k-ok"><div class="dash-kpi-num">'+actComp+'</div><div class="dash-kpi-lbl">✅ ACT Completades</div><div class="dash-kpi-sub">aquest mes</div></div>'+
        '</div>';
    }
    function _renderKpisOpo(fil){
        // Y4.1 — Cards específiques per pestanya Oportunitats (només OPO, 4 cards)
        var avui = new Date(); avui.setHours(0,0,0,0);
        var y = avui.getFullYear(), mo = avui.getMonth();
        var mesIni  = new Date(y, mo,   1, 0,0,0).getTime();
        var mesFi   = new Date(y, mo+1, 0, 23,59,59).getTime();
        var mes1Ini = new Date(y, mo+1, 1, 0,0,0).getTime();
        var mes1Fi  = new Date(y, mo+2, 0, 23,59,59).getTime();
        var mes2Ini = new Date(y, mo+2, 1, 0,0,0).getTime();
        var mes2Fi  = new Date(y, mo+3, 0, 23,59,59).getTime();
        function _toMs(s){
            if(!s) return 0;
            var p = String(s).slice(0,10).split('/');
            if(p.length!==3) return 0;
            return new Date(+p[2], +p[1]-1, +p[0]).getTime();
        }
        var opos = fil.filter(function(x){return x.isOpo;});
        var opoMes  = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mesIni  && ms<=mesFi; }).length;
        var opoMes1 = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mes1Ini && ms<=mes1Fi;}).length;
        var opoMes2 = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mes2Ini && ms<=mes2Fi;}).length;
        var opoUrg  = opos.filter(function(x){return x.estat==='ab' && x.urgent;}).length;
        return '<div class="dash-kpi-row dash-kpi-row-4">'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes+'</div><div class="dash-kpi-lbl">💼 Cierre Mes</div><div class="dash-kpi-sub">en curs</div></div>'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes1+'</div><div class="dash-kpi-lbl">💼 Cierre Mes+1</div><div class="dash-kpi-sub">següent</div></div>'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes2+'</div><div class="dash-kpi-lbl">💼 Cierre Mes+2</div><div class="dash-kpi-sub">2 mesos</div></div>'+
            '<div class="dash-kpi k-red"><div class="dash-kpi-num">'+opoUrg+'</div><div class="dash-kpi-lbl">🚨 OPOs Urgents</div></div>'+
        '</div>';
    }

    function _renderKpis(fil){
        // Y3.1 — Cards específiques per Resum
        var avui = new Date(); avui.setHours(0,0,0,0);
        var avuiMs = avui.getTime();
        var y = avui.getFullYear(), mo = avui.getMonth();
        var mesIni  = new Date(y, mo,   1, 0,0,0).getTime();
        var mesFi   = new Date(y, mo+1, 0, 23,59,59).getTime();
        var mes1Ini = new Date(y, mo+1, 1, 0,0,0).getTime();
        var mes1Fi  = new Date(y, mo+2, 0, 23,59,59).getTime();
        var mes2Ini = new Date(y, mo+2, 1, 0,0,0).getTime();
        var mes2Fi  = new Date(y, mo+3, 0, 23,59,59).getTime();
        function _toMs(s){
            if(!s) return 0;
            var p = String(s).slice(0,10).split('/');
            if(p.length!==3) return 0;
            return new Date(+p[2], +p[1]-1, +p[0]).getTime();
        }
        var opos = fil.filter(function(x){return x.isOpo;});
        var acts = fil.filter(function(x){return !x.isOpo;});
        // OPOs cierre per mes (només obertes)
        var opoMes  = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mesIni  && ms<=mesFi; }).length;
        var opoMes1 = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mes1Ini && ms<=mes1Fi;}).length;
        var opoMes2 = opos.filter(function(x){if(x.estat!=='ab')return false;var ms=_toMs(x.dataCierre);return ms>=mes2Ini && ms<=mes2Fi;}).length;
        var opoUrg  = opos.filter(function(x){return x.estat==='ab' && x.urgent;}).length;
        // PP.3 — Card "🎯 ACCIÓ" amb popover (Resum + Mediador). Substitueix la versió OO.3/OO.4.
        var _sopt = _S.sel.opoTipo;
        var _soptOpt = null;
        if(_sopt){ for(var _spi=0;_spi<OPO_TIPO_OPTS.length;_spi++){ if(OPO_TIPO_OPTS[_spi].k===_sopt){ _soptOpt=OPO_TIPO_OPTS[_spi]; break; } } }
        var _opoTipoCardHtml =
            '<div class="dash-kpi dash-kpi-opotipos'+(_sopt?' sel':'')+'" data-t="opotipo" data-k="opotipo" style="cursor:pointer;border:'+(_sopt?'2px solid #DC0028':'1px dashed var(--br)')+';background:'+(_sopt?'#fff':'var(--bg2)')+'">'+
            (_soptOpt
                ? '<div class="dash-kpi-num" style="color:#DC0028;font-size:24px">'+_soptOpt.e+'</div><div class="dash-kpi-lbl" style="color:#DC0028;font-weight:700">'+_soptOpt.l+'</div><div class="dash-kpi-sub" style="color:#DC0028">filtre actiu</div>'
                : '<div class="dash-kpi-num" style="font-size:24px">🎯</div><div class="dash-kpi-lbl">ACCIÓ</div><div class="dash-kpi-sub">filtra per tipus</div>'
            )+'</div>';
        // ACTs
        var actPend = acts.filter(function(x){return x.estat==='ab' && x.dataIniciMs && x.dataIniciMs<=avuiMs;}).length;
        var actUrg  = acts.filter(function(x){return x.estat==='ab' && x.urgent && x.dataIniciMs && x.dataIniciMs<=avuiMs;}).length;
        var actComp = acts.filter(function(x){return x.estat==='co' && x.dataIniciMs && x.dataIniciMs>=mesIni && x.dataIniciMs<=mesFi;}).length;
        var _rmLblK = _rangModeLabel();
        return '<div class="dash-kpi-row dash-kpi-row-9">'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes+'</div><div class="dash-kpi-lbl">💼 Cierre Mes</div><div class="dash-kpi-sub">en curs</div></div>'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes1+'</div><div class="dash-kpi-lbl">💼 Cierre Mes+1</div><div class="dash-kpi-sub">següent</div></div>'+
            '<div class="dash-kpi k-opo"><div class="dash-kpi-num">'+opoMes2+'</div><div class="dash-kpi-lbl">💼 Cierre Mes+2</div><div class="dash-kpi-sub">2 mesos</div></div>'+
            '<div class="dash-kpi k-red"><div class="dash-kpi-num">'+opoUrg+'</div><div class="dash-kpi-lbl">🚨 OPOs Urgents</div></div>'+
            _opoTipoCardHtml + /* OO.3+OO.4 — Card Tipus OPO entre OPOs Urgents i Rang */
            // Z2.8: Card Rang gran al mig (entre OPOs Urgents i ACT Pendents)
            '<div class="dash-kpi dash-kpi-rang" data-t="rang" data-k="rang" style="cursor:pointer;border:2px solid #DC0028;background:#fff"><div class="dash-kpi-num" style="color:#DC0028;font-size:28px">📆</div><div class="dash-kpi-lbl" style="color:#DC0028;font-weight:700">RANG</div><div class="dash-kpi-sub" style="color:#DC0028">'+_rmLblK+'</div></div>'+
            '<div class="dash-kpi k-act"><div class="dash-kpi-num">'+actPend+'</div><div class="dash-kpi-lbl">📋 ACT Pendents</div><div class="dash-kpi-sub">avui o anterior</div></div>'+
            '<div class="dash-kpi k-red"><div class="dash-kpi-num">'+actUrg+'</div><div class="dash-kpi-lbl">🚨 ACT Urgents</div><div class="dash-kpi-sub">avui o anterior</div></div>'+
            '<div class="dash-kpi k-ok"><div class="dash-kpi-num">'+actComp+'</div><div class="dash-kpi-lbl">✅ ACT Completades</div><div class="dash-kpi-sub">aquest mes</div></div>'+
        '</div>';
    }

    function _renderCG(cgid, title, count, color, body, opened, sizeKey){
        // Render col·lapsable group (pill amb cos)
        var sizeClass = sizeKey==='small' ? ' dash-cg-sm' : '';
        return '<div class="dash-cg'+sizeClass+'" data-cgid="'+cgid+'">'+
            '<div class="dash-cg-h" data-cg="'+cgid+'" style="border-left:3px solid '+color+'">'+
                '<span class="dash-cg-arrow">'+(opened?'▼':'▶')+'</span>'+
                '<span class="dash-cg-title">'+title+'</span>'+
                '<span class="dash-cg-count">'+count+'</span>'+
            '</div>'+
            '<div class="dash-cg-b" style="display:'+(opened?'block':'none')+'">'+body+'</div>'+
        '</div>';
    }

    function _renderItemsTable(items, isOpo){
        // Reusable items table — un només per grup col·lapsable
        var sortedItems = _sortArr(items, _S.sortCol);
        // F3: timestamp d'avui per detectar items amb data anterior
        var _today_F3 = new Date(); _today_F3.setHours(0,0,0,0);
        var avuiMs_F3 = _today_F3.getTime();
        var th='';
        if(isOpo){
            // NN.9 — Nova columna Tipus després d'Estat
            th=_th('','urgent')+_th('Asunto','asunto')+_th('Client','client')+_th('Mediador','uName')+_th('Etapa','kbLabel')+_th('Inici','dataInici')+_th('Cierre','dataCierre')+_th('Dies','diesCierre')+_th('Estat','estat')+_th('Tipus','opoTipoEmoji');
        } else {
            th=_th('','urgent')+_th('Asunto','asunto')+_th('Client','client')+_th('Tipus','tipus')+_th('Mediador','uName')+_th('Kanban','kbLabel')+_th('Data','dataInici')+_th('Dies','diesCreacio')+_th('Estat','estat');
        }
        var rows = sortedItems.map(function(x){
            if(isOpo){
                var _antOpo = (x.dataIniciMs && x.dataIniciMs < avuiMs_F3) ? ' dash-anterior' : '';
                var _urgOpo = x.urgent ? ' dash-urgent' : '';
                var _drgO = (_S.curTab>=1) ? ' draggable="true"' : '';
                return '<tr'+_drgO+' data-id="'+x.id+'" data-isopo="1" data-uid="'+x.uid+'" data-kb="'+_esc(x.kb)+'" class="'+(_antOpo+_urgOpo).trim()+'">'+
                    '<td style="width:24px;padding:2px 0;text-align:center">'+_urgBadge(x.urgent, true)+'</td>'+
                    '<td style="max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-weight:600">'+_esc(x.asunto)+'</td>'+
                    '<td style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--t2)">'+_esc(x.client)+'</td>'+
                    '<td class="dash-medcell" data-id="'+x.id+'" data-uid="'+x.uid+'"><div style="display:flex;align-items:center;gap:5px">'+_iniHtml(x)+'<span style="font-size:10.5px">'+_esc(x.uIni)+'</span></div></td>'+
                    '<td class="dash-kbcell" data-id="'+x.id+'" data-kb="'+_esc(x.kb)+'">'+_kbHtml(x)+'</td>'+
                    '<td style="color:var(--t3);font-size:10.5px;white-space:nowrap">'+_esc(x.dataInici)+'</td>'+
                    '<td style="color:var(--t3);font-size:10.5px;white-space:nowrap">'+_esc(x.dataCierre)+'</td>'+
                    '<td style="white-space:nowrap">'+_diasHtml(x.diesCierre)+'</td>'+
                    '<td>'+_estatBadge(x.estat)+'</td>'+
                    /* NN.9 — Cel·la emoji Tipus després d'Estat */
                    '<td style="width:30px;text-align:center;font-size:14px;line-height:1" title="Tipus Acció">'+(x.opoTipoEmoji||'')+'</td>'+
                '</tr>';
            } else {
                var _antAct = (x.dataIniciMs && x.dataIniciMs < avuiMs_F3) ? ' dash-anterior' : '';
                var _urgAct = x.urgent ? ' dash-urgent' : '';
                var _drgA = (_S.curTab>=1) ? ' draggable="true"' : '';
                return '<tr'+_drgA+' data-id="'+x.id+'" data-isopo="0" data-uid="'+x.uid+'" data-kb="'+_esc(x.kb)+'" class="'+(_antAct+_urgAct).trim()+'">'+
                    '<td style="width:24px;padding:2px 0;text-align:center">'+_urgBadge(x.urgent, false)+'</td>'+
                    '<td style="max-width:220px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-weight:600">'+_esc(x.asunto)+'</td>'+
                    '<td style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;color:var(--t2)">'+_esc(x.client)+'</td>'+
                    '<td style="white-space:nowrap;color:var(--t2);font-size:11px">'+_esc(x.tipus)+'</td>'+
                    '<td class="dash-medcell" data-id="'+x.id+'" data-uid="'+x.uid+'"><div style="display:flex;align-items:center;gap:5px">'+_iniHtml(x)+'<span style="font-size:10.5px">'+_esc(x.uIni)+'</span></div></td>'+
                    '<td class="dash-kbcell" data-id="'+x.id+'" data-kb="'+_esc(x.kb)+'">'+_kbHtml(x)+'</td>'+
                    '<td style="color:var(--t3);font-size:10.5px;white-space:nowrap">'+_esc(x.dataInici)+'</td>'+
                    '<td style="white-space:nowrap">'+_diasCreaHtml(x.dataIniciMs, avuiMs_F3)+'</td>'+
                    '<td>'+_estatBadge(x.estat)+'</td>'+
                '</tr>';
            }
        }).join('');
        return '<table><thead><tr>'+th+'</tr></thead><tbody>'+rows+'</tbody></table>';
    }

    function _renderResum(fil, allItems){
        var h='';
        var OSTG=[{k:'espera',l:'En Espera',c:'#64748B'},{k:'analisis',l:'En Analisi',c:'#3B82F6'},{k:'tarifa',l:'Tarificacio',c:'#0EA5E9'},{k:'docu',l:'Pdte. Docu',c:'#6366F1'},{k:'presentar',l:'Presentar',c:'#8B5CF6'},{k:'respuesta',l:'Resp.Client',c:'#A855F7'},{k:'resp_cond',l:'Resp.Cond.',c:'#EC4899'},{k:'emitir',l:'Per Emetre',c:'#F59E0B'},{k:'cierre',l:'Cierre',c:'#F97316'},{k:'ganada',l:'Ganada',c:'#10B981'},{k:'anyo',l:'Any Prox.',c:'#8B5CF6'},{k:'perdida',l:'Perduda',c:'#EF4444'},{k:'completada',l:'Completada',c:'#6EE7B7'},{k:'cancelada',l:'Cancel.lada',c:'#FCA5A5'}];
        var ATYP=[{k:'Tarea',l:'Tarea',e:'📋'},{k:'Llamada',l:'Llamada',e:'📞'},{k:'Cita',l:'Cita',e:'📅'},{k:'Visita',l:'Visita',e:'🤝'},{k:'WhatsApp',l:'WhatsApp',e:'💬'},{k:'Correo',l:'Correo',e:'✉'},{k:'Propen',l:'Propensio',e:'🎯'}];
        function cO(s){return fil.filter(function(x){if(!x.isOpo)return false;if(s==='completada')return x.estat==='co';if(s==='cancelada')return x.estat==='ca';return x.estat==='ab'&&x.kb===s;}).length;}
        function cA(t){return fil.filter(function(x){return !x.isOpo&&x.tipus.indexOf(t)===0;}).length;}
        function cM(u){return u==='all'?fil.length:fil.filter(function(x){return x.uid===u;}).length;}
        function cT(t){if(t==='any')return fil.length;var n=new Date();n.setHours(0,0,0,0);return fil.filter(function(x){if(!x.dataInici)return false;var p=x.dataInici.split('/');if(p.length!==3)return false;var d=new Date(+p[2],+p[1]-1,+p[0]);var df=Math.round((d-n)/86400000);return t==='venc'?df<0:t==='dia'?df===0:t==='set'?df>=-6&&df<=0:t==='mes'?df>=-30&&df<=0:t==='2m'?df>=-60&&df<=0:df>=-90&&df<=0;}).length;}
        // Z — Fila 1: Usuari → OPOs per etapa
        h+='<div class="dash-frt">👥 Usuari &nbsp;|&nbsp; 💼 OPOs per etapa</div><div class="dash-frow2b">';
        // 1. Usuaris (esquerra)
        var selAllZ=_S.sel.m.has('all')?' sel':'';
        h+='<div class="dash-fc'+selAllZ+'" data-t="med" data-k="all" style="border-top:3px solid #F59E0B"><div class="dash-fcn" style="color:#F59E0B">'+cM('all')+'</div><div class="dash-fcl">TOTS</div></div>';
        UIDS.forEach(function(uid){var u=USERS[uid];if(!u)return;var c=cM(uid);var s=_S.sel.m.has(uid)?' sel':'';h+='<div class="dash-fc'+s+'" data-t="med" data-k="'+uid+'" style="border-top:3px solid '+u.color+'"><div class="dash-fcn" style="color:'+u.color+'">'+c+'</div><div class="dash-fcl"><b style="background:'+u.bg+';color:'+u.color+';padding:0 3px;border-radius:3px">'+u.ini+'</b> '+_esc(u.name.split(' ')[0])+'</div></div>';});
        h+='<div class="dash-fsep"></div>';
        // 2. Etapes OPO (dreta)
        OSTG.forEach(function(s){var c=cO(s.k);var sel=_S.sel.o.has(s.k)?' sel':'';h+='<div class="dash-fc'+sel+'" data-t="opo" data-k="'+s.k+'" style="border-top:3px solid '+s.c+'"><div class="dash-fcn" style="color:'+s.c+'">'+c+'</div><div class="dash-fcl">'+_esc(s.l)+'</div></div>';});
        h+='</div>';
        // Z — Fila 2: Període → Rang → Tipus ACT
        h+='<div class="dash-frt">📅 Període &nbsp;|&nbsp; 📋 Tipus ACT</div><div class="dash-frow2b">';
        // 1. Període (esquerra)
        [{k:'venc',l:'Vençudes'},{k:'dia',l:'Avui'},{k:'set',l:'Setmana'},{k:'mes',l:'Mes'},{k:'2m',l:'2 mesos'},{k:'3m',l:'3 mesos'},{k:'any',l:'Qualsevol'}].forEach(function(t){var c=cT(t.k);var sel=_S.sel.t.has(t.k)?' sel':'';h+='<div class="dash-fc'+sel+'" data-t="time" data-k="'+t.k+'" style="border-top:3px solid #0EA5E9"><div class="dash-fcn" style="color:#0EA5E9">'+c+'</div><div class="dash-fcl">'+t.l+'</div></div>';});
        h+='<div class="dash-fsep"></div>';
        // 2. Tipus ACT (dreta)
        ATYP.forEach(function(t){var c=cA(t.k);var sel=_S.sel.a.has(t.k)?' sel':'';h+='<div class="dash-fc'+sel+'" data-t="act" data-k="'+t.k+'" style="border-top:3px solid #3B82F6"><div class="dash-fcn" style="color:#3B82F6">'+c+'</div><div class="dash-fcl">'+t.e+' '+t.l+'</div></div>';});
        h+='</div>';
        h+='<div id="dash-ir" style="margin-top:10px;flex:1;overflow-y:auto;min-height:120px"><div style="color:var(--t4);font-size:12px;padding:20px;text-align:center">Clica una o mes cards per filtrar</div></div>';
        return h;
    }

    function _renderOpos(fil){
        // Y4.3+4+5: Reescriptura amb usuaris a l'inici, CARD Rang i agrupació multi-user
        var n=new Date();n.setHours(0,0,0,0);
        var avuiMs=n.getTime();
        // Z2.3: usar _passesRangMode (no doblar filtre)
        var dateFiltered = fil.filter(function(x){return x.isOpo;});
        var hO=_S.sel.o.size>0, hT=_S.sel.t.size>0;
        function _chkTime(x){if(_S.sel.t.has('any'))return true;if(!x.dataIniciMs)return false;var df=Math.round((x.dataIniciMs-avuiMs)/86400000);return Array.from(_S.sel.t).some(function(t){return t==='venc'?df<0:t==='dia'?df===0:t==='set'?df>=-6&&df<=0:t==='mes'?df>=-30&&df<=0:t==='2m'?df>=-60&&df<=0:t==='3m'?df>=-90&&df<=0:false;});}
        var opos=dateFiltered.filter(function(x){
            var oO=!hO||(_S.sel.o.has(x.kb)||(_S.sel.o.has('completada')&&x.estat==='co')||(_S.sel.o.has('cancelada')&&x.estat==='ca'));
            var oT=!hT||_chkTime(x);
            return oO && oT && _passesUserFilter(x);
        });
        // Etapes OPO
        var OSTG=[{k:'espera',l:'En Espera',c:'#64748B'},{k:'analisis',l:'En Anàlisi',c:'#3B82F6'},{k:'tarifa',l:'Tarificació',c:'#0EA5E9'},{k:'docu',l:'Pdte. Docu',c:'#6366F1'},{k:'presentar',l:'Presentar',c:'#8B5CF6'},{k:'respuesta',l:'Pdte. Resp. Client',c:'#A855F7'},{k:'resp_cond',l:'Pdte. Resp. Cond.',c:'#EC4899'},{k:'emitir',l:'Per Emetre',c:'#F59E0B'},{k:'cierre',l:'Cierre/Revisió',c:'#F97316'}];
        function cO(s){return dateFiltered.filter(function(x){if(s==='completada')return x.estat==='co';if(s==='cancelada')return x.estat==='ca';return x.estat==='ab'&&x.kb===s;}).length;}
        // ── Cards de filtre — Y4.3+Y4.5b: Usuari → Rang → Etapa ──
        var cards='';
        cards+='<div class="dash-frt">👥 Usuari &nbsp;|&nbsp; 📆 Rang &nbsp;|&nbsp; 💼 Etapa</div><div class="dash-frow2b">';
        // 1) Cards d'usuari (PRIMER)
        var selAll=_S.sel.m.has('all')?' sel':'';
        cards+='<div class="dash-fc'+selAll+'" data-t="med" data-k="all" style="border-top:3px solid #F59E0B"><div class="dash-fcn" style="color:#F59E0B">'+dateFiltered.length+'</div><div class="dash-fcl">TOTS</div></div>';
        UIDS.forEach(function(uid){var u=USERS[uid];if(!u)return;var c=dateFiltered.filter(function(x){return x.uid===uid;}).length;var s=_S.sel.m.has(uid)?' sel':'';cards+='<div class="dash-fc'+s+'" data-t="med" data-k="'+uid+'" style="border-top:3px solid '+u.color+'"><div class="dash-fcn" style="color:'+u.color+'">'+c+'</div><div class="dash-fcl"><b style="background:'+u.bg+';color:'+u.color+';padding:0 3px;border-radius:3px">'+u.ini+'</b> '+_esc(u.name.split(' ')[0])+'</div></div>';});
        cards+='<div class="dash-fsep"></div>';
        // 2) Y4.4: CARD Rang (DESPRÉS d'usuaris)
        var _rmLbl = _rangModeLabel();
        cards+='<div class="dash-fc" data-t="rang" data-k="rang" style="border:1px solid #DC0028;background:#fff;cursor:pointer"><div class="dash-fcn" style="color:#DC0028;font-size:13px">📆</div><div class="dash-fcl" style="color:#DC0028;font-weight:700">Rang<br><span style="font-size:9px;color:#DC0028;font-weight:700">'+_rmLbl+'</span></div></div>';
        cards+='<div class="dash-fsep"></div>';
        // PP.4 — Card "🎯 ACCIÓ" amb popover (entre Rang i Etapes Kanban). Substitueix la versió OO.5.
        (function(){
            var _sopt2 = _S.sel.opoTipo;
            var _soptOpt2 = null;
            if(_sopt2){ for(var _spj=0;_spj<OPO_TIPO_OPTS.length;_spj++){ if(OPO_TIPO_OPTS[_spj].k===_sopt2){ _soptOpt2=OPO_TIPO_OPTS[_spj]; break; } } }
            cards += '<div class="dash-fc'+(_sopt2?' sel':'')+'" data-t="opotipo" data-k="opotipo" style="cursor:pointer;'+(_sopt2?'border:2px solid #DC0028;background:#fff':'border:1px dashed var(--br)')+'">'+
                (_soptOpt2
                    ? '<div class="dash-fcn" style="color:#DC0028;font-size:18px">'+_soptOpt2.e+'</div><div class="dash-fcl" style="color:#DC0028;font-weight:700">'+_soptOpt2.l+'</div>'
                    : '<div class="dash-fcn" style="font-size:18px">🎯</div><div class="dash-fcl">ACCIÓ</div>'
                )+'</div>';
        })();
        cards+='<div class="dash-fsep"></div>';
        // 3) Cards d'etapes OPO (al final)
        OSTG.forEach(function(s){var c=cO(s.k);var sel=_S.sel.o.has(s.k)?' sel':'';cards+='<div class="dash-fc'+sel+'" data-t="opo" data-k="'+s.k+'" style="border-top:3px solid '+s.c+'"><div class="dash-fcn" style="color:'+s.c+'">'+c+'</div><div class="dash-fcl">'+_esc(s.l)+'</div></div>';});
        cards+='</div>';
        // ── Render dels grups ──
        if(!opos.length) return cards+'<div class="dash-empty">💼<br>Cap OPO trobada amb els filtres actuals</div>';
        // Y4.5: Si multi-user (més d'1 usuari implicat), agrupar per usuari
        var uidsPresent = {};
        opos.forEach(function(x){uidsPresent[x.uid]=true;});
        var multiUser = Object.keys(uidsPresent).length > 1;
        function _renderOpoKbGroups(items, prefix){
            var groups={}; OSTG.forEach(function(s){groups[s.k]=[];}); groups['_sense']=[];
            items.forEach(function(x){if(x.kb && groups[x.kb]) groups[x.kb].push(x); else groups['_sense'].push(x);});
            var html='';
            OSTG.forEach(function(s){
                var arr=groups[s.k]; if(!arr.length) return;
                var cgid=prefix+'opo-'+s.k;
                var open=_S.openCG && _S.openCG.has(cgid);
                html+=_renderCG(cgid,s.l,arr.length,s.c,_renderItemsTable(arr,true),open);
            });
            if(groups['_sense'].length){
                var cgidS=prefix+'opo-_sense';
                var openS=_S.openCG && _S.openCG.has(cgidS);
                html+=_renderCG(cgidS,'Sense estat',groups['_sense'].length,'#64748B',_renderItemsTable(groups['_sense'],true),openS);
            }
            return html;
        }
        var groupsHtml='<div style="margin-top:10px">';
        if(multiUser){
            // Agrupar per usuari, dins cada usuari → grups Kanban
            UIDS.forEach(function(uid){
                var u=USERS[uid]; if(!u) return;
                var uOpos = opos.filter(function(x){return x.uid===uid;});
                if(!uOpos.length) return;
                var cgidU = 'opo-u-'+uid;
                var openU = _S.openCG && _S.openCG.has(cgidU);
                var userTitle = '<b style="background:'+u.bg+';color:'+u.color+';padding:1px 6px;border-radius:4px;margin-right:6px">'+u.ini+'</b> '+_esc(u.name);
                var userBody = _renderOpoKbGroups(uOpos, 'u-'+uid+'-');
                groupsHtml+=_renderCG(cgidU, userTitle, uOpos.length, u.color, userBody, openU);
            });
        } else {
            // Un sol usuari: grups Kanban directament (sense agrupació per usuari)
            groupsHtml+=_renderOpoKbGroups(opos, '');
        }
        groupsHtml+='</div>';
        return cards+groupsHtml;
    }

    function _renderActs(fil){
        // Y5.2: Reescriptura amb cards de filtre, CARD Rang i agrupació multi-user
        var n=new Date();n.setHours(0,0,0,0);
        var avuiMs=n.getTime();
        // Z2.3: usar _passesRangMode (no doblar filtre)
        var dateFiltered = fil.filter(function(x){return !x.isOpo;});
        var acts = dateFiltered.filter(_passesUserFilter);
        // ── Cards de filtre — Usuari → Rang → Tipus ──
        var cards='';
        cards+='<div class="dash-frt">👥 Usuari &nbsp;|&nbsp; 📆 Rang &nbsp;|&nbsp; 📋 Tipus</div><div class="dash-frow2b">';
        // 1) Cards d'usuari
        var selAll=_S.sel.m.has('all')?' sel':'';
        cards+='<div class="dash-fc'+selAll+'" data-t="med" data-k="all" style="border-top:3px solid #F59E0B"><div class="dash-fcn" style="color:#F59E0B">'+dateFiltered.length+'</div><div class="dash-fcl">TOTS</div></div>';
        UIDS.forEach(function(uid){var u=USERS[uid];if(!u)return;var c=dateFiltered.filter(function(x){return x.uid===uid;}).length;var s=_S.sel.m.has(uid)?' sel':'';cards+='<div class="dash-fc'+s+'" data-t="med" data-k="'+uid+'" style="border-top:3px solid '+u.color+'"><div class="dash-fcn" style="color:'+u.color+'">'+c+'</div><div class="dash-fcl"><b style="background:'+u.bg+';color:'+u.color+';padding:0 3px;border-radius:3px">'+u.ini+'</b> '+_esc(u.name.split(' ')[0])+'</div></div>';});
        cards+='<div class="dash-fsep"></div>';
        // 2) CARD Rang
        var _rmLbl = _rangModeLabel();
        cards+='<div class="dash-fc" data-t="rang" data-k="rang" style="border:1px solid #DC0028;background:#fff;cursor:pointer"><div class="dash-fcn" style="color:#DC0028;font-size:13px">📆</div><div class="dash-fcl" style="color:#DC0028;font-weight:700">Rang<br><span style="font-size:9px;color:#DC0028;font-weight:700">'+_rmLbl+'</span></div></div>';
        cards+='<div class="dash-fsep"></div>';
        // 3) Y5.3: Cards de tipus ACT
        var ATYP=[{k:'Tarea',l:'Tarea',e:'📋'},{k:'Llamada',l:'Llamada',e:'📞'},{k:'Cita',l:'Cita',e:'📅'},{k:'Visita',l:'Visita',e:'🤝'},{k:'WhatsApp',l:'WhatsApp',e:'💬'},{k:'Correo',l:'Correo',e:'✉'},{k:'Propen',l:'Propensió',e:'🎯'}];
        ATYP.forEach(function(t){
            var c=dateFiltered.filter(function(x){return x.tipus && x.tipus.indexOf(t.k)===0;}).length;
            var sel=_S.sel.a.has(t.k)?' sel':'';
            cards+='<div class="dash-fc'+sel+'" data-t="act" data-k="'+t.k+'" style="border-top:3px solid #3B82F6"><div class="dash-fcn" style="color:#3B82F6">'+c+'</div><div class="dash-fcl">'+t.e+' '+_esc(t.l)+'</div></div>';
        });
        cards+='</div>';
        // Y5.3: aplicar filtre de tipus si hi ha cards seleccionades
        var hA = _S.sel.a.size>0;
        if(hA){
            acts = acts.filter(function(x){
                return Array.from(_S.sel.a).some(function(k){return x.tipus && x.tipus.indexOf(k)===0;});
            });
        }
        // ── Render dels grups ──
        if(!acts.length) return cards+'<div class="dash-empty">📋<br>Cap activitat trobada amb els filtres actuals</div>';
        var ASTG=[{k:'pendent',l:'Pendents',c:'#64748B'},{k:'avui',l:'Avui',c:'#DC0028'},{k:'setmana',l:'Setmana',c:'#3B82F6'},{k:'mes',l:'Mes',c:'#8B5CF6'},{k:'fent',l:'En Curs',c:'#0EA5E9'},{k:'esperant',l:'Esperant',c:'#F59E0B'},{k:'altres',l:'Altres',c:'#A855F7'},{k:'urgent',l:'Urgents',c:'#EF4444'}];
        // Y5.2: agrupació multi-user
        var uidsPresent = {};
        acts.forEach(function(x){uidsPresent[x.uid]=true;});
        var multiUser = Object.keys(uidsPresent).length > 1;
        function _renderActKbGroups(items, prefix){
            var groups={}; ASTG.forEach(function(s){groups[s.k]=[];}); groups['_sense']=[];
            items.forEach(function(x){if(x.kb && groups[x.kb]) groups[x.kb].push(x); else groups['_sense'].push(x);});
            var html='';
            ASTG.forEach(function(s){
                var arr=groups[s.k]; if(!arr.length) return;
                var cgid=prefix+'act-'+s.k;
                var open=_S.openCG && _S.openCG.has(cgid);
                html+=_renderCG(cgid,s.l,arr.length,s.c,_renderItemsTable(arr,false),open);
            });
            if(groups['_sense'].length){
                var cgidS=prefix+'act-_sense';
                var openS=_S.openCG && _S.openCG.has(cgidS);
                html+=_renderCG(cgidS,'Sense estat',groups['_sense'].length,'#64748B',_renderItemsTable(groups['_sense'],false),openS);
            }
            return html;
        }
        var groupsHtml='<div style="margin-top:10px">';
        if(multiUser){
            UIDS.forEach(function(uid){
                var u=USERS[uid]; if(!u) return;
                var uActs = acts.filter(function(x){return x.uid===uid;});
                if(!uActs.length) return;
                var cgidU = 'act-u-'+uid;
                var openU = _S.openCG && _S.openCG.has(cgidU);
                var userTitle = '<b style="background:'+u.bg+';color:'+u.color+';padding:1px 6px;border-radius:4px;margin-right:6px">'+u.ini+'</b> '+_esc(u.name);
                var userBody = _renderActKbGroups(uActs, 'u-'+uid+'-');
                groupsHtml+=_renderCG(cgidU, userTitle, uActs.length, u.color, userBody, openU);
            });
        } else {
            groupsHtml+=_renderActKbGroups(acts, '');
        }
        groupsHtml+='</div>';
        return cards+groupsHtml;
    }

    function _renderMeds(fil){
        // Stages OPO i ACT (mateix ordre que els selects de Kanban)
        var OSTG=[{k:'espera',l:'En Espera',c:'#64748B'},{k:'analisis',l:'En Anàlisi',c:'#3B82F6'},{k:'tarifa',l:'Tarificació',c:'#0EA5E9'},{k:'docu',l:'Pdte. Docu',c:'#6366F1'},{k:'presentar',l:'Presentar',c:'#8B5CF6'},{k:'respuesta',l:'Pdte. Resp. Client',c:'#A855F7'},{k:'resp_cond',l:'Pdte. Resp. Cond.',c:'#EC4899'},{k:'emitir',l:'Per Emetre',c:'#F59E0B'},{k:'cierre',l:'Cierre/Revisió',c:'#F97316'}];
        var ASTG=[{k:'pendent',l:'Pendents',c:'#64748B'},{k:'avui',l:'Avui',c:'#DC0028'},{k:'setmana',l:'Setmana',c:'#3B82F6'},{k:'mes',l:'Mes',c:'#8B5CF6'},{k:'fent',l:'En Curs',c:'#0EA5E9'},{k:'esperant',l:'Esperant',c:'#F59E0B'},{k:'altres',l:'Altres',c:'#A855F7'},{k:'urgent',l:'Urgents',c:'#EF4444'}];
        // Z2.3: fil ja ve filtrat per _passesRangMode des de _getFiltered
        var n=new Date();n.setHours(0,0,0,0);
        var avuiMs=n.getTime();
        var fil2 = fil;
        // AA.2: rangBar eliminada (duplicada amb la card Rang gran als KPIs)
        var html='';
        UIDS.forEach(function(uid){
            var u=USERS[uid];if(!u)return;
            var uItems=fil2.filter(function(x){return x.uid===uid;});
            var opos=uItems.filter(function(x){return x.isOpo;});
            var acts=uItems.filter(function(x){return !x.isOpo;});
            var urg=uItems.filter(function(x){return x.urgent;}).length;
            // ── Wrapper de l'usuari (1 columna del grid amb les 2 cards apilades) ──
            html+='<div class="dash-mcol" data-uid="'+uid+'">';
            // ── CARD OPOs ─────────────────────────────────
            var opoCard='<div class="dash-mcard" style="border-left-color:'+u.color+'">'+
                '<div class="dash-mcard-hdr"><span class="dash-ini" style="background:'+u.bg+';color:'+u.color+';width:30px;height:30px;border-radius:8px;font-size:12px">'+_esc(u.ini)+'</span>'+
                '<div><div class="dash-mcard-name">💼 '+_esc(u.name)+' — Oportunitats</div>'+
                '<div class="dash-mcard-sub">'+opos.length+' OPOs'+(urg?' · 🚨 '+urg+' urgents':'')+'</div></div></div>';
            var opoPills='<div style="margin-top:8px;display:flex;flex-direction:column;gap:4px">';
            var hasOpoPills=false;
            OSTG.forEach(function(s){
                var items=opos.filter(function(x){return x.kb===s.k;});
                if(!items.length)return;
                hasOpoPills=true;
                var cgid='med-'+uid+'-opo-'+s.k;
                var open=_S.openCG && _S.openCG.has(cgid);
                opoPills+=_renderCG(cgid,s.l,items.length,s.c,_renderItemsTable(items,true),open,'small');
            });
            // OPOs sense estat
            var opoSense=opos.filter(function(x){return !x.kb;});
            if(opoSense.length){
                hasOpoPills=true;
                var cgid='med-'+uid+'-opo-sense';
                var open=_S.openCG && _S.openCG.has(cgid);
                opoPills+=_renderCG(cgid,'Sense estat',opoSense.length,'#64748B',_renderItemsTable(opoSense,true),open,'small');
            }
            if(!hasOpoPills) opoPills+='<div style="font-size:10px;color:var(--t4);padding:6px">Cap OPO</div>';
            opoPills+='</div>';
            html+=opoCard+opoPills+'</div>';
            // ── CARD ACTs ─────────────────────────────────
            var actCard='<div class="dash-mcard" style="border-left-color:'+u.color+'">'+
                '<div class="dash-mcard-hdr"><span class="dash-ini" style="background:'+u.bg+';color:'+u.color+';width:30px;height:30px;border-radius:8px;font-size:12px">'+_esc(u.ini)+'</span>'+
                '<div><div class="dash-mcard-name">📋 '+_esc(u.name)+' — Activitats</div>'+
                '<div class="dash-mcard-sub">'+acts.length+' ACTs</div></div></div>';
            var actPills='<div style="margin-top:8px;display:flex;flex-direction:column;gap:4px">';
            var hasActPills=false;
            ASTG.forEach(function(s){
                var items=acts.filter(function(x){return x.kb===s.k;});
                if(!items.length)return;
                hasActPills=true;
                var cgid='med-'+uid+'-act-'+s.k;
                var open=_S.openCG && _S.openCG.has(cgid);
                actPills+=_renderCG(cgid,s.l,items.length,s.c,_renderItemsTable(items,false),open,'small');
            });
            // ACTs sense estat
            var actSense=acts.filter(function(x){return !x.kb;});
            if(actSense.length){
                hasActPills=true;
                var cgid='med-'+uid+'-act-sense';
                var open=_S.openCG && _S.openCG.has(cgid);
                actPills+=_renderCG(cgid,'Sense estat',actSense.length,'#64748B',_renderItemsTable(actSense,false),open,'small');
            }
            if(!hasActPills) actPills+='<div style="font-size:10px;color:var(--t4);padding:6px">Cap ACT</div>';
            actPills+='</div>';
            html+=actCard+actPills+'</div>';
            html+='</div>'; // tanca .dash-mcol
        });
        return '<div class="dash-mcol-grid">'+html+'</div>';
    }

    // Filter cards (mode resum)
    function _renderFiltered(allItems){
        var ir=_root.querySelector('#dash-ir');if(!ir)return;
        var hO=_S.sel.o.size>0,hA=_S.sel.a.size>0,hM=_S.sel.m.size>0,hT=_S.sel.t.size>0;
        // Y3.5: si no hi ha cap card seleccionada, missatge i sortida
        if(!hO&&!hA&&!hM&&!hT){
            ir.innerHTML='<div style="color:var(--t4);font-size:12px;padding:20px;text-align:center">Clica una o més cards per filtrar</div>';
            return;
        }
        var f=_getFiltered(allItems);
        function _chkT(x){if(_S.sel.t.has('any'))return true;if(!x.dataIniciMs)return false;var n=new Date();n.setHours(0,0,0,0);var df=Math.round((x.dataIniciMs-n.getTime())/86400000);return Array.from(_S.sel.t).some(function(t){return t==='venc'?df<0:t==='dia'?df===0:t==='set'?df>=-6&&df<=0:t==='mes'?df>=-30&&df<=0:t==='2m'?df>=-60&&df<=0:t==='3m'?df>=-90&&df<=0:false;});}
        var res = f.filter(function(x){
            var oO=!hO||(x.isOpo&&(_S.sel.o.has(x.kb)||(_S.sel.o.has('completada')&&x.estat==='co')||(_S.sel.o.has('cancelada')&&x.estat==='ca')));
            var oA=!hA||(!x.isOpo&&Array.from(_S.sel.a).some(function(k){return x.tipus.indexOf(k)===0;}));
            var oM=!hM||_S.sel.m.has('all')||_S.sel.m.has(x.uid);
            var oT=!hT||_chkT(x);
            if(hO&&hA)return(oO||oA)&&oM&&oT;
            return((!hO||oO)&&(!hA||oA))&&oM&&oT;
        });
        // Y3.2: Agrupació per usuari amb sub-grups OPO/ACT
        var byUser = {};
        UIDS.forEach(function(uid){byUser[uid] = {opos:[], acts:[]};});
        res.forEach(function(x){
            if(byUser[x.uid]){
                if(x.isOpo) byUser[x.uid].opos.push(x);
                else        byUser[x.uid].acts.push(x);
            }
        });
        // Per defecte: usuaris oberts, sub-grups oberts (primera vegada)
        if(!_S._initResumUserCG){
            UIDS.forEach(function(uid){
                _S.openCG.add('resum-u-'+uid);
                _S.openCG.add('resum-u-'+uid+'-opo');
                _S.openCG.add('resum-u-'+uid+'-act');
            });
            _S._initResumUserCG = true;
        }
        var tb='<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px"><span class="dash-sec-title" style="margin:0">'+res.length+' items</span>'+(hO||hA||hM||hT?'<span data-act="clear-fc" style="cursor:pointer;color:#EF4444;font-size:11px">× Netejar filtres</span>':'')+'</div>';
        var anyShown = false;
        UIDS.forEach(function(uid){
            var u = USERS[uid]; if(!u) return;
            var data = byUser[uid];
            var tot = data.opos.length + data.acts.length;
            if(tot === 0) return;
            anyShown = true;
            var userBody = '';
            if(data.opos.length>0){
                var cgidO = 'resum-u-'+uid+'-opo';
                userBody += _renderCG(cgidO, '💼 OPOs', data.opos.length, '#8B5CF6', _renderItemsTable(data.opos, true), _S.openCG.has(cgidO), 'small');
            }
            if(data.acts.length>0){
                var cgidA = 'resum-u-'+uid+'-act';
                userBody += _renderCG(cgidA, '📋 ACTs', data.acts.length, '#3B82F6', _renderItemsTable(data.acts, false), _S.openCG.has(cgidA), 'small');
            }
            var cgidU = 'resum-u-'+uid;
            var userTitle = '<b style="background:'+u.bg+';color:'+u.color+';padding:1px 6px;border-radius:4px;margin-right:6px">'+u.ini+'</b> '+_esc(u.name);
            tb += _renderCG(cgidU, userTitle, tot, u.color, userBody, _S.openCG.has(cgidU));
        });
        if(!anyShown){
            tb += '<div style="color:var(--t4);font-size:12px;padding:20px;text-align:center">Sense resultats</div>';
        }
        ir.innerHTML=tb;
        // Re-marcar cards seleccionades
        _root.querySelectorAll('.dash-fc').forEach(function(el){
            var t=el.getAttribute('data-t'),k=el.getAttribute('data-k');
            var g=t==='med'?'m':t==='time'?'t':t==='act'?'a':'o';
            if(_S.sel[g]&&_S.sel[g].has(k))el.classList.add('sel');
            else el.classList.remove('sel');
        });
    }

    function _openItem(id, isOpo, focEl){
        if(typeof _OAv === 'undefined' || !_OAv.showDetail){
            console.warn('[dash] _OAv not ready');
            return;
        }
        var item = S.all.find(function(a){return String(a.IDOPOACT)===String(id)||String(a.IDACTIV)===String(id);});
        if(item){
            var foc = focEl || SR.querySelector('[data-aid="'+id+'"]') || null;
            _OAv.showDetail(item, foc);
        } else if(isOpo){
            _OAv.oaOpo && _OAv.oaOpo(String(id));
        } else {
            _OAv.oa && _OAv.oa(String(id));
        }
    }

    function _updateRangePill(){
        var rB = _root && _root.querySelector('#dash-f-rang');
        if(!rB) return;
        var rOn = !!(S.dateRange && (S.dateRange.from || S.dateRange.to));
        if(rOn){
            rB.classList.add('on');
            rB.style.borderColor = '#DC0028';
            rB.style.borderWidth = '2px';
            rB.style.color = '#DC0028';
            var fT = S.dateRange.from ? S.dateRange.from.split('-').reverse().join('/').slice(0,5) : '?';
            var tT = S.dateRange.to ? S.dateRange.to.split('-').reverse().join('/').slice(0,5) : '?';
            rB.innerHTML = '📆 ' + fT + ' → ' + tT + ' <span style="opacity:.7;margin-left:4px">×</span>';
        } else {
            rB.classList.remove('on');
            rB.style.borderColor = '';
            rB.style.borderWidth = '';
            rB.style.color = '';
            rB.innerHTML = '📆 Rang dates';
        }
    }

    function _wireInlineSelects(){
        if(!_root)return;
        // Mediador inline (com a rList) — lligat a _OAv.rua(id, uid)
        _root.querySelectorAll('.dash-medcell[data-id]').forEach(function(td){
            if(td.querySelector('select.dash-mediador-sel'))return;
            var id=td.getAttribute('data-id');
            var curUid=td.getAttribute('data-uid')||'M441819E';
            var u=USERS[curUid]||USERS['M441819E'];
            var sel=document.createElement('select');
            sel.className='dash-mediador-sel';
            sel.style.cssText='background:'+u.bg+';color:'+u.color+';border:1px solid '+u.color+';border-radius:5px;padding:2px 6px;font-size:11px;font-weight:700;font-family:inherit;cursor:pointer;outline:none';
            UIDS.forEach(function(uid){
                var op=document.createElement('option');
                op.value=uid;
                op.textContent=USERS[uid].ini+' — '+USERS[uid].name;
                if(uid===curUid)op.selected=true;
                sel.appendChild(op);
            });
            sel.addEventListener('mousedown',function(e){e.stopPropagation();});
            sel.addEventListener('click',function(e){e.stopPropagation();});
            sel.addEventListener('change',function(e){
                e.stopPropagation();
                if(typeof _OAv!=='undefined' && _OAv.rua) _OAv.rua(id, this.value);
            });
            td.innerHTML='';
            td.appendChild(sel);
        });
        // Kanban inline — directament a localStorage + applyF()
        _root.querySelectorAll('.dash-kbcell[data-id]').forEach(function(td){
            if(td.querySelector('select.dash-kanban-sel'))return;
            var id=td.getAttribute('data-id');
            var curKb=td.getAttribute('data-kb')||'';
            var tr=td.closest('tr');
            var isOpo=tr && tr.getAttribute('data-isopo')==='1';
            var sel=document.createElement('select');
            sel.className='dash-kanban-sel';
            sel.style.cssText='background:var(--bg3);color:var(--t1);border:1px solid var(--br);border-radius:5px;padding:2px 6px;font-size:11px;font-family:inherit;cursor:pointer;outline:none;max-width:140px';
            var opts;
            if(isOpo){
                opts=[['','— sense —'],['espera','En Espera'],['analisis','En Anàlisi'],['tarifa','Tarificació'],['docu','Pdte. Docu'],['presentar','Presentar'],['respuesta','Pdte. Resp. Client'],['resp_cond','Pdte. Resp. Cond.'],['emitir','Per Emetre'],['cierre','Cierre/Revisió']];
            } else {
                opts=[['','— sense —'],['pendent','Pendents'],['avui','Avui'],['setmana','Setmana'],['mes','Mes'],['fent','En Curs'],['esperant','Esperant'],['altres','Altres'],['urgent','Urgents']];
            }
            opts.forEach(function(o){
                var op=document.createElement('option');
                op.value=o[0];
                op.textContent=o[1];
                if(o[0]===curKb)op.selected=true;
                sel.appendChild(op);
            });
            sel.addEventListener('mousedown',function(e){e.stopPropagation();});
            sel.addEventListener('click',function(e){e.stopPropagation();});
            sel.addEventListener('change',function(e){
                e.stopPropagation();
                var v=this.value;
                var key=isOpo?('kb_'+id):('tc_col_'+id);
                if(v)localStorage.setItem(key,v);
                else localStorage.removeItem(key);
                if(typeof applyF==='function')applyF();
            });
            td.innerHTML='';
            td.appendChild(sel);
        });
    }

    function _renderBody(){
        if(!_root||!_content)return;
        var allItems = _getItems();
        var fil = _getFiltered(allItems);
        // Z2.3: Subset que reflecteix la vista actual (per als KPIs)
        // fil ja ve filtrat per _passesRangMode des de _getFiltered
        var kpiSubset = fil;
        if(_S.curTab===2 || _S.curTab===3){
            kpiSubset = fil.filter(function(x){
                if(_S.curTab===2 && !x.isOpo) return false;
                if(_S.curTab===3 && x.isOpo) return false;
                return _passesUserFilter(x);
            });
            // Pestanya 2 (OPOs): aplicar també les cards de filtre seleccionades
            if(_S.curTab===2){
                var hO=_S.sel.o.size>0,hM=_S.sel.m.size>0,hT=_S.sel.t.size>0;
                if(hO||hM||hT){
                    var _nKpi=new Date();_nKpi.setHours(0,0,0,0);
                    function _chkT2(x){if(_S.sel.t.has('any'))return true;var d=x.dataIniciMs;if(!d)return false;var df=Math.round((d-_nKpi.getTime())/86400000);return Array.from(_S.sel.t).some(function(t){return t==='venc'?df<0:t==='dia'?df===0:t==='set'?df>=-6&&df<=0:t==='mes'?df>=-30&&df<=0:t==='2m'?df>=-60&&df<=0:t==='3m'?df>=-90&&df<=0:false;});}
                    kpiSubset = kpiSubset.filter(function(x){
                        var oO=!hO||(_S.sel.o.has(x.kb)||(_S.sel.o.has('completada')&&x.estat==='co')||(_S.sel.o.has('cancelada')&&x.estat==='ca'));
                        var oM=!hM||_S.sel.m.has('all')||_S.sel.m.has(x.uid);
                        var oT=!hT||_chkT2(x);
                        return oO&&oM&&oT;
                    });
                }
            }
        }
        var kpis = (_S.curTab===3) ? _renderKpisAct(kpiSubset) : (_S.curTab===2 ? _renderKpisOpo(kpiSubset) : _renderKpis(kpiSubset));
        var main='';
        var noWrap=false;
        if(_S.curTab===0){main=_renderResum(fil, allItems);noWrap=true;}
        else if(_S.curTab===1)main=_renderMeds(fil);
        else if(_S.curTab===2)main=_renderOpos(fil);
        else main=_renderActs(fil);
        var inner=noWrap?main:'<div class="dash-scroll">'+main+'</div>';
        _content.innerHTML=kpis+'<div id="dash-pane">'+inner+'</div>';
        // Z7.2: Wire explícit a totes les cards Rang (després de cada render)
        try {
            var rangCards = _content.querySelectorAll('.dash-fc[data-t="rang"], .dash-kpi-rang');
            console.log('[reunio render] tab='+_S.curTab+' rangMode='+_S.rangMode+' cards Rang trobades:', rangCards.length);
            rangCards.forEach(function(el){
                el.addEventListener('click', function(ev){
                    ev.stopPropagation();
                    ev.preventDefault();
                    console.log('[rangmode] direct click on card', this);
                    _showRangModePopover(this);
                });
            });
        } catch(eWire){ console.warn('[rangmode wire err]', eWire); }
        if(_S.curTab===0)setTimeout(function(){_renderFiltered(allItems);},0);
        // _wireInlineSelects();  // TEMP: desactivat per diagnosticar bloqueig modal
        _updateRangePill();
    }

    function _initSelects(){
        var medSel=_root.querySelector('#dash-f-med');
        if(medSel){
            medSel.innerHTML='<option value="">Tots els mediadors</option>';
            UIDS.forEach(function(uid){var u=USERS[uid];if(!u)return;var o=document.createElement('option');o.value=uid;o.textContent=u.ini+' — '+u.name;medSel.appendChild(o);});
        }
        var allItems=_getItems();
        var kbSel=_root.querySelector('#dash-f-kb');
        if(kbSel){
            // Llista fixa coincident amb els modals (OPO + ACT amb optgroup)
            var _kbHtml='<option value="">Totes les etapes</option>';
            _kbHtml+='<optgroup label="── OPO (Etapa) ──">';
            _kbHtml+='<option value="espera">En Espera</option>';
            _kbHtml+='<option value="analisis">En Anàlisi</option>';
            _kbHtml+='<option value="tarifa">Tarificació</option>';
            _kbHtml+='<option value="docu">Pdte. Docu</option>';
            _kbHtml+='<option value="presentar">Presentar</option>';
            _kbHtml+='<option value="respuesta">Pdte. Resp. Client</option>';
            _kbHtml+='<option value="resp_cond">Pdte. Resp. Cond.</option>';
            _kbHtml+='<option value="emitir">Per Emetre</option>';
            _kbHtml+='<option value="cierre">Cierre/Revisió</option>';
            _kbHtml+='</optgroup>';
            _kbHtml+='<optgroup label="── ACT (Columna) ──">';
            _kbHtml+='<option value="pendent">Pendents</option>';
            _kbHtml+='<option value="avui">Avui</option>';
            _kbHtml+='<option value="setmana">Setmana</option>';
            _kbHtml+='<option value="mes">Mes</option>';
            _kbHtml+='<option value="fent">En Curs</option>';
            _kbHtml+='<option value="esperant">Esperant</option>';
            _kbHtml+='<option value="altres">Altres</option>';
            _kbHtml+='<option value="urgent">Urgents</option>';
            _kbHtml+='</optgroup>';
            kbSel.innerHTML=_kbHtml;
        }
        var tps={}; allItems.forEach(function(x){tps[x.tipus]=1;});
        var tpSel=_root.querySelector('#dash-f-tipus');
        if(tpSel){
            tpSel.innerHTML='<option value="">Tots els tipus</option>';
            Object.keys(tps).sort().forEach(function(t){var o=document.createElement('option');o.value=t;o.textContent=t;tpSel.appendChild(o);});
        }
    }

    function _wireEvents(){
        // Tabs
        _root.querySelectorAll('.dash-tab').forEach(function(t){
            t.addEventListener('click',function(){
                var n=parseInt(this.getAttribute('data-tab'));
                _S.curTab=n;
                _root.querySelectorAll('.dash-tab').forEach(function(x){x.classList.remove('on');});
                this.classList.add('on');
                _renderBody();
            });
        });
        // Filtres input
        ['dash-f-med','dash-f-kb','dash-f-tipus','dash-f-srch'].forEach(function(id){
            var el=_root.querySelector('#'+id);
            if(el)el.addEventListener('input',function(){_renderBody();});
        });
        // Pill Urgents
        var fu=_root.querySelector('#dash-f-urg');
        if(fu)fu.addEventListener('click',function(){
            _S.urgOnly=!_S.urgOnly;
            this.className='pill'+(_S.urgOnly?' on-red':'');
            _renderBody();
        });
        // Pill Actius
        var fo=_root.querySelector('#dash-f-only-open');
        if(fo)fo.addEventListener('click',function(){
            _S.onlyOpen=!_S.onlyOpen;
            this.className='pill'+(_S.onlyOpen?' on':'');
            this.textContent=_S.onlyOpen?'📋 Obertes':'✅ Completades';
            _renderBody();
        });
        // Z3.3: Pill 'Avui' eliminada (substituïda per card Rang amb 5 opcions)
        // Pill Rang dates (T3.1)
        var fr=_root.querySelector('#dash-f-rang');
        if(fr)fr.addEventListener('click',function(){
            var rOn=!!(S.dateRange&&(S.dateRange.from||S.dateRange.to));
            if(rOn){
                S.dateRange={from:'',to:''};
                if(typeof applyF==='function')applyF();
                return;
            }
            if(typeof _showDateRangePopover==='function')_showDateRangePopover(fr);
        });
        // Delegation: click a contingut (cards filtre, sort headers, files de taula)
        _content.addEventListener('click',function(ev){
            var t=ev.target;
            // Z2.8: Card Rang gran als KPIs
            var kpiRang = t.closest && t.closest('.dash-kpi-rang');
            if(kpiRang){
                _showRangModePopover(kpiRang);
                return;
            }
            // PP.5b — Card ACCIÓ als KPIs (Resum/Mediador) → popover Tipus OPO
            var kpiOpoTipo = t.closest && t.closest('.dash-kpi-opotipos');
            if(kpiOpoTipo){
                _showOpoTipoPopover(kpiOpoTipo);
                return;
            }
            // Card de filtre (Resum)
            var fc = t.closest && t.closest('.dash-fc');
            if(fc){
                var dt=fc.getAttribute('data-t'),dk=fc.getAttribute('data-k');
                // Z2.7: Card Rang → popover de 5 opcions
                if(dt==='rang'){
                    _showRangModePopover(fc);
                    return;
                }
                // PP.5 — Card ACCIÓ → popover Tipus OPO
                if(dt==='opotipo'){
                    _showOpoTipoPopover(fc);
                    return;
                }
                var g=dt==='med'?'m':dt==='time'?'t':dt==='act'?'a':'o';
                // Lògica TOTS↔individual al filtre de mediadors
                if(g==='m' && dk==='all'){
                    if(_S.sel.m.has('all')){
                        _S.sel.m.delete('all');
                    } else {
                        // Marca TOTS i desmarca tots els individuals
                        _S.sel.m.clear();
                        _S.sel.m.add('all');
                    }
                } else if(g==='m'){
                    // Click a un mediador individual: desmarcar TOTS si està marcat
                    if(_S.sel.m.has('all')) _S.sel.m.delete('all');
                    if(_S.sel.m.has(dk)) _S.sel.m.delete(dk);
                    else _S.sel.m.add(dk);
                } else {
                    if(_S.sel[g].has(dk)) _S.sel[g].delete(dk);
                    else _S.sel[g].add(dk);
                }
                // Actualitzar visualment totes les cards de la mateixa columna
                if(g==='m'){
                    _root.querySelectorAll('.dash-fc[data-t="med"]').forEach(function(el){
                        var ek=el.getAttribute('data-k');
                        if(_S.sel.m.has(ek)) el.classList.add('sel');
                        else el.classList.remove('sel');
                    });
                } else {
                    if(_S.sel[g].has(dk)) fc.classList.add('sel');
                    else fc.classList.remove('sel');
                }
                if(_S.curTab===0) _renderFiltered(_getItems());
                else _renderBody();
                return;
            }
            // Clear filter cards
            if(t.getAttribute && t.getAttribute('data-act')==='clear-fc'){
                _root.querySelectorAll('.dash-fc.sel').forEach(function(e){e.classList.remove('sel');});
                _initSel();
                if(_S.curTab===0) _renderFiltered(_getItems());
                else _renderBody();
                return;
            }
            // Sort header
            var th = t.closest && t.closest('th[data-col]');
            if(th){
                var col=th.getAttribute('data-col');
                if(_S.sortCol===col)_S.sortDir*=-1;else{_S.sortCol=col;_S.sortDir=1;}
                _renderBody();
                return;
            }
            // Row click → obre item (o multisel amb Ctrl/Shift)
            var tr = t.closest && t.closest('tr[data-id]');
            if(tr){
                var id=tr.getAttribute('data-id');
                var isOpo=tr.getAttribute('data-isopo')==='1';
                // R1: Ctrl/Cmd+Click → toggle individual a multiselecció
                if(ev.ctrlKey || ev.metaKey){
                    ev.preventDefault();
                    if(typeof _selToggle === 'function'){
                        _selToggle(id);
                        tr.style.outline = (_sel && _sel.has && _sel.has(id)) ? '2px solid #8B5CF6' : '';
                        if(typeof _updSelBar === 'function') _updSelBar();
                    }
                    return;
                }
                // R1: Shift+Click → rang
                if(ev.shiftKey){
                    ev.preventDefault();
                    if(typeof _selRange === 'function'){
                        _selRange(id);
                        // Aplicar outline a tots els <tr> del Dashboard que estiguin a _sel
                        if(_root && _sel){
                            _root.querySelectorAll('tr[data-id]').forEach(function(t2){
                                t2.style.outline = _sel.has(t2.getAttribute('data-id')) ? '2px solid #8B5CF6' : '';
                            });
                        }
                        if(typeof _updSelBar === 'function') _updSelBar();
                    }
                    return;
                }
                _openItem(id, isOpo, tr);
                return;
            }
            // Mediador: click al header de card maximitza/restaura columna
            if(_S.curTab===1){
                var mhdr = t.closest && t.closest('.dash-mcard-hdr');
                if(mhdr){
                    var mcol = mhdr.closest('.dash-mcol');
                    if(mcol){
                        var wasMaxed = mcol.classList.contains('maxed');
                        _root.querySelectorAll('.dash-mcol').forEach(function(c){c.classList.remove('maxed');});
                        if(!wasMaxed) mcol.classList.add('maxed');
                    }
                    return;
                }
            }
            // Group collapse toggle (B4/B6)
            var cgh = t.closest && t.closest('.dash-cg-h');
            if(cgh){
                var cgid = cgh.getAttribute('data-cg');
                if(cgid){
                    var box = _root.querySelector('.dash-cg[data-cgid="'+cgid+'"] > .dash-cg-b');
                    var arrow = cgh.querySelector('.dash-cg-arrow');
                    if(box){
                        var isOpen = box.style.display !== 'none';
                        box.style.display = isOpen ? 'none' : 'block';
                        if(arrow) arrow.textContent = isOpen ? '▶' : '▼';
                        if(_S.openCG){
                            if(isOpen) _S.openCG.delete(cgid);
                            else _S.openCG.add(cgid);
                        }
                    }
                }
                return;
            }
        });

        // ─── O+U: Drag&drop a pestanyes Reunió (tabs 1, 2, 3) ───
        // Helper per parsejar cgid → {scope, uid?, type?, kb}
        // Formats: 'med-<uid>-<opo|act>-<kb>'  |  'opo-<kb>'  |  'act-<kb>'
        function _parseCgid(cgid){
            if(!cgid) return null;
            var parts = cgid.split('-');
            if(parts[0] === 'med'){
                if(parts.length < 4) return null;
                return { scope:'med', uid:parts[1], type:parts[2], kb:parts.slice(3).join('-') };
            } else if(parts[0] === 'opo' || parts[0] === 'act'){
                if(parts.length < 2) return null;
                return { scope:parts[0], type:parts[0], kb:parts.slice(1).join('-') };
            }
            return null;
        }
        _content.addEventListener('dragstart', function(e){
            if(_S.curTab < 1){ e.preventDefault(); return; }
            var tr = e.target && e.target.closest && e.target.closest('tr[data-id]');
            if(!tr){ e.preventDefault(); return; }
            try {
                e.dataTransfer.effectAllowed = 'move';
                e.dataTransfer.setData('text/plain', JSON.stringify({
                    id:    tr.getAttribute('data-id'),
                    isopo: tr.getAttribute('data-isopo'),
                    uid:   tr.getAttribute('data-uid'),
                    kb:    tr.getAttribute('data-kb')
                }));
                console.log('[drag start]', {id:tr.getAttribute('data-id'), isopo:tr.getAttribute('data-isopo'), uid:tr.getAttribute('data-uid'), kb:tr.getAttribute('data-kb')});
            } catch(err){ console.warn('[drag start err]', err); }
            tr.classList.add('dash-dragging');
        });
        _content.addEventListener('dragend', function(e){
            if(_root){
                _root.querySelectorAll('tr.dash-dragging').forEach(function(t){t.classList.remove('dash-dragging');});
                _root.querySelectorAll('.dash-drop-over').forEach(function(el){el.classList.remove('dash-drop-over');});
            }
        });
        _content.addEventListener('dragover', function(e){
            if(_S.curTab < 1) return;
            var mcol = e.target && e.target.closest && e.target.closest('.dash-mcol');
            var cgh  = e.target && e.target.closest && e.target.closest('.dash-cg-h');
            var cgb  = e.target && e.target.closest && e.target.closest('.dash-cg-b');
            var cg   = e.target && e.target.closest && e.target.closest('.dash-cg');
            if(mcol || cgh || cgb || cg){
                e.preventDefault();
                e.dataTransfer.dropEffect = 'move';
            }
        });
        _content.addEventListener('dragenter', function(e){
            if(_S.curTab < 1) return;
            var cg   = e.target && e.target.closest && e.target.closest('.dash-cg');
            var mcol = e.target && e.target.closest && e.target.closest('.dash-mcol');
            // Prioritzem el grup Kanban sencer (header + body) per feedback
            if(cg) cg.classList.add('dash-drop-over');
            else if(mcol) mcol.classList.add('dash-drop-over');
        });
        _content.addEventListener('dragleave', function(e){
            if(_S.curTab < 1) return;
            var cg   = e.target && e.target.closest && e.target.closest('.dash-cg');
            var mcol = e.target && e.target.closest && e.target.closest('.dash-mcol');
            if(cg && !cg.contains(e.relatedTarget)) cg.classList.remove('dash-drop-over');
            if(mcol && !mcol.contains(e.relatedTarget)) mcol.classList.remove('dash-drop-over');
        });
        _content.addEventListener('drop', function(e){
            if(_S.curTab < 1) return;
            e.preventDefault();
            var data;
            try { data = JSON.parse(e.dataTransfer.getData('text/plain')); }
            catch(err){ console.warn('[drop parse err]', err); return; }
            if(!data || !data.id){ console.warn('[drop] no data'); return; }
            // Netejar drop-over
            if(_root) _root.querySelectorAll('.dash-drop-over').forEach(function(el){
                el.classList.remove('dash-drop-over');
            });
            // ─── W3: Determinar AMBDÓS canvis (usuari + Kanban) ───
            var cg = e.target && e.target.closest && e.target.closest('.dash-cg');
            var mcol = e.target && e.target.closest && e.target.closest('.dash-mcol');
            // Usuari destí (només té sentit a Mediador, on hi ha .dash-mcol)
            var newUid = (_S.curTab === 1 && mcol) ? mcol.getAttribute('data-uid') : null;
            var userChanged = !!(newUid && newUid !== data.uid);
            // Kanban destí
            var newKb = null;
            if(cg){
                var cgid = cg.getAttribute('data-cgid') || '';
                var parsed = _parseCgid(cgid);
                if(parsed && parsed.kb && parsed.kb !== '_sense' && parsed.kb !== 'sense'){
                    newKb = parsed.kb;
                }
            }
            var kbChanged = !!(newKb && newKb !== data.kb);
            console.log('[drop]', {data:data, newUid:newUid, newKb:newKb, userChanged:userChanged, kbChanged:kbChanged});
            // Si no hi ha cap canvi, fora
            if(!userChanged && !kbChanged){
                console.log('[drop] ignored: cap canvi efectiu');
                return;
            }
            // ─── 1) Aplicar canvi de Kanban (si toca) — ràpid, només localStorage ───
            if(kbChanged){
                var key = data.isopo === '1' ? ('kb_'+data.id) : ('tc_col_'+data.id);
                try {
                    localStorage.setItem(key, newKb);
                    console.log('[drop] kb set:', key, '=', newKb);
                } catch(err2){ console.warn('[drop kb set err]', err2); }
            }
            // ─── 2) Aplicar canvi d'usuari (si toca) ───
            if(userChanged){
                // Persist asg local (override permanent)
                try{
                    var _asgLocal = (typeof loadAsg === 'function') ? loadAsg() : {};
                    _asgLocal[data.id] = newUid;
                    if(typeof saveAsg === 'function') saveAsg(_asgLocal);
                    console.log('[drop] asg saved:', data.id, '→', newUid);
                } catch(eAsg){ console.warn('[drop] saveAsg err:', eAsg); }
                // Modificar S.all directament perquè el cache reconstruirà amb el nou uid
                try{
                    var _aRef = (typeof S!=='undefined' && S.all) ? S.all.find(function(x){
                        return (x.IDACTIV===data.id) || (x.IDOPOACT===data.id);
                    }) : null;
                    if(_aRef){
                        _aRef._uid = newUid;
                        _aRef.UID_RACF = newUid;
                        console.log('[drop] S.all updated for', data.id);
                    }
                } catch(eSa){ console.warn('[drop] S.all update err:', eSa); }
                // Cridar _OAv.rua per al sync amb el CRM (en background, async)
                if(_OAv && typeof _OAv.rua === 'function'){
                    try { _OAv.rua(data.id, newUid); }
                    catch(eRua){ console.warn('[drop] rua call err:', eRua); }
                }
            }
            // ─── 3) Forçar refresh del Dashboard ───
            _invalidateCache();
            try { refresh(); } catch(eRf){ console.warn('[drop] refresh err:', eRf); }
        });
    }

    function _buildShell(){
        var d=document.createElement('div');
        d.id='dash-root';
        d.innerHTML=
            '<div id="dash-topbar">'+
                '<div class="dash-logo">🤝</div>'+
                '<div id="dash-tabbar-inline">'+
                    '<div class="dash-tab on" data-tab="0">📊 Resum</div>'+
                    '<div class="dash-tab" data-tab="1">👥 Mediador</div>'+
                    '<div class="dash-tab" data-tab="2">💼 Oportunitats</div>'+
                    '<div class="dash-tab" data-tab="3">📋 Activitats</div>'+
                '</div>'+
                '<input id="dash-f-srch" type="search" placeholder="Cercar..." style="width:275px;flex-shrink:0;margin-left:10px">'+
                '<div class="dash-fbar">'+
                    ''+
                    '<button class="pill" id="dash-f-urg">🚨 Urgents</button>'+
                    '<button class="pill on" id="dash-f-only-open">📋 Obertes</button>'+
                    ''+
                '</div>'+
            '</div>'+
            '<div id="dash-content"></div>';
        return d;
    }

    function render(container){
        if(!container)return;
        // Reset estat (nova entrada = filtres nets)
        _S.sortCol=null; _S.sortDir=1; _S.curTab=0; _S.urgOnly=false; _S.onlyOpen=true; _S.rangMode='avui_atras';
        _initSel();
        _S.openCG=new Set();
        _invalidateCache();
        container.innerHTML='';
        _root = _buildShell();
        container.appendChild(_root);
        _content = _root.querySelector('#dash-content');
        _initSelects();
        _wireEvents();
        _renderBody();
    }

    function refresh(){
        if(!_root||!_content)return;
        // LL.4 — Preservar scrolls del Dashboard entre re-renders
        var _scD = (typeof _captureScrolls === 'function') ? _captureScrolls(_root) : null;
        _invalidateCache();
        _renderBody();
        requestAnimationFrame(function(){
            if(_scD && typeof _restoreScrolls === 'function') _restoreScrolls(_root, _scD);
        });
    }

    function destroy(){
        if(_root && _root.parentNode) _root.parentNode.removeChild(_root);
        _root=null; _content=null;
        _S.sortCol=null; _S.sortDir=1; _S.curTab=0; _S.urgOnly=false; _S.onlyOpen=true; _S.rangMode='avui_atras';
        _initSel();
        _S.openCG=new Set();
        _invalidateCache();
    }

    return {render:render, refresh:refresh, destroy:destroy};
})();
