        lusel.addEventListener('mousedown',function(e){e.stopPropagation();});lusel.addEventListener('click',function(e){e.stopPropagation();});lusel.addEventListener('change',function(e){e.stopPropagation();_OAv.rua(a._isOpo?a.IDOPOACT:a.IDACTIV,this.value);});
        var lph=la.querySelector('#lus_'+a.IDACTIV);if(lph)lph.replaceWith(lusel);
