// X: flag per saber si vtosModal s'ha obert des del modal LLISTA
try{ if(typeof window._vtosFromList==='undefined') window._vtosFromList = false; }catch(e){}
function vtosModal(it){
    q('vmodal')?.remove();
    var isE=!!(it&&it.id);
    var d=it||{id:'',asunto:'',cliente:'',fecha:fmtD(S.date),tipo:'Tarea',notas:''};
    var _activeUser=_selUserUid||_activeUid||'M441819E';
    var ov=document.createElement('div');ov.className='vmodal';ov.id='vmodal';
    var box=document.createElement('div');box.className='vmbox';

    function _toISO(dd_mm_yyyy){
        if(!dd_mm_yyyy)return '';
        var p=dd_mm_yyyy.split('/');
        if(p.length===3&&p[2].length===4)return p[2]+'-'+p[1].padStart(2,'0')+'-'+p[0].padStart(2,'0');
        return dd_mm_yyyy;
    }
    function _buildFields(tipo){
        var isOpo=tipo==='Oportunidad';
        var html='';
        html+='<div class="vf"><label>Client</label><input id="vc" type="text" list="vc-datalist" value="'+esc(d.cliente)+'" autocomplete="off"></div>';
        // Build client datalist from S.all
        var _cliSet={};S.all.forEach(function(a){if(a.CLIENTE&&a.REFNUMPERS)_cliSet[a.CLIENTE]=a.REFNUMPERS;});
        html+='<datalist id="vc-datalist">';
        Object.keys(_cliSet).sort().forEach(function(nom){html+='<option value="'+esc(nom)+'">';});
        html+='</datalist>';
        html+='<div class="vf"><label>Assumpte *</label><input id="va" type="text" value="'+esc(d.asunto)+'"></div>';
        if(isOpo){
            html+='<div class="vf"><label>Data Inici (Propera Acció)</label><input id="vfe" type="date" value="'+_toISO(d.fecha)+'"></div>';
            html+='<div class="vf"><label>Data Venciment (Tancament Est.)</label><input id="vfe2" type="date" value="'+_toISO(d.fecha2||'')+'"></div>';
        } else {
            html+='<div class="vf"><label>Data Inici</label><input id="vfe" type="date" value="'+_toISO(d.fecha)+'"></div>';
        }
        html+='<div class="vf"><label>Assignar a</label><select id="vusr" style="background:var(--bg3);border:1.5px solid var(--br);border-radius:6px;padding:7px 10px;color:var(--t1);font-size:13px;font-family:inherit;width:100%">';
        UIDS.forEach(function(uid){
            html+='<option value="'+uid+'"'+(uid===_activeUser?' selected':'')+'>'+USERS[uid].ini+' — '+USERS[uid].name+'</option>';
        });
        html+='</select></div>';
        html+='<div style="display:flex;justify-content:center;margin:10px 0 4px">';
        // urgent pill removed from Nova OPO/ACT
        html+='</div>';
        return html;
    }

    function _wireUrgent(initialState){
        var _vup=box.querySelector('#vtos-urg-pill');
        if(!_vup)return;
        var _urgState=!!initialState;
        _vup.className='urg-btn'+(_urgState?' urg-on':'');
        _vup.textContent=_urgState?'URGENT':'¿Urgent?';
        _vup.addEventListener('click',function(){
            _urgState=!_urgState;
            _vup.className='urg-btn'+(_urgState?' urg-on':'');
            _vup.textContent=_urgState?'URGENT':'¿Urgent?';
        });
        _vup._getUrgent=function(){return _urgState;};
    }

    box.innerHTML='<h3>'+(isE?'✏️ Editar entrada':'✨ Nova OPO/ACT')+'</h3>'+
        '<div class="vf" style="margin-bottom:10px"><label>Tipus</label><select id="vti">'+
        (!isE?'<option value="" disabled selected>Seleccionar Tipus Tasca</option>':'')+
        '<option value="TascaRapida"'+(d.tipo==='TascaRapida'?' selected':'')+'>⚡ Tasca Ràpida</option>'+
        '<option disabled>\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</option>'+
        '<option value="Oportunidad"'+(d.tipo==='Oportunidad'?' selected':'')+'>💼 Oportunitat</option>'+
        '<option disabled>\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500</option>'+
        Object.keys(TYPES).filter(function(t){return t!=='Oportunidad';}).map(function(t){
            return'<option value="'+t+'"'+(d.tipo===t?' selected':'')+'>'+TYPES[t].i+' '+t+'</option>';
        }).join('')+
        '</select></div>'+
        '<div id="vtos-fields">'+_buildFields(d.tipo||'Tarea')+'</div>'+
        '<div class="vf"><label>Notes</label><textarea id="vn">'+esc(d.notas||'')+'</textarea></div>'+
        '<div class="vmbtns" id="vmbtns"></div>';

    var btns=box.querySelector('#vmbtns');
    var bCancel=document.createElement('button');bCancel.className='vmcancel';bCancel.textContent='Cancel·lar';
    bCancel.addEventListener('click',function(){
        q('vmodal')?.remove();
        if(window._vtosFromList){
            window._vtosFromList = false;
            try{ if(window._OAv && typeof _OAv.vtosOpenModal==='function') _OAv.vtosOpenModal(); }catch(eX){}
        }
    });
    var bSave=document.createElement('button');bSave.className='vmsave';bSave.textContent=isE?'Guardar':'Afegir';
    bSave.addEventListener('click',function(){_OAv.vtosSave(d.id||'');});
    // Botó nou: "Agregar a CRM" — guarda i passa directament al CRM nadiu
    var bSaveCRM=document.createElement('button');
    bSaveCRM.className='vmsave';
    bSaveCRM.style.cssText='background:linear-gradient(135deg,#10B981,#059669);margin-left:6px';
    bSaveCRM.textContent='\ud83d\ude80 '+(isE?'Guardar i a CRM':'Agregar a CRM');
    bSaveCRM.title='Crea l\'entrada i obre el CRM nadiu per persistir-la';
    bSaveCRM.addEventListener('click',function(){
        // 1. Desar primer (igual que el botó normal)
        var _id=d.id||'';
        _OAv.vtosSave(_id);
        // 2. Obtenir l'ID del recent creat (l'últim de la llista o el d.id si era edit)
        setTimeout(function(){
            var targetId=_id;
            if(!targetId&&S.vtos&&S.vtos.items&&S.vtos.items.length>0){
                // El recent creat és el primer (s'afegeix amb unshift)
                targetId=S.vtos.items[0].id;
            }
            if(!targetId){_toast('\u26a0 No s\'ha pogut localitzar l\'entrada','#F59E0B',2500);return;}
            // 3. Identificar usuari assignat (del camp vusr o l'actiu)
            var _itNew=S.vtos.items.find(function(x){return x.id===targetId;});
            var _uid=(_itNew&&_itNew.usuari)||_activeUid;
            // 4. Llançar vtosAssign que obre el CRM amb form omplert
            _OAv.vtosAssign(targetId,_uid);
        },100);
    });
    btns.appendChild(bCancel);btns.appendChild(bSave);btns.appendChild(bSaveCRM);
    ov.appendChild(box);app.appendChild(ov);

    setTimeout(function(){
        _wireUrgent(it&&it.urgent);
        var _vti=box.querySelector('#vti');
        if(_vti)_vti.addEventListener('change',function(){
            // E2: Preservar valors existents
            var _prevCli=box.querySelector('#vc')?box.querySelector('#vc').value:'';
            var _prevFe=box.querySelector('#vfe')?box.querySelector('#vfe').value:'';
            var _prevFe2=box.querySelector('#vfe2')?box.querySelector('#vfe2').value:'';
            var _prevUsr=box.querySelector('#vusr')?box.querySelector('#vusr').value:'';
            var _fd=box.querySelector('#vtos-fields');
            if(_fd)_fd.innerHTML=_buildFields(this.value);
            // Restaurar valors
            var _nc=box.querySelector('#vc');if(_nc&&_prevCli)_nc.value=_prevCli;
            var _nf=box.querySelector('#vfe');if(_nf&&_prevFe)_nf.value=_prevFe;
            var _nf2=box.querySelector('#vfe2');if(_nf2&&_prevFe2)_nf2.value=_prevFe2;
            var _nu=box.querySelector('#vusr');if(_nu&&_prevUsr)_nu.value=_prevUsr;
            // E4: Tasca Rapida sub-opcions
            if(this.value==='TascaRapida'){
                var _trWrap=document.createElement('div');_trWrap.id='tr-wrap';_trWrap.style.cssText='margin-top:8px;padding:10px;background:rgba(220,0,40,.04);border:1px solid rgba(220,0,40,.15);border-radius:8px';
                _trWrap.innerHTML='<div class="vf"><label>Tipus Tasca</label><select id="vtr-tipo" style="background:var(--bg3);border:1.5px solid var(--br);border-radius:6px;padding:7px 10px;color:var(--t1);font-size:13px;font-family:inherit;width:100%"><option value="!!Anulacion ENPA:">!!Anulacion ENPA</option><option value="!!Defensa Cartera:">!!Defensa Cartera</option><option value="!!Llamar a Cliente:">!!Llamar a Cliente</option><option value="!!Retarificar:">!!Retarificar</option><option value="!!Enviar Docu:">!!Enviar Docu</option></select></div><div class="vf"><label>Detall</label><input id="vtr-detall" type="text" placeholder="Detalls addicionals..."></div><div style="font-size:9px;color:var(--t3);margin-top:4px">Assumpte = T\u00edtol + Client + Detall</div>';
                _fd.insertBefore(_trWrap,_fd.firstChild);
                // Auto-build assumpte
                function _updateTrAssumpte(){
                    var _va=box.querySelector('#va');
                    var _vc=box.querySelector('#vc');
                    var _tipo=box.querySelector('#vtr-tipo');
                    var _det=box.querySelector('#vtr-detall');
                    if(_va&&_tipo)_va.value=(_tipo.value||'')+' '+(_vc?_vc.value:'')+' '+(_det?_det.value:'');
                }
                setTimeout(function(){
                    var _trT=box.querySelector('#vtr-tipo');
                    var _trD=box.querySelector('#vtr-detall');
                    var _trC=box.querySelector('#vc');
                    if(_trT)_trT.addEventListener('change',_updateTrAssumpte);
                    if(_trD)_trD.addEventListener('input',_updateTrAssumpte);
                    if(_trC)_trC.addEventListener('input',_updateTrAssumpte);
                    _updateTrAssumpte();
                },20);
            }
            setTimeout(function(){_wireUrgent(false);},10);
        });
        var el=box.querySelector('#va');if(el)el.focus();
    },50);
}
window.openCRM = async function(mod, k, v) {
  try{
    var agPage = await fetch('/FE/ISC.Gaan.CRM.FE.Inicio/?_CIA=SCO');
    var agHtml = await agPage.text();
    var mm = agHtml.match(/name="_GAAN_ClientContext_"[^>]*value='([^']+)'/);
    if(!mm) mm = agHtml.match(/name="_GAAN_ClientContext_"[^>]*value="([^"]+)"/);
    if(!mm){alert('No s\'ha pogut obtenir el context del CRM');return;}
    var ctx = JSON.parse(mm[1].replace(/&quot;/g,'"').replace(/&amp;/g,'&'));

    var html;

    if(mod.indexOf('V360')>=0){
      var f = document.createElement('form');
      f.method='POST'; f.action='/FE/ISC.Gaan.CRM.FE.Inicio/'; f.target='_v360win'; f.style.display='none';
      [{n:'_GAAN_Mensaje_Pantalla_',v:JSON.stringify({IdCliente:v,Url:'vercliente'})},
       {n:'_GAAN_Comando_',v:'vercliente'},
       {n:'_GAAN_ClientContext_',v:JSON.stringify(ctx)}
      ].forEach(function(fi){var i=document.createElement('input');i.type='hidden';i.name=fi.n;i.value=fi.v;f.appendChild(i);});
      document.body.appendChild(f);
      // Obrir en segon pla (finestra petita fora de pantalla)
      var v360win = window.open('','_v360win','width=1,height=1,left=-9999,top=-9999');
      f.submit();
      setTimeout(function(){try{document.body.removeChild(f);}catch(e){}},300);
      // Tancar als 2.5 segons
      setTimeout(function(){try{if(v360win&&!v360win.closed)v360win.close();}catch(e){}}, 2500);
      return;
    }
      var cmd = mod.indexOf('Oportunidad')>=0 ? 'veropor' : 'veract';
      var msg = mod.indexOf('Oportunidad')>=0
        ? {IdOportunidad:v, Url:'veropor'}
        : {IdActividad:v, Url:'veract'};
      var r = await fetch('/FE/ISC.Gaan.CRM.FE.Inicio/', {
        method:'POST',
        headers:{'Content-Type':'application/x-www-form-urlencoded'},
        body: new URLSearchParams({
          '_GAAN_Mensaje_Pantalla_': JSON.stringify(msg),
          '_GAAN_Comando_': cmd,
          '_GAAN_ClientContext_': JSON.stringify(ctx)
        }).toString()
      });
      if(!r.ok){alert('Error '+r.status);return;}
      html = await r.text();

    var base = '<base href="https://grupoaplicaciones.gco.global/">';
    html = html.replace('<head>', '<head>'+base);
    var win = window.open('','_blank');
    win.document.open(); win.document.write(html); win.document.close();
  }catch(e){
    console.error('openCRM:',e); alert('Error: '+e.message);
  }
};
window.showImportRpt=function showImportRpt(){var log=S.importLog||[];var acts=log.filter(function(x){return x.t==='act';});var opos=log.filter(function(x){return x.t==='opo';});var byUser={};UIDS.forEach(function(uid){byUser[uid]={acts:0,opos:0,types:{}};});log.forEach(function(x){var b=byUser[x.uid]||(byUser[x.uid]={acts:0,opos:0,types:{}});if(x.t==='act')b.acts++;else b.opos++;b.types[x.ta]=(b.types[x.ta]||0)+1;});var ov=document.createElement('div');ov.style.cssText='position:absolute;inset:0;background:rgba(0,0,0,.85);display:flex;align-items:flex-start;justify-content:center;z-index:10;overflow-y:auto;padding:24px 16px;';var box=document.createElement('div');box.style.cssText='background:var(--bg2);border:1px solid var(--brl);border-radius:14px;padding:24px;max-width:700px;width:100%;font-size:12px;line-height:1.5;';var h='<div style="font-weight:700;font-size:15px;margin-bottom:4px;color:var(--t1);font-family:inherit">📊 Informe d\'importació — Agenda v8</div>';h+='<div style="color:var(--t3);font-size:11px;margin-bottom:16px;font-family:inherit">'+new Date().toLocaleString('ca-ES')+'</div>';h+='<div style="display:flex;gap:12px;margin-bottom:20px;">';[['Activitats',acts.length,'#3B82F6'],['Oportunitats',opos.length,'#8B5CF6'],['Total',log.length,'#10B981']].forEach(function(c){h+='<div style="flex:1;background:var(--bg3);border-radius:8px;padding:12px;text-align:center;border:1px solid var(--br)"><div style="font-size:24px;font-weight:700;color:'+c[2]+'">'+c[1]+'</div><div style="color:var(--t3);font-size:11px;font-family:inherit">'+c[0]+'</div></div>';});h+='</div>';h+='<div style="font-weight:700;color:var(--t1);margin-bottom:8px;font-family:inherit;font-size:12px">Per usuari</div>';h+='<table style="width:100%;border-collapse:collapse;margin-bottom:20px;font-family:inherit">';h+='<tr style="color:var(--t3);border-bottom:1px solid var(--br);font-size:11px"><td style="padding:5px 8px">Usuari</td><td style="padding:5px 8px;text-align:center">Act.</td><td style="padding:5px 8px;text-align:center">Opos.</td><td style="padding:5px 8px;text-align:center">Total</td><td style="padding:5px 8px">Tipus (top 4)</td></tr>';UIDS.forEach(function(uid){var u=USERS[uid];var d=byUser[uid]||{acts:0,opos:0,types:{}};var top=Object.entries(d.types).sort(function(a,b){return b[1]-a[1];}).slice(0,4).map(function(e){return'<span style="background:var(--bg4);padding:1px 5px;border-radius:4px;margin-right:3px">'+e[0]+' <b>'+e[1]+'</b></span>';}).join('');h+='<tr style="border-bottom:1px solid var(--br)"><td style="padding:6px 8px"><span style="color:'+u.color+';font-weight:700;font-family:inherit">'+u.ini+'</span> <span style="color:var(--t1)">'+u.name+'</span></td><td style="padding:6px 8px;text-align:center;color:var(--t1);font-weight:700">'+d.acts+'</td><td style="padding:6px 8px;text-align:center;color:var(--t1);font-weight:700">'+d.opos+'</td><td style="padding:6px 8px;text-align:center;color:'+(d.acts+d.opos>0?u.color:'var(--t4)')+';font-weight:700">'+(d.acts+d.opos)+'</td><td style="padding:6px 8px;font-size:11px">'+top+'</td></tr>';});h+='</table>';h+='<div style="font-weight:700;color:var(--t1);margin-bottom:8px;font-family:inherit;font-size:12px">Detall complet <span style="color:var(--t3);font-weight:400">('+log.length+' registres'+(log.length>300?', mostrant 300':'')+' — IDs únics)</span></div>';h+='<div style="max-height:380px;overflow-y:auto;border:1px solid var(--br);border-radius:8px">';h+='<table style="width:100%;border-collapse:collapse;font-size:11px;font-family:monospace">';h+='<tr style="position:sticky;top:0;background:var(--bg3);color:var(--t3)"><td style="padding:4px 6px">T</td><td style="padding:4px 6px">Tipus act.</td><td style="padding:4px 6px">Usr</td><td style="padding:4px 6px">ID</td><td style="padding:4px 6px">Asumpte</td><td style="padding:4px 6px">Client</td></tr>';log.slice(0,300).forEach(function(x,i){var u=USERS[x.uid]||{ini:'?',color:'#888'};h+='<tr style="border-bottom:1px solid var(--br);background:'+(i%2?'transparent':'var(--bg3)')+'"><td style="padding:3px 6px;color:'+(x.t==='opo'?'#8B5CF6':'#3B82F6')+';font-weight:700">'+x.t.toUpperCase()+'</td><td style="padding:3px 6px;color:var(--t2)">'+x.ta+'</td><td style="padding:3px 6px;color:'+u.color+';font-weight:700">'+u.ini+'</td><td style="padding:3px 6px;color:var(--t4)">'+x.id+'</td><td style="padding:3px 6px;color:var(--t1)">'+esc(x.as).substring(0,45)+'</td><td style="padding:3px 6px;color:var(--t3)">'+esc(x.cl).substring(0,30)+'</td></tr>';});h+='</table></div>';box.innerHTML=h;var bC=document.createElement('button');bC.textContent='Tancar';bC.style.cssText='margin-top:16px;padding:7px 20px;background:#DC0028;color:#fff;border:none;border-radius:7px;cursor:pointer;font-family:inherit;font-size:12px;font-weight:600';bC.addEventListener('click',function(){ov.remove();});box.appendChild(bC);ov.appendChild(box);app.appendChild(ov);}
// ══════════════════════════════════════════════════════════════
// VISTA CLIENTS
// ══════════════════════════════════════════════════════════════
function buildClientMap(){
    var map={};
    S.all.forEach(function(a){
        if(!a.REFNUMPERS)return;
        var key=a.REFNUMPERS;
        if(!map[key])map[key]={ref:key,nom:a.CLIENTE||'—',oposOb:[],actsOb:[],mediadors:{},lastContact:''};
        var c=map[key];
        if(a.CLIENTE&&a.CLIENTE.length>c.nom.length)c.nom=a.CLIENTE;
        var uid=a._uid||a.UID_RACF||'M441819E';
        c.mediadors[uid]=true;
        var dt=(a.TIM_INICI||'').slice(0,10);
        if(dt>c.lastContact)c.lastContact=dt;
        if(a._isOpo&&gS(a)==='ab')c.oposOb.push(a);
        if(!a._isOpo&&gS(a)==='ab')c.actsOb.push(a);
    });
    return map;
}

// ─── M1+W2: Helpers per al mode blur (shadow DOM aware) ───
function _getBlurRoot(){
    // Prioritzem el #app dins el shadow root
    try { if(typeof SR!=='undefined' && SR.getElementById){var a=SR.getElementById('app');if(a)return a;} } catch(e){}
    return document.body;
}
function _getBlurScope(){
    // Scope on cercar elements: shadow root si existeix, sino document
    try { if(typeof SR!=='undefined' && SR.querySelectorAll) return SR; } catch(e){}
    return document;
}
function _clearCliBlur(){
    var cnt = _getBlurRoot(); if(!cnt) return;
    var scope = _getBlurScope();
    cnt.classList.remove('cli-blur-mode');
    scope.querySelectorAll('.cli-card.cli-active, .cli-related').forEach(function(el){
        el.classList.remove('cli-active');
        el.classList.remove('cli-related');
    });
    window._cliActiveRef = null;
}
function _toggleCliBlur(cardEl, cliRef){
    var cnt = _getBlurRoot(); if(!cnt) return;
    var scope = _getBlurScope();
    var alreadyActive = cardEl.classList.contains('cli-active');
    // Sempre netejar abans
    scope.querySelectorAll('.cli-card.cli-active, .cli-related').forEach(function(el){
        el.classList.remove('cli-active');
        el.classList.remove('cli-related');
    });
    if(alreadyActive){
        cnt.classList.remove('cli-blur-mode');
        window._cliActiveRef = null;
        return;
    }
    cnt.classList.add('cli-blur-mode');
    cardEl.classList.add('cli-active');
    window._cliActiveRef = cliRef;
    // Marcar elements relacionats per data-cli-ref
    scope.querySelectorAll('[data-cli-ref="'+cliRef+'"]').forEach(function(el){
        if(el !== cardEl) el.classList.add('cli-related');
    });
}

function rClients(){
    var map=buildClientMap();
    var list=Object.values(map);
    var sq=(S.clSq||'').toLowerCase();
    if(sq)list=list.filter(function(c){return(c.nom+c.ref).toLowerCase().includes(sq);});
    // Cerca: incloure tots els clients quan hi ha sq actiu
    if(!sq) list=list.filter(function(c){return Object.keys(c.mediadors).some(function(u){return S.aU.has(u);});});
    list.sort(function(a,b){if(b.oposOb.length!==a.oposOb.length)return b.oposOb.length-a.oposOb.length;return a.nom.localeCompare(b.nom);});

    var wrap=document.createElement('div');
    wrap.style.cssText='display:flex;flex-direction:column;height:100%;overflow:hidden';

    var cbarCnt=SR.getElementById('clibar-cnt');
    if(cbarCnt)cbarCnt.textContent=list.length+(list.length===1?' client':' clients')+(sq?' · "'+sq+'"':'');

    // ── CERCA ACTIVA: layout 5 columnes ───────────────────────────
    if(sq){
        // Cerca: sempre mostrar tots els usuaris
        var matchOpos=S.all.filter(function(a){
            if(!a._isOpo)return false;
            return((a.DESASUN||'')+(a.CLIENTE||'')).toLowerCase().includes(sq);
        });
        var matchActs=S.all.filter(function(a){
            if(a._isOpo)return false;
            return((a.DESASUN||'')+(a.CLIENTE||'')).toLowerCase().includes(sq);
        });

        // ── Grid 3 files × 3 columnes (DH/FK/SF × Clients/OPOs/Acts) ──
        var gridWrap=document.createElement('div');
        gridWrap.classList.add('cli-search-zone'); // HH.2: scope CSS blur només dins la zona del cercador
        gridWrap.style.cssText='flex:1;min-height:0;overflow:hidden;display:flex;flex-direction:column';

        // Capçalera de les 3 columnes
        var colHdr=document.createElement('div');
        colHdr.style.cssText='display:grid;grid-template-columns:200px 1fr 1fr 1fr 1fr 1fr;background:var(--bg2);border-bottom:2px solid var(--br);flex-shrink:0';
        colHdr.innerHTML='<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:var(--t3)">Usuari</div>'+
            '<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:#10B981;border-left:1px solid var(--br)">👥 Clients</div>'+
            '<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:#8B5CF6;border-left:1px solid var(--br)">💼 Oportunitats</div>'+
            '<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:#3B82F6;border-left:1px solid var(--br)">📋 Activitats</div>'+
            '<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:var(--t4);border-left:1px solid var(--br);opacity:.4">💳 Rebuts</div>'+
            '<div style="padding:8px 10px;font-size:9px;font-weight:800;letter-spacing:.8px;text-transform:uppercase;color:var(--t4);border-left:1px solid var(--br);opacity:.4">⚠️ Sinistres</div>';
        gridWrap.appendChild(colHdr);

        // 3 files d'usuari
        // Calcular total d'ítems per repartir espai proporcionalment
        var _totalItems=UIDS.reduce(function(acc,uid){
            var uO=matchOpos.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;}).length;
            var uA=matchActs.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;}).length;
            var uC=list.filter(function(c){var m=Object.keys(c.mediadors);return m.indexOf(uid)>=0&&!UIDS.filter(function(u2){return m.indexOf(u2)<m.indexOf(uid);}).length;}).length;
            return acc+(uO+uA+uC)||0;
        },0)||1;
        var rowsWrap=document.createElement('div');
        rowsWrap.style.cssText='flex:1;min-height:0;overflow-y:auto;display:flex;flex-direction:column';

        UIDS.forEach(function(uid, uidIdx){
            var u=USERS[uid];
            var uOpos=matchOpos.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;});
            var uActs=matchActs.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;});
            // Clients assignats a aquest usuari (ell és el primari)
            var uClients=list.filter(function(c){
                // El client és d'aquest usuari si és el primer de la llista de mediadors
                var meds=Object.keys(c.mediadors);
                return meds.indexOf(uid)>=0 && (meds[0]===uid || !UIDS.filter(function(u2){return meds.indexOf(u2)<meds.indexOf(uid);}).length);
            });

            var _uO2=matchOpos.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;}).length;
            var _uA2=matchActs.filter(function(a){return(a._uid||a.UID_RACF||'M441819E')===uid;}).length;
            var _uC2=list.filter(function(c){var m=Object.keys(c.mediadors);return m.indexOf(uid)>=0&&!UIDS.filter(function(u2){return m.indexOf(u2)<m.indexOf(uid);}).length;}).length;
            var _rowItems=_uO2+_uA2+_uC2||1;
            var _rowFlex=Math.max(1,Math.round((_rowItems/_totalItems)*10));
            var row=document.createElement('div');
            row.style.cssText='display:grid;grid-template-columns:200px 1fr 1fr 1fr 1fr 1fr;border-bottom:1px solid var(--br);flex-shrink:0;min-height:120px;max-height:300px;overflow:hidden';

            // Col 0: Etiqueta d'usuari
            var userCell=document.createElement('div');
            userCell.style.cssText='padding:10px;background:'+u.bg+';display:flex;align-items:flex-start;gap:7px;flex-shrink:0;border-right:2px solid '+u.color;
            userCell.innerHTML='<div style="width:26px;height:26px;border-radius:6px;background:'+u.color+';color:#fff;font-size:9px;font-weight:800;display:grid;place-items:center;flex-shrink:0">'+u.ini+'</div>'+
                '<div><div style="font-size:11px;font-weight:700;color:var(--t1);line-height:1.3">'+u.name+'</div>'+
                '<div style="font-size:9px;color:var(--t3);margin-top:2px">'+uClients.length+' cli · '+uOpos.length+' opo · '+uActs.length+' act</div></div>';
            row.appendChild(userCell);

            // Col 1: Clients
            var cliCell=document.createElement('div');
            cliCell.style.cssText='padding:6px;border-left:1px solid var(--br);display:flex;flex-direction:column;gap:3px;overflow-y:auto';
            if(!uClients.length){
                cliCell.innerHTML='<div style="font-size:10px;color:var(--t4);padding:8px 4px;text-align:center">—</div>';
            } else {
                uClients.slice(0,10).forEach(function(c){
                    var cc=document.createElement('div');
                    cc.style.cssText='background:var(--bg2);border:1px solid var(--br);border-radius:6px;padding:7px 9px;cursor:pointer;font-size:11px;font-weight:600;color:var(--t1);overflow:hidden;text-overflow:ellipsis;white-space:nowrap;transition:background .1s';
                    cc.onmouseenter=function(){this.style.background='var(--bg3)';};
                    cc.onmouseleave=function(){this.style.background='var(--bg2)';};
                    cc.textContent=c.nom;
                    cc.title=c.nom+' · '+c.ref;
                    // V2: cli-card al cercador per al blur M1
                    cc.classList.add('cli-card');
                    cc.dataset.cliRef=c.ref;
                    var _ccTm=null;
                    cc.addEventListener('click',function(e){
                        if(_ccTm){clearTimeout(_ccTm);_ccTm=null;}
                        _ccTm=setTimeout(function(){
                            _ccTm=null;
                            if(typeof _toggleCliBlur==='function')_toggleCliBlur(cc, c.ref);
                            else showClient(c.ref);
                        },260);
                    });
                    cc.addEventListener('dblclick',function(e){
                        if(_ccTm){clearTimeout(_ccTm);_ccTm=null;}
                        e.preventDefault();
                        // HH.3: garantir cli-active abans d'obrir modal perquè el blur persisteixi al tornar (pas 4)
                        if(!cc.classList.contains('cli-active') && typeof _toggleCliBlur==='function'){
                            _toggleCliBlur(cc, c.ref);
                        }
                        showClient(c.ref);
                    });
                    cliCell.appendChild(cc);
                });
                if(uClients.length>10){
                    var more=document.createElement('div');more.style.cssText='font-size:9px;color:var(--t4);text-align:center;padding:2px';more.textContent='+'+( uClients.length-10)+' més';cliCell.appendChild(more);
                }
            }
            row.appendChild(cliCell);

            // Helper targeta opo/act
            function makeCard(a){
                var ti=TYPES[gT(a)]||TYPES['Tarea'];
                var isOpo=a._isOpo||gT(a)==='Oportunidad';
                var dateVal=(a.TIM_INICI||'').slice(0,10);
                var ac=document.createElement('div');
                var _acSt=gS(a);
                ac.style.cssText='background:var(--bg2);border:1px solid var(--br);border-left:3px solid '+(isOpo?'#8B5CF6':ti.c)+';border-radius:6px;padding:6px 8px;cursor:pointer;transition:background .1s'+(_acSt!=='ab'?';opacity:0.35;filter:grayscale(60%)':'');
                if(a.REFNUMPERS) ac.dataset.cliRef=a.REFNUMPERS;
                ac.onmouseenter=function(){this.style.background='var(--bg3)';};
                ac.onmouseleave=function(){this.style.background='var(--bg2)';};
                ac.innerHTML='<div style="display:flex;align-items:center;gap:3px"><span style="font-size:10px;flex-shrink:0">'+(isOpo?'💼':ti.i)+'</span>'+
                    '<span style="font-size:10.5px;font-weight:600;color:var(--t1);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+esc(a.DESASUN||'—')+'</span>'+
                    '<span style="font-size:8.5px;color:var(--t4);flex-shrink:0;margin-left:3px;font-family:monospace">'+dateVal+'</span></div>'+
                    '<div style="font-size:9px;color:var(--t3);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+esc(a.CLIENTE||'')+'</div>';
                ac.addEventListener('click',function(e){if(e.ctrlKey||e.metaKey){e.preventDefault();_selToggle(a.IDACTIV);c.style.outline=_sel.has(a.IDACTIV)?'2px solid #8B5CF6':'';return;}showDetail(a.IDACTIV);});
                return ac;
            }

            // Col 2: OPOs
            var opoCell=document.createElement('div');
            opoCell.style.cssText='padding:6px;border-left:1px solid var(--br);display:flex;flex-direction:column;gap:3px;overflow-y:auto';
            if(!uOpos.length){
                opoCell.innerHTML='<div style="font-size:10px;color:var(--t4);padding:8px 4px;text-align:center">—</div>';
            } else {
                uOpos.slice(0,8).forEach(function(a){opoCell.appendChild(makeCard(a));});
                if(uOpos.length>8){var m=document.createElement('div');m.style.cssText='font-size:9px;color:var(--t4);text-align:center;padding:2px';m.textContent='+'+( uOpos.length-8)+' més';opoCell.appendChild(m);}
            }
            row.appendChild(opoCell);

            // Col 3: Activitats
            var actCell=document.createElement('div');
            actCell.style.cssText='padding:6px;border-left:1px solid var(--br);display:flex;flex-direction:column;gap:3px;overflow-y:auto';
            if(!uActs.length){
                actCell.innerHTML='<div style="font-size:10px;color:var(--t4);padding:8px 4px;text-align:center">—</div>';
            } else {
                uActs.slice(0,8).forEach(function(a){actCell.appendChild(makeCard(a));});
                if(uActs.length>8){var m2=document.createElement('div');m2.style.cssText='font-size:9px;color:var(--t4);text-align:center;padding:2px';m2.textContent='+'+( uActs.length-8)+' més';actCell.appendChild(m2);}
            }
            row.appendChild(actCell);

            // Col 4: Rebuts (desactivat)
            var rebCell=document.createElement('div');
            rebCell.style.cssText='padding:5px;border-left:1px solid var(--br);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px;opacity:.3;background:repeating-linear-gradient(45deg,transparent,transparent 8px,rgba(128,128,160,.04) 8px,rgba(128,128,160,.04) 9px);cursor:not-allowed';
            rebCell.innerHTML='<div style="font-size:20px">🔒</div><div style="font-size:9px;color:var(--t3);text-align:center;font-weight:600;letter-spacing:.3px">Properament</div>';
            row.appendChild(rebCell);
            // Col 5: Sinistres (desactivat)
            var sinCell=document.createElement('div');
            sinCell.style.cssText='padding:5px;border-left:1px solid var(--br);display:flex;flex-direction:column;align-items:center;justify-content:center;gap:6px;opacity:.3;background:repeating-linear-gradient(45deg,transparent,transparent 8px,rgba(128,128,160,.04) 8px,rgba(128,128,160,.04) 9px);cursor:not-allowed';
            sinCell.innerHTML='<div style="font-size:20px">🔒</div><div style="font-size:9px;color:var(--t3);text-align:center;font-weight:600;letter-spacing:.3px">Properament</div>';
            row.appendChild(sinCell);
            rowsWrap.appendChild(row);
        });
        gridWrap.appendChild(rowsWrap);
        wrap.appendChild(gridWrap);
        CNT.innerHTML='';CNT.appendChild(wrap);
        // HH.4: restaurar mode blur si hi havia un client actiu (cerca activa)
        try {
            if(window._cliActiveRef){
                var _activeRef = window._cliActiveRef;
                var _cardActive = gridWrap.querySelector('.cli-card[data-cli-ref="'+_activeRef+'"]');
                if(_cardActive && typeof _toggleCliBlur==='function'){
                    _toggleCliBlur(_cardActive, _activeRef);
                } else {
                    if(typeof _clearCliBlur==='function')_clearCliBlur();
                }
            }
        } catch(_e){}
        return;
    }

    // ── SENSE CERCA: llista normal ────────────────────────────────
    var listEl=document.createElement('div');
    listEl.style.cssText='flex:1;overflow-y:auto;padding:12px 14px;display:flex;flex-direction:column;gap:8px';

    // Ordenar: urgents primer, després per OPOs
    list.sort(function(a,b){
        var ua=gUrgCli(a.ref),ub=gUrgCli(b.ref);
        if(ua&&!ub)return -1;if(!ua&&ub)return 1;
        if(b.oposOb.length!==a.oposOb.length)return b.oposOb.length-a.oposOb.length;
        return a.nom.localeCompare(b.nom);
    });

    function buildCliCard(c){
        var card=document.createElement('div');
        var isUrg=gUrgCli(c.ref);
        card.className='cli-card';
        card.dataset.cliRef=c.ref;
        card.style.cssText='background:var(--bg2);border:1px solid '+(isUrg?'rgba(220,0,40,.4)':'var(--br)')+';border-radius:10px;padding:10px 14px;cursor:pointer;transition:all .12s;'+(isUrg?'background:rgba(220,0,40,.06);':'')+';display:grid;grid-template-columns:365px 1fr '+(isUrg?'28px':'0px')+' 80px;grid-template-rows:auto auto;gap:4px 8px;align-items:center';
        if(isUrg)card.classList.add('urg-pulse');
        card.onmouseenter=function(){this.style.borderColor=isUrg?'rgba(220,0,40,.7)':'var(--brl)';};
        card.onmouseleave=function(){this.style.borderColor=isUrg?'rgba(220,0,40,.4)':'var(--br)';};
        var medsH=Object.keys(c.mediadors).map(function(uid){
            var u=USERS[uid];if(!u)return'';
            return'<span style="display:inline-block;padding:1px 6px;border-radius:8px;font-size:9px;font-weight:700;background:'+u.bg+';color:'+u.color+'">'+u.ini+'</span>';
        }).join('');
        var lc=c.lastContact?c.lastContact.split('-').reverse().join('/'):'';
        var refNum=c.ref.split('/')[0];
        // Fila 1: Nom | OPOs | ⚠️ (rowspan 2 centrat) | ID
        // Fila 2: Mediadors | Acts | | Data
        card.innerHTML=
            // F1C1: Nom
            '<div style="grid-row:1;grid-column:1;font-size:12px;font-weight:700;color:var(--t1);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+esc(c.nom)+'</div>'+
            // F1C2: OPOs
            '<div style="grid-row:1;grid-column:2;display:flex;align-items:center;gap:4px">'+
            (c.oposOb.length?'<span style="font-size:9px;font-weight:700;color:#8B5CF6">💼 <b>'+c.oposOb.length+'</b> OPOs</span>':'<span style="font-size:9px;color:var(--t4)">💼 0</span>')+
            '</div>'+
            // F1C3+F2C3: Icona urgent centrada entre files (rowspan 2)
            (isUrg?'<div style="grid-row:1/3;grid-column:3;display:flex;align-items:center;justify-content:center;font-size:20px">⚠️</div>':'<div style="grid-row:1/3;grid-column:3"></div>')+
            // F1C4: ID
            '<div style="grid-row:1;grid-column:4;text-align:right;font-size:9px;color:var(--t3);font-family:monospace;background:var(--bg3);border:1px solid var(--br);border-radius:3px;padding:1px 5px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+refNum+'</div>'+
            // F2C1: Mediadors
            '<div style="grid-row:2;grid-column:1;display:flex;gap:3px;flex-wrap:wrap">'+medsH+'</div>'+
            // F2C2: Activitats
            '<div style="grid-row:2;grid-column:2;display:flex;align-items:center;gap:4px">'+
            (c.actsOb.length?'<span style="font-size:9px;font-weight:700;color:#3B82F6">📋 <b>'+c.actsOb.length+'</b> act.</span>':'<span style="font-size:9px;color:var(--t4)">📋 0</span>')+
            '</div>'+
            // F2C4: Data
            (lc?'<div style="grid-row:2;grid-column:4;text-align:right;font-size:8px;color:var(--t4)">'+lc+'</div>':'<div style="grid-row:2;grid-column:4"></div>');
        card.addEventListener('click',function(e){
            if(e.ctrlKey||e.metaKey){e.preventDefault();_selToggle(c.ref);card.style.outline=_sel.has(c.ref)?'2px solid #8B5CF6':'';return;}
            // Si la card ja és activa al mode blur → toggle off (treure blur de tots)
            if(card.classList.contains('cli-active')){
                if(typeof _clearCliBlur==='function')_clearCliBlur();
                return;
            }
            // W1: vista tots clients → single click obre modal directament (sense blur)
            showClient(c.ref);
        });
        return card;
    }

    if(list.length===0){
        listEl.innerHTML='<div style="text-align:center;padding:60px;color:var(--t3)"><div style="font-size:32px;margin-bottom:10px">👥</div><div>Cap client trobat</div></div>';
    } else {
        // 3 columnes per mediador: DH | FK | SF
        var _colMap={'M441819E':0,'M354046Y':1,'MA44658D':2}; // DH | FK | SF
        var col1=document.createElement('div');
        col1.style.cssText='flex:1;display:flex;flex-direction:column;gap:6px';
        col1.innerHTML='<div style="font-size:9px;font-weight:800;color:'+USERS['M441819E'].color+';text-transform:uppercase;letter-spacing:.8px;padding:4px 8px;background:'+USERS['M441819E'].bg+';border-radius:6px;text-align:center;margin-bottom:2px">DH · '+USERS['M441819E'].ini+'</div>';
        var col2=document.createElement('div');
        col2.style.cssText='flex:1;display:flex;flex-direction:column;gap:6px';
        col2.innerHTML='<div style="font-size:9px;font-weight:800;color:'+USERS['M354046Y'].color+';text-transform:uppercase;letter-spacing:.8px;padding:4px 8px;background:'+USERS['M354046Y'].bg+';border-radius:6px;text-align:center;margin-bottom:2px">FK · '+USERS['M354046Y'].ini+'</div>';
        var col3=document.createElement('div');
        col3.style.cssText='flex:1;display:flex;flex-direction:column;gap:6px';
        col3.innerHTML='<div style="font-size:9px;font-weight:800;color:'+USERS['MA44658D'].color+';text-transform:uppercase;letter-spacing:.8px;padding:4px 8px;background:'+USERS['MA44658D'].bg+';border-radius:6px;text-align:center;margin-bottom:2px">SF · '+USERS['MA44658D'].ini+'</div>';
        var grid2=document.createElement('div');grid2.style.cssText='display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;padding:10px';
        // Repartir clients per mediador principal
        list.forEach(function(c){
            var meds=Object.keys(c.mediadors);
            // Mediador principal: el primer de la llista que sigui del nostre equip
            var mainMed=meds.find(function(uid){return _colMap.hasOwnProperty(uid);});
            var colIdx=mainMed!==undefined?_colMap[mainMed]:0;
            ([col1,col2,col3])[colIdx].appendChild(buildCliCard(c));
        });
        grid2.appendChild(col1);grid2.appendChild(col2);grid2.appendChild(col3);
        listEl.appendChild(grid2);
    }
    wrap.appendChild(listEl);
    CNT.innerHTML='';CNT.appendChild(wrap);
    // Restaurar mode blur si hi havia un client actiu abans del re-render
    try {
        if(window._cliActiveRef){
            var _activeRef = window._cliActiveRef;
            var _cardActive = listEl.querySelector('.cli-card[data-cli-ref="'+_activeRef+'"]');
            if(_cardActive && typeof _toggleCliBlur==='function'){
                // toggleCliBlur el deixarà actiu (la card està neta de classes)
                _toggleCliBlur(_cardActive, _activeRef);
            } else {
                // Card no trobada (filtrat o eliminat) → netejar estat
                if(typeof _clearCliBlur==='function')_clearCliBlur();
            }
        }
    } catch(_e){}
}

// ─── Cache mapatge numpers → NIF per fer preview del cli_<NIF>.json al OD ───
function _cliGetNifForNumpers(numpers) {
    try {
        var raw = localStorage.getItem('oa_cli_numpers_nif') || '{}';
        var map = JSON.parse(raw);
        return map[numpers] || null;
    } catch(e) { return null; }
}
function _cliSaveNifForNumpers(numpers, nif) {
    if (!numpers || !nif) return;
    try {
        var raw = localStorage.getItem('oa_cli_numpers_nif') || '{}';
        var map = JSON.parse(raw);
        if (map[numpers] === nif) return; // res a fer
        map[numpers] = nif;
        localStorage.setItem('oa_cli_numpers_nif', JSON.stringify(map));
    } catch(e) { console.warn('[_cliSaveNifForNumpers]', e); }
}

// Mapejar JSON de l'alta-cliente (formulari) al format que renderClientData espera
function _mapODtoClientData(od) {
    if (!od || typeof od !== 'object') return null;
    var nif = (od.nif_cif || od.par_nif || od.aut_nif || od.emp_cif || '').trim();
    var tel = od.par_telefono || od.aut_telefono || od.emp_telefono || '';
    var email = od.par_email || od.aut_email || od.emp_email || '';
    var adreca = od.par_direccion || od.aut_direccion || od.emp_direccion || '';
    var fnac = od.par_fnac || od.aut_fnac || '';
    return {
        nif: nif || null,
        telefon: tel || null,
        telefons: tel ? [tel] : [],
        email: email || null,
        adreca: adreca || null,
        fnaixement: fnac || null,
        // Camps que NO tenim al cache OD (venen del CRM)
        professio: null, idioma: null, mediador: null,
        eclient: null, occidentActiva: null, rgpd: null,
        antiguitat: null, totalProductes: null, totalPrimes: null,
        polisses: [], rebuts: [], sinistres: [],
        _odPreview: true // flag per saber que és preview
    };
}

// Desar dades CRM al OD com a cli_crm_<NIF>.json (no sobreescriu el format formulari)
// Background: cridat des de _onResult; no esperem resultat.
function _saveCRMtoOD(crmData) {
    try {
        if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) return;
        if (!crmData || !crmData.nif) return;
        var nif = String(crmData.nif).replace(/[^A-Za-z0-9]/g,'').toUpperCase();
        if (!nif) return;
        var fname = 'cli_crm_' + nif + '.json';
        // Afegim metadades de timestamp
        var payload = Object.assign({}, crmData, { _crmSavedAt: Date.now() });
        OD.saveFile(fname, payload).then(function(ok){
            if (ok) console.log('[CRM→OD] OK:', fname);
            else console.warn('[CRM→OD] saveFile retorna false:', fname);
        }).catch(function(err){
            console.warn('[CRM→OD] error:', err);
        });
    } catch(e) {
        console.warn('[CRM→OD] exception:', e);
    }
}

// Fusió OD + CRM: el CRM té prioritat per cada camp no-buit
function _mergeClientData(odData, crmData) {
    if (!odData) return crmData;
    if (!crmData) return odData;
    var out = {};
    var keys = Object.keys(odData).concat(Object.keys(crmData));
    var seen = {};
    keys.forEach(function(k){
        if (seen[k]) return;
        seen[k] = 1;
        var c = crmData[k];
        var o = odData[k];
        // CRM és prioritari si té valor no-buit (no null/undefined/'' i no array buit)
        var crmHasValue = (c !== null && c !== undefined && c !== '' &&
                           !(Array.isArray(c) && c.length === 0));
        out[k] = crmHasValue ? c : o;
    });
    out._odPreview = false;
    return out;
}

// ── Carrega dades Occident: iframe visible + injecció quan carregat ─────────────
async function _loadInteropData(container, refnumpers, clientName) {
    var refPts = (refnumpers || '').split('/');
    var numpers = refPts[0] || '';
    var refpers = refPts[1] || '000';
    var v360Url = 'https://catalanaaplicaciones.gco.global/FE/PER.Clientes.Menu.FE.Busqueda/?_CIA=SCO&NUMPERS='+encodeURIComponent(numpers)+'&REFPERS='+encodeURIComponent(refpers)+'&ORIGEN=PER&_t='+Date.now();

    // ── iframe ocult (necessari per postMessage d'extracció) ──
    container.innerHTML = '';

    // iframe off-screen (no visible): necessari per al postMessage d'extracció
    var _ifr = document.createElement('iframe');
    _ifr.id = '_iop_ifr';
    _ifr.src = v360Url;
    _ifr.style.cssText = 'position:fixed;width:1px;height:1px;left:-9999px;top:-9999px;border:none;opacity:0;pointer-events:none';
    document.body.appendChild(_ifr);

    // ── Pas 2: Quan iframe carregat → injectar via extensió ──────────────────
    var _extracted = false;
    var _loadCount = 0;
    // ── Preview OD: si tenim NIF associat al numpers, mostrar dades cache mentre carrega l'iframe
    var _odPreviewData = null; // dades preview (formulari mapejat o CRM directe)
    (async function _tryODPreview(){
        try {
            if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) return;
            var nif = _cliGetNifForNumpers(numpers);
            if (!nif) return;
            // 1r intent: cli_<NIF>.json (formulari, format alta-clientes)
            try {
                var formJson = await OD.loadFile('cli_' + nif + '.json');
                if (_extracted) return;
                if (formJson) {
                    var mapped = _mapODtoClientData(formJson);
                    if (mapped) {
                        _odPreviewData = mapped;
                        renderClientData(container, mapped, numpers);
                        container.dispatchEvent(new CustomEvent('_opticrm_rendered'));
                        return;
                    }
                }
            } catch(eForm) { console.warn('[OD preview form]', eForm); }
            // 2n intent (fallback): cli_crm_<NIF>.json (CRM, format ja compatible)
            try {
                var crmCacheJson = await OD.loadFile('cli_crm_' + nif + '.json');
                if (_extracted) return;
                if (crmCacheJson) {
                    _odPreviewData = crmCacheJson; // ja en format CRM
                    renderClientData(container, crmCacheJson, numpers);
                    container.dispatchEvent(new CustomEvent('_opticrm_rendered'));
                }
            } catch(eCrm) { console.warn('[OD preview crm]', eCrm); }
        } catch(e) { console.warn('[OD preview] try-catch:', e); }
    })();

    function _tryExtract() {
        if (_extracted) return;
        window.postMessage({
            type: '_opticrm_req_v360_iframe',
            numpers: numpers,
            clientName: clientName || '',
            _opticrm: true
        }, '*');
    }

    // Listener per la resposta (isolated→main via CustomEvent ✅)
    function _onResult(e) {
        if (_extracted) return;
        var resp = e.detail;
        if (resp && resp.ok && resp.data &&
            (resp.data.nif || resp.data.email || resp.data.telefon ||
             (resp.data.polisses && resp.data.polisses.length > 0))) {
            _extracted = true;
            window.removeEventListener('_opticrm_res_v360_data', _onResult);
            // Desar numpers → NIF al cache (per a previews futurs)
            if (resp.data.nif) _cliSaveNifForNumpers(numpers, resp.data.nif);
            // Desar dades CRM al OD en background (per omplir cache automàticament)
            _saveCRMtoOD(resp.data);
            // Fusionar amb el preview OD si en tenim (CRM prevaleix per cada camp)
            var finalData = _odPreviewData
                ? _mergeClientData(_odPreviewData, resp.data)
                : resp.data;
            // Substituir iframe per card estructurada
            renderClientData(container, finalData, numpers);
            // Notificar que el card pot expandir-se
            try { _ifr.remove(); } catch(e2) {}
            container.dispatchEvent(new CustomEvent('_opticrm_rendered'));
        } else if (resp && !resp.ok) {
            // Fallback silenciós (mantenim el preview OD si en hi ha)
            try { _ifr.remove(); } catch(e2) {}
            if (!_odPreviewData) container.dispatchEvent(new CustomEvent('_opticrm_rendered'));
        }
    }
    window.addEventListener('_opticrm_res_v360_data', _onResult);

    // onload: pot disparar 2+ vegades per redireccions
    _ifr.addEventListener('load', function() {
        _loadCount++;
        // Esperar que s'estabilitzi (300ms sense nous loads)
        clearTimeout(_ifr._loadTimer);
        _ifr._loadTimer = setTimeout(_tryExtract, 500);
    });

    // Timeout final: si no respon en 15s, silenciar el spinner
    setTimeout(function() {
        window.removeEventListener('_opticrm_res_v360_data', _onResult);
        if (!_extracted) {
            try { _ifr.remove(); } catch(e2) {}
            container.dispatchEvent(new CustomEvent('_opticrm_rendered'));
        }
    }, 15000);
}


// ═══════════════════════════════════════════════════════════════════════
// SYNC SILENCIÓS CLIENTS — Job background per enriquir cli_crm_<NIF>.json
// 
// Aprofita _loadInteropData (que ja existeix) per fer fetch silenciós de
// telèfon/email de cada client de S.all i desar-ho al OD. Després construeix
// un índex lleuger `opticrm-clients-index.json` que el formulari llegirà.
//
// Estratègia:
// - Watcher cada 30s comprova si pot iniciar (S.all i OD ready)
// - Quan inicia: primer tick als 5s, després cada 30 min
// - Per tick: max 25 clients sense enriquir, rate-limited 2s/client
// - Index complet construit a cada tick a partir de S.all + cli_crm_*.json
// 
// 2026-05-18 — Fase 2 cercador refactor
// ═══════════════════════════════════════════════════════════════════════

var _SYNC_CLIENTS_INTERVAL = 30 * 60 * 1000;  // 30 min entre cicles
var _SYNC_BATCH_RATE_MS = 2000;               // 2s entre fetches (conservador)
var _SYNC_BATCH_MAX = 25;                     // max 25 clients enriquits per cicle
var _SYNC_INDEX_FILE = 'opticrm-clients-index.json';
var _SYNC_STALE_MS = 30 * 24 * 3600 * 1000;   // re-enriquir si >30 dies

var _clientsIndex = null;        // { refnumpers: {nom, nif, refnumpers, tel1, email1, _enrichedAt} }
var _clientsIndexLoaded = false;
var _syncClientsRunning = false;

// Carregar índex existent del OD (una vegada per sessió)
async function _loadClientsIndexFromOD() {
    if (_clientsIndexLoaded) return _clientsIndex;
    try {
        if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) {
            _clientsIndex = {}; _clientsIndexLoaded = true; return _clientsIndex;
        }
        var data = await OD.loadFile(_SYNC_INDEX_FILE);
        if (data && data.clients && typeof data.clients === 'object') {
            _clientsIndex = data.clients;
            console.log('[sync-clients] Índex carregat del OD:', Object.keys(_clientsIndex).length, 'clients');
        } else {
            _clientsIndex = {};
        }
    } catch(e) {
        console.warn('[sync-clients] Error carregant índex:', e);
        _clientsIndex = {};
    }
    _clientsIndexLoaded = true;
    return _clientsIndex;
}

// Desar índex al OD
async function _saveClientsIndexToOD() {
    if (!_clientsIndex) return false;
    try {
        if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) return false;
        var keys = Object.keys(_clientsIndex);
        var payload = {
            version: 1,
            generated_at: new Date().toISOString(),
            count: keys.length,
            clients: _clientsIndex
        };
        var ok = await OD.saveFile(_SYNC_INDEX_FILE, payload);
        if (ok) console.log('[sync-clients] Índex desat al OD:', keys.length, 'clients');
        return ok;
    } catch(e) {
        console.warn('[sync-clients] Error desant índex:', e);
        return false;
    }
}

// Build base index a partir de S.all (sense fetch — només noms/refs/NIF cached)
function _buildBaseClientsIndex() {
    if (!_clientsIndex) _clientsIndex = {};
    if (!S || !S.all) return { added: 0, updated: 0 };
    var stats = { added: 0, updated: 0 };
    var seen = {};
    S.all.forEach(function(a) {
        if (!a.REFNUMPERS) return;
        if (seen[a.REFNUMPERS]) return;
        seen[a.REFNUMPERS] = true;
        var refnumpers = a.REFNUMPERS;
        var numpers = refnumpers.split('/')[0];
        var nifCached = _cliGetNifForNumpers(numpers);
        var nameNew = a.CLIENTE || '';
        var existing = _clientsIndex[refnumpers];
        if (existing) {
            if (nameNew.length > (existing.nom || '').length) {
                existing.nom = nameNew; stats.updated++;
            }
            if (nifCached && !existing.nif) {
                existing.nif = nifCached; stats.updated++;
            }
        } else {
            _clientsIndex[refnumpers] = {
                refnumpers: refnumpers,
                nom: nameNew,
                nif: nifCached || '',
                tel1: '',
                email1: '',
                _enrichedAt: 0
            };
            stats.added++;
        }
    });
    return stats;
}

// Versió silenciosa de _loadInteropData: només extreu i desa, sense renderitzar
function _loadInteropDataSilent(refnumpers, clientName) {
    return new Promise(function(resolve) {
        var refPts = (refnumpers || '').split('/');
        var numpers = refPts[0] || '';
        var refpers = refPts[1] || '000';
        if (!numpers) { resolve(null); return; }

        var v360Url = 'https://catalanaaplicaciones.gco.global/FE/PER.Clientes.Menu.FE.Busqueda/?_CIA=SCO&NUMPERS=' + encodeURIComponent(numpers) + '&REFPERS=' + encodeURIComponent(refpers) + '&ORIGEN=PER&_t=' + Date.now();

        var _ifr = document.createElement('iframe');
        _ifr.style.cssText = 'position:fixed;width:1px;height:1px;left:-9999px;top:-9999px;border:none;opacity:0;pointer-events:none';
        _ifr.src = v360Url;
        document.body.appendChild(_ifr);

        var _done = false;
        var cleanup = function(data) {
            if (_done) return;
            _done = true;
            try { window.removeEventListener('_opticrm_res_v360_data', _onResult); } catch(e) {}
            try { _ifr.remove(); } catch(e) {}
            resolve(data);
        };

        function _onResult(e) {
            if (_done) return;
            var resp = e.detail;
            if (resp && resp.ok && resp.data && resp.data.nif) {
                if (resp.data.nif) _cliSaveNifForNumpers(numpers, resp.data.nif);
                _saveCRMtoOD(resp.data);   // desa cli_crm_<NIF>.json automàticament
                cleanup(resp.data);
            } else if (resp && !resp.ok) {
                cleanup(null);
            }
        }
        window.addEventListener('_opticrm_res_v360_data', _onResult);

        _ifr.addEventListener('load', function() {
            // Esperar 600ms perquè el iframe estabilitzi després de la càrrega
            setTimeout(function() {
                if (_done) return;
                try {
                    window.postMessage({
                        type: '_opticrm_req_v360_iframe',
                        numpers: numpers,
                        clientName: clientName || '',
                        _opticrm: true
                    }, '*');
                } catch(e) { cleanup(null); }
            }, 600);
        });

        // Timeout 12s — si no respon, descartar
        setTimeout(function() { cleanup(null); }, 12000);
    });
}

// Tick del background job: build index + enrich N clients
async function _syncClientsTick() {
    if (_syncClientsRunning) {
        console.log('[sync-clients] tick: ja en execució, skip');
        return;
    }
    _syncClientsRunning = true;
    try {
        if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) return;
        if (!S || !S.all || S.all.length === 0) return;

        // 1. Carregar índex (una vegada)
        await _loadClientsIndexFromOD();

        // 2. Build base a partir de S.all
        var stats = _buildBaseClientsIndex();
        var total = Object.keys(_clientsIndex).length;
        console.log('[sync-clients] Base index:', total, '(+'+stats.added+' nous, '+stats.updated+' actualitzats)');

        // 3. Candidats a enriquir: sense tel/email, o stale
        var nowTs = Date.now();
        var candidates = [];
        for (var k in _clientsIndex) {
            var c = _clientsIndex[k];
            var hasContact = (c.tel1 && c.tel1.length > 0) || (c.email1 && c.email1.length > 0);
            var isStale = (nowTs - (c._enrichedAt || 0)) > _SYNC_STALE_MS;
            if (!hasContact || isStale) candidates.push(c);
        }
        // Ordenar: primer els que mai s'han intentat (_enrichedAt=0), després per data
        candidates.sort(function(a,b){ return (a._enrichedAt||0) - (b._enrichedAt||0); });
        var batch = candidates.slice(0, _SYNC_BATCH_MAX);
        console.log('[sync-clients] Enriquint '+batch.length+' / '+candidates.length+' candidates pendents');

        // 4. Per cada client, fetch silenciós amb rate limit
        var enrichedCount = 0;
        for (var i = 0; i < batch.length; i++) {
            var cli = batch[i];
            try {
                var data = await _loadInteropDataSilent(cli.refnumpers, cli.nom);
                if (data) {
                    if (data.nif) cli.nif = data.nif;
                    if (data.telefon) cli.tel1 = String(data.telefon);
                    if (data.email) cli.email1 = String(data.email);
                    enrichedCount++;
                }
                // Marcar com a intentat (encara que hagi fallat, per no retry immediatament)
                cli._enrichedAt = Date.now();
            } catch(e) {
                console.warn('[sync-clients] error enrich '+cli.refnumpers+':', e);
                cli._enrichedAt = Date.now();
            }
            // Rate limit entre fetches
            if (i < batch.length - 1) {
                await new Promise(function(r){ setTimeout(r, _SYNC_BATCH_RATE_MS); });
            }
        }
        console.log('[sync-clients] Tick OK: enriquits '+enrichedCount+'/'+batch.length+' (queden ~'+(candidates.length-batch.length)+' pendents)');

        // 5. Desar índex actualitzat
        await _saveClientsIndexToOD();
    } catch(e) {
        console.warn('[sync-clients] tick error:', e);
    } finally {
        _syncClientsRunning = false;
    }
}

// Watcher: cada 30s comprova si pot iniciar el job. Quan inicia, es desactiva.
(function() {
    var _watcher = setInterval(function() {
        if (window._clientsSyncStarted) {
            clearInterval(_watcher);
            return;
        }
        if (typeof OD === 'undefined' || !OD.isReady || !OD.isReady()) return;
        if (!S || !S.all || S.all.length === 0) return;
        // Tot ready → iniciar
        window._clientsSyncStarted = true;
        clearInterval(_watcher);
        console.log('[sync-clients] Background job iniciat — primer tick en 5s, després cada 30 min');
        setTimeout(_syncClientsTick, 5000);
        setInterval(_syncClientsTick, _SYNC_CLIENTS_INTERVAL);
    }, 30000);  // check cada 30s
})();

// Exposar per debug
try {
    window._opticrmClientsSync = {
        tick: _syncClientsTick,
        getIndex: function(){ return _clientsIndex; },
        save: _saveClientsIndexToOD,
        load: _loadClientsIndexFromOD,
        config: {
            interval: _SYNC_CLIENTS_INTERVAL,
            batchMax: _SYNC_BATCH_MAX,
            rateMs: _SYNC_BATCH_RATE_MS
        }
    };
} catch(e) {}

