// ── Renderitza les dades extretes en cards ─────────────────────────────────
function renderClientData(container, d, numpers) {
    // Helper: row label + value com a Gestiona original
    function lv(label, val, isHtml) {
        var v = val ? String(val).trim() : '';
        var vHtml = isHtml ? v : (v ? esc(v) : '');
        return '<div style="display:flex;align-items:baseline;padding:3px 0;min-height:24px">' +
            '<div style="font-size:11px;color:var(--t2);width:150px;flex-shrink:0;font-weight:500">'+esc(label)+'</div>' +
            '<div style="font-size:11.5px;color:'+(v?'var(--t1)':'var(--t3)')+'">'+vHtml+'</div>' +
            '</div>';
    }

    // Clean mediador: deduplica i treu comes finals
    var med = '';
    if (d.mediador) {
        var seen2 = {}, uniq2 = [];
        d.mediador.split(/OPTIMIZARTE|,/).forEach(function(p){
            var t = p.trim().replace(/[,;]+$/,'').trim();
            if (t && !seen2[t.toLowerCase()]) { seen2[t.toLowerCase()]=1; uniq2.push(t); }
        });
        // Si no va funcionar, agafar el primer tros fins a coma/punt i coma
        if (!uniq2.length) {
            med = d.mediador.split(/[,;]/)[0].trim();
        } else {
            // Reconstruir amb el prefix si calia
            med = uniq2[0].indexOf('OPTIMIZARTE') < 0 && d.mediador.indexOf('OPTIMIZARTE') >= 0
                ? 'OPTIMIZARTE ' + uniq2[0] : uniq2[0];
        }
        if (!med) med = d.mediador.split(',')[0].trim().replace(/\.+$/,'');
    }

    // Primer telèfon únicament
    var tel = '';
    if (d.telefons && d.telefons.length > 0) tel = d.telefons[0];
    else if (d.telefon) tel = d.telefon;

    // Email com a link
    var emailHtml = d.email
        ? '<a href="mailto:'+esc(d.email)+'" style="color:#3B82F6;text-decoration:none">'+esc(d.email)+'</a>'
        : '';

    // (RGPD html es construeix amb l'alert check més avall)

    // Meta: productes + primes
    var metaHtml = '';
    var mParts = [];
    if (d.totalProductes) mParts.push('<span style="color:var(--t2)">'+d.totalProductes+' productes</span>');
    if (d.totalPrimes) mParts.push('<span style="color:#10B981;font-weight:700">'+esc(d.totalPrimes)+' en primes</span>');
    if (mParts.length) {
        metaHtml = '<div style="padding:6px 12px;border-bottom:1px solid var(--br);font-size:10px;display:flex;gap:8px;align-items:center;flex-wrap:wrap">'+
            mParts.join('<span style="color:var(--brl)"> · </span>')+'</div>';
    }

    // Pulse animation CSS (Shadow DOM)
    (function(){
        var _root = container.getRootNode && container.getRootNode();
        if (_root && !_root.getElementById && _root.querySelector) { /* skip */ }
        else if (_root && !_root.getElementById('_ocrm_alert_css')) {
            var _s=document.createElement('style');_s.id='_ocrm_alert_css';
            _s.textContent='@keyframes _ocrm_pulse{0%,100%{opacity:1}40%,60%{opacity:.08}}._ocrm_alert{color:#ff0000!important;animation:_ocrm_pulse 3s ease-in-out infinite;font-weight:700!important;display:inline-block}';
            _root.appendChild(_s);
        }
    })();

    // Telèfon clickable → Teams
    var telHtml = '';
    if (tel) {
        var _cleanTel = tel.replace(/\s/g,'');
        var _teamsUrl = 'msteams://l/call/0/0?users=4:' + encodeURIComponent(_cleanTel);
        telHtml = '<a href="'+esc(_teamsUrl)+'" title="Trucar per Teams" style="color:#464EB8;text-decoration:none;font-weight:600">'+esc(tel)+'</a>';
    }

    // e-cliente alert
    var _eclientAlert = (d.eclient||'').toLowerCase()==='no';
    var eclientHtml = _eclientAlert
        ? '<span class="_ocrm_alert">'+esc(d.eclient)+'</span>'
        : (d.eclient ? esc(d.eclient) : '');

    // RGPD alert
    // Normalitzar valors RGPD en majúscules (CRM retorna 'NO'/'SI')
    var _rgpdNorm = d.rgpd ? (d.rgpd==='NO'?'No':d.rgpd==='SI'?'Sí':d.rgpd==='YES'?'Sí':d.rgpd) : '';
    var _rgpdAlert = _rgpdNorm && (_rgpdNorm.toLowerCase()==='no' || _rgpdNorm.toLowerCase().indexOf('sol')>=0 || _rgpdNorm.toLowerCase().indexOf('consent')>=0);
    var rgpdAlertHtml = _rgpdAlert
        ? '<span class="_ocrm_alert">'+esc(_rgpdNorm)+'</span>'
        : (_rgpdNorm ? esc(_rgpdNorm) : '');

    // Columna esquerra: NIF, Professió, Adreça, Email, Telèfon, Mediador
    var leftCol =
        lv('NIF:', d.nif) +
        lv('Profesión:', d.professio) +
        lv('Dirección:', d.adreca) +
        lv('Email:', emailHtml, true) +
        lv('Teléfono:', telHtml, true) +
        lv('Mediador:', med);

    // Columna dreta: Data naix, Idioma, e-client, Occident Activa, RGPD, Antiguitat
    var rightCol =
        lv('Fecha nacimiento:', d.fnaixement) +
        lv('Idioma:', d.idioma) +
        lv('e-cliente:', eclientHtml, true) +
        lv('Occident Activa:', d.occidentActiva) +
        lv('RGPD:', rgpdAlertHtml, true) +
        lv('Antigüedad cliente:', d.antiguitat);

    var html = metaHtml +
        '<div style="display:grid;grid-template-columns:1fr 1fr;padding:10px 12px;gap:0 20px">' +
            '<div style="border-right:1px solid var(--brl);padding-right:16px">' + leftCol + '</div>' +
            '<div>' + rightCol + '</div>' +
        '</div>';

    // Nota de font i link
    html += '<div style="padding:4px 12px 6px;border-top:1px solid var(--brl);display:flex;justify-content:space-between;align-items:center">' +
        '<span style="font-size:9px;color:var(--t4)">Font: Gestiona Occident</span>' +
        '<a href="https://gestiona.gco.global" target="_blank" style="font-size:9px;color:#3B82F6;text-decoration:none">Gestiona &#8599;</a>' +
        '</div>';

    container.innerHTML = html;
}


// ─── HELPER: Copy a portapapers amb fallback robust ─────────────────────
// Bug del 2026-05-18: navigator.clipboard.writeText falla silenciosament quan
// el document no està enfocat (passa sovint amb modals dins Shadow DOM).
// Solució: 3 estratègies en ordre + notificació clara si totes fallen.
function _copyToClipboardSafe(text) {
    if (text == null) text = '';
    var str = String(text);
    var _t = function(msg, color, ms) {
        try { if (typeof _toast === 'function') _toast(msg, color || '#3B82F6', ms || 3000); } catch(e) {}
    };

    // Estratègia 1: clipboard API moderna
    var tryModern = function() {
        return new Promise(function(resolve, reject) {
            if (!navigator.clipboard || !navigator.clipboard.writeText) {
                reject(new Error('no-clipboard-api')); return;
            }
            try {
                navigator.clipboard.writeText(str).then(function() {
                    resolve('modern');
                }).catch(function(err) {
                    reject(err);
                });
            } catch (e) { reject(e); }
        });
    };

    // Estratègia 2: execCommand('copy') via textarea temporal
    var tryLegacy = function() {
        try {
            var ta = document.createElement('textarea');
            ta.value = str;
            ta.style.cssText = 'position:fixed;left:-9999px;top:0;opacity:0';
            ta.setAttribute('readonly', 'true');
            document.body.appendChild(ta);
            ta.select();
            ta.setSelectionRange(0, str.length);
            var ok = document.execCommand('copy');
            ta.remove();
            return ok;
        } catch (e) { return false; }
    };

    // Estratègia 3: mostrar modal amb el text perquè l'usuari faci copy manual
    var showFallbackModal = function() {
        try {
            var existing = document.getElementById('opticrm-copy-fallback');
            if (existing) existing.remove();
            var ov = document.createElement('div');
            ov.id = 'opticrm-copy-fallback';
            ov.style.cssText = 'position:fixed;inset:0;background:rgba(0,0,0,.5);z-index:2147483647;display:flex;align-items:center;justify-content:center';
            var box = document.createElement('div');
            box.style.cssText = 'background:#fff;border-radius:12px;padding:20px;max-width:460px;width:92vw;box-shadow:0 6px 30px rgba(0,0,0,.4)';
            box.innerHTML =
                '<div style="font-size:14px;font-weight:700;margin-bottom:8px;color:#111">⚠️ No s\'ha pogut copiar automàticament</div>' +
                '<div style="font-size:12px;color:#555;margin-bottom:10px">Selecciona el text i fes Ctrl+C:</div>' +
                '<input type="text" id="opticrm-copy-text" readonly value="' +
                    String(str).replace(/"/g,'&quot;') +
                '" style="width:100%;padding:8px 10px;border:1.5px solid #DC0028;border-radius:6px;font-size:13px;font-family:monospace;background:#FEF3F4;color:#111;box-sizing:border-box">' +
                '<div style="display:flex;gap:8px;justify-content:flex-end;margin-top:12px">' +
                '<button id="opticrm-copy-close" style="padding:7px 14px;background:#DC0028;color:#fff;border:none;border-radius:6px;font-size:12px;font-weight:600;cursor:pointer">Tancar</button>' +
                '</div>';
            ov.appendChild(box);
            document.body.appendChild(ov);
            var inp = box.querySelector('#opticrm-copy-text');
            if (inp) { inp.focus(); inp.select(); }
            box.querySelector('#opticrm-copy-close').addEventListener('click', function(){ ov.remove(); });
            ov.addEventListener('click', function(e){ if (e.target === ov) ov.remove(); });
        } catch(e) {
            // últim recurs: prompt() — bloca però funciona sempre
            try { window.prompt('Copia aquest text (Ctrl+C):', str); } catch(e2) {}
        }
    };

    // Pipeline: modern → legacy → modal fallback
    tryModern().then(function() {
        _t('📋 "' + str + '" copiat — enganxa\'l al CRM', '#3B82F6', 3000);
    }).catch(function(errModern) {
        console.warn('[clipboard] modern API failed:', errModern && errModern.message);
        if (tryLegacy()) {
            _t('📋 "' + str + '" copiat — enganxa\'l al CRM', '#3B82F6', 3000);
        } else {
            console.warn('[clipboard] legacy execCommand failed too — showing fallback modal');
            showFallbackModal();
        }
    });
}

