        caHdr.innerHTML='<div style="display:flex;align-items:center;gap:8px"><span>📋</span><span style="font-size:11px;font-weight:700;color:var(--t1)">Activitats Obertes</span><span style="background:rgba(59,130,246,.12);color:#3B82F6;padding:1px 8px;border-radius:10px;font-size:10px;font-weight:700">'+c.actsOb.length+'</span></div><span id="cli-act-arr" style="font-size:10px;color:#3B82F6;font-weight:600">▲</span>';
        var caBody=document.createElement('div');
