            row.onmouseenter=function(){this.style.background='var(--bg4)';};row.onmouseleave=function(){this.style.background='var(--bg3)';};
            row.innerHTML='<div style="flex:1;min-width:0">'+
                '<div style="font-size:12px;font-weight:600;color:var(--t1);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+ti.i+' '+esc(act.DESASUN||'—')+'</div>'+
                '<div style="font-size:10px;color:var(--t3);margin-top:2px">'+((act.TIM_INICI||'').slice(0,10).split('-').reverse().join('/'))+'</div></div>'+
                (u?'<span style="padding:1px 6px;border-radius:8px;font-size:9.5px;font-weight:700;background:'+u.bg+';color:'+u.color+';flex-shrink:0">'+u.ini+'</span>':'');
            row.addEventListener('click',function(){ov.remove();showDetail(act,ref);});
