    ftr.innerHTML=
        '<button onclick="_OAv.crm()" style="padding:8px 10px;background:var(--bg3);border:1px solid var(--br);border-radius:7px;color:var(--t2);font-size:11px;cursor:pointer;font-weight:600;font-family:inherit;text-align:center">\ud83c\udf10 Portal</button>'+
        '<div></div>'+
        '<button id="cli-create-opo" style="padding:8px 10px;background:rgba(139,92,246,.12);border:1px solid rgba(139,92,246,.3);border-radius:7px;color:#8B5CF6;font-size:11px;cursor:pointer;font-weight:600;font-family:inherit;text-align:center">\ud83d\udcbc Nova OPO</button>'+
        '<button id="cli-create-act" style="padding:8px 10px;background:rgba(59,130,246,.12);border:1px solid rgba(59,130,246,.3);border-radius:7px;color:#3B82F6;font-size:11px;cursor:pointer;font-weight:600;font-family:inherit;text-align:center">\ud83d\udccb Nova ACT</button>'+
        '<button id="cli-open-ext" style="padding:8px 10px;background:rgba(16,185,129,.12);border:1px solid rgba(16,185,129,.3);border-radius:7px;color:#10B981;font-size:11px;cursor:pointer;font-weight:600;font-family:inherit;text-align:center">🌐 Visión 360º</button>';
    // ── CARD: Dades CRM Occident (V360 Interop) ─────────────────
    // Card pills: buit | Polisses | Rebuts | Sinistres | buit
    var _pillsCard = document.createElement('div');
