    // ── ENTRY LOG: confirma que la funció es crida ──
    console.log('%c[RUA] === ENTRY ===','background:#DC0028;color:#fff;padding:2px 6px;font-weight:700;border-radius:3px',
                'actId:',actId,'uid:',uid);
    
