    if(!a){console.error('[RUA] ABORT: activitat/OPO no trobada amb id',actId);
           if(typeof _toast==='function')_toast('⚠ Item '+actId+' no trobat','#DC0028',3500);
           return;}
    if(!uid){console.error('[RUA] ABORT: uid buit'); return;}
    if(!USERS[uid]){console.error('[RUA] ABORT: USERS['+uid+'] no existeix'); return;}
    
    var prevUid=a._uid||a.UID_RACF||'M441819E';
    console.log('[RUA] activitat trobada:',a._isOpo?'OPO':'ACT',a.DESASUN,'| prev uid:',prevUid,'| nou uid:',uid);
    if(prevUid===uid){console.log('[RUA] mateix uid, no faig res'); return;} // sense canvis
    
    // 1. Actualitzar local i assigns OD
