            'select[id*="COD_MEDIADOR"]',
            'select[name*="COD_MEDIADOR"]',
            'select[id*="Mediador"]',
            'select[id*="MEDIADOR"]',
            'select[name*="Mediador"]',
            'select[id*="Colaborador"]',
