        '<textarea id="od-import-code" placeholder="Enganxa aquí el codi que t\u2019ha enviat DH..." style="width:100%;height:80px;background:var(--bg3);border:1.5px solid var(--br);border-radius:8px;padding:8px 12px;color:var(--t1);font-size:11px;font-family:monospace;outline:none;resize:none;box-sizing:border-box;line-height:1.4"></textarea>'+
        '</div>'+
        '</div>'+
        '<div style="padding:12px 22px;border-top:1px solid var(--br);display:flex;gap:8px;justify-content:flex-end">'+
        '<button id="od-import-cancel" style="padding:8px 18px;border-radius:8px;border:1px solid var(--br);background:var(--bg3);color:var(--t2);font-size:12px;cursor:pointer;font-family:inherit">Tancar</button>'+
        '<button id="od-import-ok" style="padding:8px 18px;border-radius:8px;border:none;background:#10B981;color:#fff;font-size:12px;font-weight:700;cursor:pointer;font-family:inherit">✅ Importar</button>'+
        '</div>';
